    { href: '/admin/traffic', label: '트래픽', icon: BarChart2, section: 'Reports' },
    { href: '/admin/report', label: '종합 보고서', icon: FileText, section: 'Reports' },
    { href: '/admin/pending-photos', label: '사진 등록 관리', icon: Camera, section: 'Photos' },
  ];

  const isActive = (href: string) => pathname === href;

  // Inject CSS for Firebase image thumbnails at runtime
  useEffect(() => {
    const styleId = 'admin-thumb-fix';
    if (!document.getElementById(styleId)) {
      const style = document.createElement('style');
      style.id = styleId;
      style.textContent = 'img[src*="firebasestorage"]{width:80px!important;height:60px!important;min-width:80px!important;max-width:80px!important;max-height:60px!important;object-fit:cover!important;border-radius:8px;flex-shrink:0}';
      document.head.appendChild(style);
    }
    return () => {
      const el = document.getElementById(styleId);
      if (el) el.remove();
    };
  }, []);

  const SidebarContent = () => (
    <>
      <div className="mb-10 flex items-center gap-2">
        <h2 className="text-[18px] font-bold text-primary tracking-tight">Admin<span className="text-toss-blue"> CMS</span></h2>
        <span className="text-[10px] bg-toss-blue-light text-toss-blue px-1.5 py-0.5 rounded-sm font-bold">Beta</span>
      </div>
      <nav className="flex flex-col gap-1">
        {navLinks.map((link) => (
          <Link key={link.href} href={link.href}
            onClick={() => setSidebarOpen(false)}
            className={`flex items-center gap-3 px-4 py-3 rounded-xl text-[14px] font-semibold transition-all ${
              isActive(link.href) ? 'bg-toss-blue text-surface shadow-lg shadow-[#3182f6]/20' : 'text-secondary hover:bg-body'
            }`}>
            <link.icon size={18} />
            {link.label}
          </Link>
        ))}
      </nav>
      <div className="mt-auto pt-6 border-t border-body">
        <Link href="/" className="flex items-center gap-3 px-4 py-3 rounded-xl text-[13px] font-semibold text-tertiary hover:bg-body hover:text-toss-blue transition-all">
          <ExternalLink size={16} /> 소비자 화면 보기
        </Link>
      </div>
    </>
  );

  return (
    <AdminGuard>
      <div className="flex min-h-screen bg-body">
        {/* Desktop Sidebar */}
        <aside className="hidden md:flex w-[240px] shrink-0 flex-col bg-surface p-6 border-r border-border fixed h-full overflow-y-auto z-30">
          <SidebarContent />
        </aside>

        {/* Spacer for fixed sidebar */}
        <div className="hidden md:block w-[240px] shrink-0" />

        {/* Mobile header */}
        <div className="md:hidden fixed top-0 left-0 right-0 z-40 bg-surface/80 backdrop-blur-lg border-b border-border px-4 py-3 flex items-center justify-between">
          <h2 className="text-[16px] font-bold text-primary">Admin<span className="text-toss-blue"> CMS</span></h2>
          <div className="flex items-center gap-1">
            <Link href="/" className="p-2 text-tertiary hover:text-toss-blue transition-colors" title="소비자 화면 보기">
              <ExternalLink size={20} />
            </Link>
            <button onClick={() => setSidebarOpen(!sidebarOpen)} className="p-2 text-secondary">
              <Menu size={22} />
            </button>
          </div>
        </div>

        {/* Mobile sidebar overlay */}
        {sidebarOpen && (
          <>
            <div className="md:hidden fixed inset-0 z-40 bg-black/30 backdrop-blur-sm" onClick={() => setSidebarOpen(false)} />
            <aside className="md:hidden fixed top-0 left-0 z-50 w-[280px] h-full bg-surface flex flex-col p-6 overflow-y-auto shadow-2xl animate-in slide-in-from-left duration-200">
              <div className="flex justify-end mb-2">
                <button onClick={() => setSidebarOpen(false)} className="p-1 text-tertiary">
                  <X size={20} />
                </button>
              </div>
              <SidebarContent />
            </aside>
          </>
        )}

        {/* Main Content */}
        <main className="flex-1 p-4 pt-16 md:p-8 md:pt-6 lg:p-12 lg:pt-8 overflow-y-auto w-full max-w-7xl mx-auto flex flex-col">
          <div className="hidden md:flex justify-end mb-4">
            <Link href="/" className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-[13px] font-bold text-tertiary hover:text-toss-blue hover:bg-surface hover:shadow-sm transition-all border border-transparent hover:border-border">
              <ExternalLink size={15} /> 소비자 화면으로 가기
            </Link>
          </div>
          {children}
        </main>
      </div>
    </AdminGuard>
  );
}

'use client';

import { useState, useEffect, useMemo, useCallback, useTransition, useDeferredValue } from 'react';
import useSWR from 'swr';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import {
  Building, Save, Search, Check, AlertTriangle, ChevronDown, ChevronRight,
  Home, Link2, FileText, Plus, Trash2, MapPin, PlusCircle, Edit, RefreshCw
} from 'lucide-react';
import { doc, getDoc, setDoc, collection, query, onSnapshot, where, getDocs, updateDoc, deleteDoc } from 'firebase/firestore';
import { db, auth } from '@/lib/firebaseConfig';
import { TX_SUMMARY } from '@/lib/transaction-summary';
import { DONGS } from '@/lib/dongs';
import { FULL_DONG_DATA } from '@/lib/dong-apartments';
import { ScoutingReport } from '@/lib/types/scoutingReport';
import { findTxKey } from '@/lib/utils/apartmentMapping';

const FIRESTORE_DOC = 'settings/apartmentMeta';
const dongNames = DONGS.map(d => d.name).sort((a, b) => a.localeCompare(b, 'ko'));

// ── Auto-suggest TX key matching ──
function normalizeAptName(name: string): string {
  return name.replace(/\[.*?\]\s*/g, '').replace(/\s+/g, '').replace(/[()（）]/g, '').trim();
}
function autoSuggest(aptName: string): string | null {
  return findTxKey(aptName, TX_SUMMARY) || null;
}

// ── Types ──
export interface AptMeta {
  dong: string;
  txKey?: string;
  maxFloor?: number;
  isPublicRental?: boolean;
  householdCount?: number;
  yearBuilt?: string;
  brand?: string;
  ticker?: string; // Ticker from Google Sheets
}
type MetaMap = Record<string, AptMeta>;

export interface AdInquiry {
  id: string;
  companyName: string;
  contactInfo: string;
  message: string;
  status: 'pending' | 'reviewed';
  createdAt: any;
}

export default function AdminDashboard() {
  const router = useRouter();
  // ── State ──
  const [activeAdminTab, setActiveAdminTab] = useState<'apartments' | 'inquiries'>('apartments');
  const [inquiries, setInquiries] = useState<AdInquiry[]>([]);
  const [meta, setMeta] = useState<MetaMap>({});
  const [initialMeta, setInitialMeta] = useState<MetaMap>({}); // To track changes for sync
  const [saving, setSaving] = useState(false);
  const [saved, setSaved] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [search, setSearch] = useState('');
  const [filter, setFilter] = useState<'all'|'unmatched'|'public'|'private'|'analyzed'|'verified'>('all');
  const [expandedDongs, setExpandedDongs] = useState<Set<string>>(new Set());
  const [expandedApts, setExpandedApts] = useState<Set<string>>(new Set());
  const [loaded, setLoaded] = useState(false);
  
  // Scouting reports
  const [reports, setReports] = useState<ScoutingReport[]>([]);
  const [reportsByApt, setReportsByApt] = useState<Record<string, ScoutingReport[]>>({});
  
  // Add apartment form
  const [showAddForm, setShowAddForm] = useState(false);
  const [newAptName, setNewAptName] = useState('');
  const [newAptDong, setNewAptDong] = useState(dongNames[0]);
  // Deletes tracking for sync
  const [deletedApts, setDeletedApts] = useState<Set<string>>(new Set());

  const txKeys = useMemo(() => Object.keys(TX_SUMMARY).sort(), []);



  // ── Load Scouting Reports ──
  useEffect(() => {
    const q = query(collection(db, 'scoutingReports'));
    const unsub = onSnapshot(q, snap => {
      const fetched = snap.docs.map(d => ({ id: d.id, ...d.data() } as ScoutingReport));
      setReports(fetched);
      const byApt: Record<string, ScoutingReport[]> = {};
      fetched.forEach(r => {
        if (!byApt[r.apartmentName]) byApt[r.apartmentName] = [];
        byApt[r.apartmentName].push(r);
      });
      setReportsByApt(byApt);
    });
    return () => unsub();
  }, []);

  // ── Load Ad Inquiries ──
  useEffect(() => {
    const q = query(collection(db, 'adInquiries'));
    const unsub = onSnapshot(q, snap => {
      const fetched = snap.docs.map(d => ({ id: d.id, ...d.data() } as AdInquiry));
      fetched.sort((a, b) => (b.createdAt?.toMillis() || 0) - (a.createdAt?.toMillis() || 0));
      setInquiries(fetched);
    });
    return () => unsub();
  }, []);

  const [isPending, startTransition] = useTransition();

  // ── SWR Fetcher for Google Sheets (Single Source of Truth) ──
  const fetcher = async (url: string) => {
    try {
      const res = await fetch(url);
      if (!res.ok) throw new Error('Failed to fetch from sheets');
      const data = await res.json();
      const sheetMap: MetaMap = {};
      
      if (data.byDong) {
        for (const [dong, apts] of Object.entries(data.byDong)) {
          (apts as Record<string, unknown>[]).forEach(apt => {
            sheetMap[apt.name as string] = {
              dong: (apt as Record<string, string>)?.dong,
              txKey: (apt as Record<string, string>)?.txKey || autoSuggest(apt.name as string) || undefined,
              maxFloor: (apt as Record<string, number>)?.maxFloor || 0,
              isPublicRental: (apt as Record<string, boolean>)?.isPublicRental || false,
              householdCount: (apt as Record<string, number>)?.householdCount,
              yearBuilt: (apt as Record<string, string>)?.yearBuilt,
              brand: (apt as Record<string, string>)?.brand,
              ticker: (apt as Record<string, string>)?.ticker,
            };
          });
        }
      }
      return sheetMap;
    } catch (e) {
      console.error('Failed to load sheets, trying Firestore fallback:', e);
      try {
        const metaDoc = await getDoc(doc(db, 'settings/apartmentMeta'));
        if (metaDoc.exists()) {
          const data = metaDoc.data() as Record<string, unknown>;
          const fbMap: MetaMap = {};
          for (const [name, m] of Object.entries(data)) {
            if (m && typeof m === 'object' && 'dong' in m) {
              const mapObj = m as Record<string, unknown>;
              fbMap[name] = {
                dong: mapObj.dong as string,
                txKey: (mapObj.txKey as string) || autoSuggest(name) || undefined,
                maxFloor: (mapObj.maxFloor as number) || 0,
                isPublicRental: (mapObj.isPublicRental as boolean) || false,
                householdCount: mapObj.householdCount as number | undefined,
                yearBuilt: mapObj.yearBuilt as string | undefined,
                brand: mapObj.brand as string | undefined,
                ticker: mapObj.ticker as string | undefined,
              };
            }
          }
          if (Object.keys(fbMap).length > 0) return fbMap;
        }
      } catch (fbErr) {
        console.error('Firestore fallback also failed:', fbErr);
      }
      const staticMap: MetaMap = {};
      for (const [dong, apts] of Object.entries(FULL_DONG_DATA)) {
        apts.forEach(aptName => {
          staticMap[aptName] = { dong, txKey: autoSuggest(aptName) || undefined, isPublicRental: false };
        });
      }
      return staticMap;
    }
  };

  const { data: swrMeta } = useSWR('/api/apartments-by-dong', fetcher, { 
    revalidateOnFocus: false,
    dedupingInterval: 60000 
  });

  useEffect(() => {
    if (swrMeta && !loaded) {
      setMeta(swrMeta);
      setInitialMeta(JSON.parse(JSON.stringify(swrMeta)));
      setLoaded(true);
    }
  }, [swrMeta, loaded]);

  // ── Actions ──
  const toggleInquiryStatus = async (id: string, currentStatus: string) => {
    try {
      await updateDoc(doc(db, 'adInquiries', id), { status: currentStatus === 'pending' ? 'reviewed' : 'pending' });
    } catch (e) { console.error(e); }
  };

  const deleteInquiry = async (id: string) => {
    if (!confirm('해당 문의를 삭제하시겠습니까? 삭제 후 복구할 수 없습니다.')) return;
    try {
      await deleteDoc(doc(db, 'adInquiries', id));
    } catch (e) { console.error(e); }
  };

  const handleSync = async () => {
    if (!confirm('국토교통부 실거래가 최신 데이터를 수동으로 가져오시겠습니까?\n이 작업은 시간이 다소 소요될 수 있습니다.')) return;
    
    setIsSyncing(true);
    try {
      const res = await fetch('/api/cron/sync-transactions');
      const data = await res.json();
      
      if (res.ok) {
        alert(`동기화 완료!\n- 추가된 데이터: ${data.synced}건`);
      } else {
        throw new Error(data.error || 'Unknown error');
      }
    } catch (e: any) {
      console.error('Sync error:', e);
      alert('동기화 중 오류가 발생했습니다: ' + e.message);
    } finally {
      setIsSyncing(false);
    }
  };

  const handleSave = async () => {
    setSaving(true);
    try {
      // 1. Calculate diffs for Google Sheets
      const syncPayload: { updates: unknown[], adds: unknown[], deletes: string[] } = {
        updates: [],
        adds: [],
        deletes: Array.from(deletedApts)
      };

      for (const [name, currentM] of Object.entries(meta)) {
        const initialM = initialMeta[name];
        if (!initialM) {
          // This is a new apartment (added)
          syncPayload.adds.push({
            name,
            dong: currentM.dong,
            txKey: currentM.txKey,
          });
        } else {
          // Compare fields for updates
          const updates: Record<string, string|number|boolean> = {};
          if (currentM.dong !== initialM.dong) updates['동'] = currentM.dong;
          if (currentM.txKey !== initialM.txKey) updates['txKey'] = currentM.txKey || '';
          if (currentM.maxFloor !== initialM.maxFloor) updates['최고층'] = currentM.maxFloor || '';
          if (currentM.isPublicRental !== initialM.isPublicRental) updates['공공임대'] = currentM.isPublicRental ? 'Y' : 'N';
          // NOTE: renamed apartment checking via old name (since exact name match fails if renamed)
          // Actually, if we rename, the key changes. Wait, `name` is the key. 
          // Re-evaluate: rename function deletes old name and creates new name.
          // The old name will NOT be in `meta`, so it's not checked here. It was caught by initialMeta diff? No, the code below handles it.
          // Wait, if it's renamed, `targetRow` won't find it if it searches by name. BUT we have `ticker`!
          // Since `currentM.ticker` matches `initialM.ticker`, let's just use ticker.
          
          if (Object.keys(updates).length > 0) {
            syncPayload.updates.push({
              ticker: currentM.ticker,
              name: name,
              updates
            });
          }
        }
      }

      // Check for renames (apartments that exist in meta but the name key doesn't match initialMeta, AND they have a ticker)
      // Wait, the loop above already covered them as "adds" if the key (newName) isn't in initialMeta!
      // But if it's a rename, it's NOT an "add". It should be an "update" on the '아파트명' column identified by `ticker`.
      
      // Let's refine the diffing logic explicitly for renames:
      // Loop over current meta to find renames (where current `ticker` matches an initial, but `name` differs)
      const currentTickers = new Map<string, string>(); // ticker -> newName
      for (const [newName, m] of Object.entries(meta)) {
        if (m.ticker) currentTickers.set(m.ticker, newName);
      }

      // Re-build diffs perfectly using ticker as ID
      syncPayload.updates = [];
      syncPayload.adds = [];
      syncPayload.deletes = [];

      // Detect deletions and updates for existing items
      for (const [oldName, initialM] of Object.entries(initialMeta)) {
        if (initialM.ticker) {
          const newName = currentTickers.get(initialM.ticker);
          if (!newName) {
            // Deleted entirely
            syncPayload.deletes.push(oldName);
          } else {
            // Updated
            const currentM = meta[newName];
            const updates: Record<string, string|number|boolean> = {};
            if (newName !== oldName) updates['아파트명'] = newName;
            if (currentM.dong !== initialM.dong) updates['동'] = currentM.dong;
            if (currentM.txKey !== initialM.txKey) updates['txKey'] = currentM.txKey || '';
            if (currentM.maxFloor !== initialM.maxFloor) updates['최고층'] = currentM.maxFloor || '';
            if (currentM.isPublicRental !== initialM.isPublicRental) updates['공공임대'] = currentM.isPublicRental ? 'Y' : 'N';

            if (Object.keys(updates).length > 0) {
              syncPayload.updates.push({ ticker: initialM.ticker, updates });
            }
          }
        }
      }

      // Detect pure Adds (no ticker)
      for (const [newName, currentM] of Object.entries(meta)) {
        if (!currentM.ticker) {
          syncPayload.adds.push({
            name: newName,
            dong: currentM.dong,
            txKey: currentM.txKey || ''
          });
        }
      }

      // 2. Send to Google Sheets API
      if (syncPayload.updates.length > 0 || syncPayload.adds.length > 0 || syncPayload.deletes.length > 0) {
        const idToken = await auth.currentUser?.getIdToken();
        const syncRes = await fetch('/api/apartments-sync', {
          method: 'POST',
          headers: { 
            'Content-Type': 'application/json',
            ...(idToken ? { 'Authorization': `Bearer ${idToken}` } : {})
          },
          body: JSON.stringify(syncPayload)
        });
        if (!syncRes.ok) {
          const errData = await syncRes.json();
          throw new Error('Google Sheets Sync Failed: ' + errData.error);
        }
      }

      // 3. Keep Firestore caching for fast dashboard loading? Yes.
      const clean: Record<string, Record<string, unknown>> = {};
      for (const [name, m] of Object.entries(meta)) {
        const entry: Record<string, unknown> = {};
        for (const [k, v] of Object.entries(m)) {
          if (v !== undefined && v !== null && v !== '') entry[k] = v;
        }
        if (entry.dong) clean[name] = entry;
      }
      await setDoc(doc(db, FIRESTORE_DOC), clean);

      // Re-sync initial state to current state
      setInitialMeta(JSON.parse(JSON.stringify(meta)));
      setDeletedApts(new Set());
      setSaved(true);
      setTimeout(() => setSaved(false), 2000);
    } catch (e: unknown) {
      console.error('Save failed:', e);
      alert('저장에 실패했습니다: ' + (e as Error).message);
    }
    setSaving(false);
  };

  const updateMeta = useCallback((aptName: string, patch: Partial<AptMeta>) => {
    setMeta(prev => ({
      ...prev,
      [aptName]: { ...(prev[aptName] || { dong: '' }), ...patch },
    }));
  }, []);

  const deleteApt = useCallback((aptName: string) => {
    if (!confirm(`"${aptName}" 아파트를 삭제하시겠습니까?`)) return;
    setDeletedApts(prev => { const next = new Set(prev); next.add(aptName); return next; });
    setMeta(prev => { const next = { ...prev }; delete next[aptName]; return next; });
  }, []);

  const addApartment = useCallback(() => {
    const name = newAptName.trim();
    if (!name) return alert('아파트 이름을 입력하세요.');
    if (meta[name]) return alert('이미 존재하는 아파트입니다.');
    setMeta(prev => ({
      ...prev,
      [name]: { dong: newAptDong, txKey: autoSuggest(name) || undefined },
    }));
    setNewAptName('');
    setShowAddForm(false);
  }, [newAptName, newAptDong, meta]);

  const toggleDong = useCallback((dong: string) => {
    setExpandedDongs(prev => {
      const next = new Set(prev); next.has(dong) ? next.delete(dong) : next.add(dong); return next;
    });
  }, []);

  // ── Computed Data ──
  const aptsByDong = useMemo(() => {
    const result: Record<string, { name: string; meta: AptMeta }[]> = {};
    for (const [name, m] of Object.entries(meta)) {
      const dong = m.dong || '미분류';
      if (!result[dong]) result[dong] = [];
      result[dong].push({ name, meta: m });
    }
    for (const dong of Object.keys(result)) {
      result[dong].sort((a, b) => a.name.localeCompare(b.name, 'ko'));
    }
    return result;
  }, [meta]);

  const allAptNames = useMemo(() => Object.keys(meta), [meta]);
  const analyzedApts = useMemo(() => {
    const set = new Set<string>();
    reports.forEach(r => {
      const m = r.metrics;
      if (m && (
        m.distanceToElementary || m.distanceToMiddle || m.distanceToHigh ||
        m.distanceToSubway || m.distanceToIndeokwon || m.distanceToTram ||
        m.academyDensity || m.restaurantDensity ||
        m.distanceToStarbucks || m.distanceToMcDonalds || m.distanceToOliveYoung ||
        m.distanceToDaiso || m.distanceToSupermarket
      )) {
        set.add(r.apartmentName);
      }
    });
    return set;
  }, [reports]);
  const verifiedApts = useMemo(() => {
    const set = new Set<string>();
    reports.forEach(r => {
      if (r.images && r.images.length > 0) {
        set.add(r.apartmentName);
      }
    });
    return set;
  }, [reports]);

  const stats = useMemo(() => {
    let mapped = 0, unmapped = 0, publicR = 0, verified = 0, analyzed = 0;
    for (const name of allAptNames) {
      const m = meta[name];
      if (m?.isPublicRental) publicR++;
      if (m?.txKey && TX_SUMMARY[m.txKey as keyof typeof TX_SUMMARY]) mapped++;
      else unmapped++;
      if (verifiedApts.has(name)) verified++;
      if (analyzedApts.has(name)) analyzed++;
    }
    const totalVerifiedReports = reports.filter(r => r.images && r.images.length > 0).length;
    return { total: allAptNames.length, mapped, unmapped, publicR, verified, analyzed, totalVerifiedReports };
  }, [meta, allAptNames, verifiedApts, analyzedApts, reports]);

  const deferredSearch = useDeferredValue(search);

  const filteredDongs = useMemo(() => {
    const q = deferredSearch.trim().toLowerCase();
    return Object.entries(aptsByDong)
      .map(([dong, apts]) => {
        let f = apts;
        if (q) f = f.filter(a => a.name.toLowerCase().includes(q) || dong.toLowerCase().includes(q));
        if (filter === 'unmatched') f = f.filter(a => !a.meta.txKey);
        if (filter === 'public') f = f.filter(a => a.meta.isPublicRental);
        if (filter === 'private') f = f.filter(a => !a.meta.isPublicRental);
        if (filter === 'analyzed') f = f.filter(a => analyzedApts.has(a.name));
        if (filter === 'verified') f = f.filter(a => verifiedApts.has(a.name));
        return [dong, f] as const;
      })
      .filter(([, a]) => a.length > 0)
      .sort(([a], [b]) => a.localeCompare(b, 'ko'));
  }, [deferredSearch, filter, aptsByDong, analyzedApts, verifiedApts]);

  if (!loaded) return (
    <div className="flex justify-center items-center py-32">
      <div className="w-8 h-8 border-4 border-toss-blue border-t-transparent rounded-full animate-spin" />
    </div>
  );

  return (
    <div className="animate-in fade-in duration-300">
      {/* Header & Tabs */}
      <div className="flex flex-col sm:flex-row sm:justify-between sm:items-end gap-4 mb-4">
        <div>
          <h1 className="text-2xl md:text-3xl font-bold text-primary tracking-tight mb-2">관리자 대시보드</h1>
          <p className="text-secondary text-[14px]">아파트 데이터 및 문의 통합 관리</p>
        </div>
        {activeAdminTab === 'apartments' && (
          <div className="flex gap-2">
            <button onClick={handleSync} disabled={isSyncing}
              className="flex items-center gap-2 px-4 py-3 rounded-xl font-bold text-[#1b64da] bg-toss-blue-light hover:bg-toss-blue hover:text-surface disabled:opacity-50 transition-all text-[13px]">
              <RefreshCw size={16} className={isSyncing ? "animate-spin" : ""} /> 
              {isSyncing ? '동기화 중...' : '실거래가 수동 동기화'}
            </button>
            <button onClick={() => setShowAddForm(!showAddForm)}
              className="flex items-center gap-2 px-4 py-3 rounded-xl font-bold text-toss-blue bg-toss-blue-light hover:bg-toss-blue hover:text-surface transition-all text-[13px]">
              <Plus size={16}/> 아파트 추가
            </button>
          </div>
        )}
      </div>

      <div className="flex gap-4 border-b border-border mb-8 overflow-x-auto">
        <button 
          onClick={() => startTransition(() => setActiveAdminTab('apartments'))}
          className={`pb-3 text-[15px] font-bold transition-colors whitespace-nowrap ${activeAdminTab === 'apartments' ? 'text-toss-blue border-b-2 border-toss-blue' : 'text-tertiary hover:text-secondary'}`}
        >
          아파트 데이터 관리
        </button>
        <button 
          onClick={() => startTransition(() => setActiveAdminTab('inquiries'))}
          className={`pb-3 text-[15px] font-bold transition-colors whitespace-nowrap flex items-center gap-1.5 ${activeAdminTab === 'inquiries' ? 'text-toss-blue border-b-2 border-toss-blue' : 'text-tertiary hover:text-secondary'}`}
        >
          광고/제휴 문의 관리
          {inquiries.filter(i => i.status === 'pending').length > 0 && (
            <span className="bg-[#ff3b30] text-surface text-[10px] px-1.5 py-0.5 rounded-full">{inquiries.filter(i => i.status === 'pending').length}</span>
          )}
        </button>
      </div>

      <div className={`transition-opacity duration-300 ${isPending ? 'opacity-50' : 'opacity-100'}`}>
      {activeAdminTab === 'apartments' ? (
        <>

      {/* Add Apartment Form */}
      {showAddForm && (
        <div className="bg-toss-blue-light rounded-2xl p-5 mb-6 flex flex-col sm:flex-row gap-3 items-end animate-in slide-in-from-top duration-200">
          <div className="flex-1 min-w-0">
            <label className="text-[12px] font-bold text-toss-blue mb-1 block">아파트 이름</label>
            <input type="text" value={newAptName} onChange={e => setNewAptName(e.target.value)}
              placeholder="예: 동탄역 힐스테이트 2차"
              className="w-full px-3 py-2.5 border border-toss-blue/30 rounded-xl text-[14px] outline-none focus:border-toss-blue bg-surface" />
          </div>
          <div className="shrink-0">
            <label className="text-[12px] font-bold text-toss-blue mb-1 block">동</label>
            <select value={newAptDong} onChange={e => setNewAptDong(e.target.value)}
              className="px-3 py-2.5 border border-toss-blue/30 rounded-xl text-[14px] bg-surface outline-none focus:border-toss-blue">
              {dongNames.map(d => <option key={d} value={d}>{d}</option>)}
            </select>
          </div>
          <div className="flex gap-2 shrink-0">
            <button onClick={addApartment} className="px-4 py-2.5 bg-toss-blue text-surface rounded-xl text-[13px] font-bold hover:bg-[#2b72d6] transition-colors">추가</button>
            <button onClick={() => setShowAddForm(false)} className="px-4 py-2.5 bg-surface text-tertiary rounded-xl text-[13px] font-bold hover:bg-body transition-colors">취소</button>
          </div>
        </div>
      )}

      {/* Stats */}
      <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-6 gap-3 mb-6">
        {[
          { label: '전체 단지', value: stats.total, color: '#3182f6', bg: '#e8f3ff', icon: Building, fk: 'all' as const },
          { label: '매핑 완료', value: stats.mapped, color: '#03c75a', bg: '#f0fdf4', icon: Check, fk: 'all' as const },
          { label: '미매핑', value: stats.unmapped, color: '#f04452', bg: '#ffebec', icon: AlertTriangle, fk: 'unmatched' as const },
          { label: '가치평가', value: stats.analyzed, color: '#8b5cf6', bg: '#f5f3ff', icon: MapPin, fk: 'analyzed' as const },
          { label: '현장검증', value: stats.verified, color: '#ff8a3d', bg: '#fff4e6', icon: FileText, fk: 'verified' as const },
          { label: '공공임대', value: stats.publicR, color: '#8b95a1', bg: '#f2f4f6', icon: Home, fk: 'public' as const },
        ].map(s => (
          <div key={s.label} onClick={() => startTransition(() => setFilter(s.fk))}
            className={`bg-surface p-4 rounded-2xl border shadow-sm cursor-pointer hover:shadow-md transition-all ${
              filter === s.fk && s.fk !== 'all' ? 'border-toss-blue ring-2 ring-toss-blue/10' : 'border-border'
            }`}>
            <div className="flex items-center gap-2 mb-2">
              <div className="p-1.5 rounded-lg" style={{ backgroundColor: s.bg, color: s.color }}><s.icon size={14}/></div>
              <span className="text-[11px] font-bold text-tertiary">{s.label}</span>
            </div>
            <div className="text-[26px] font-extrabold" style={{ color: s.color }}>{s.value}</div>
          </div>
        ))}
      </div>

      {/* Search + Filter */}
      <div className="flex flex-col sm:flex-row gap-3 mb-6">
        <div className="flex-1 relative">
          <Search size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-tertiary" />
          <input type="text" value={search} onChange={e => setSearch(e.target.value)}
            placeholder="아파트명 또는 동 이름으로 검색..."
            className="w-full pl-11 pr-4 py-3 bg-surface border border-border rounded-xl text-[14px] outline-none focus:border-toss-blue focus:ring-4 focus:ring-toss-blue/10 transition-all" />
        </div>
        <div className="flex gap-1.5 overflow-x-auto pb-2">
          {([['all','전체'],['unmatched','미매핑'],['analyzed','가치평가'],['verified','현장검증'],['public','공공임대'],['private','일반분양']] as const).map(([key, label]) => (
            <button key={key} onClick={() => startTransition(() => setFilter(key))}
              className={`shrink-0 px-4 py-2 rounded-xl text-[13px] font-bold transition-all ${
                filter === key ? 'bg-primary text-surface' : 'bg-surface border border-border text-secondary hover:bg-body'
              }`}>{label}</button>
          ))}
        </div>
      </div>


      {/* Apartment List by Dong */}
      <div className="flex flex-col gap-3">
        {filteredDongs.map(([dong, apts]) => {
          const isExpanded = expandedDongs.has(dong) || search.trim().length > 0 || filter !== 'all';
          const dongMapped = apts.filter(a => !!a.meta.txKey).length;
          const dongAnalyzed = apts.filter(a => analyzedApts.has(a.name)).length;
          const dongVerified = apts.filter(a => verifiedApts.has(a.name)).length;

          return (
            <div key={dong} className="bg-surface rounded-2xl border border-border shadow-sm overflow-hidden">
              <button onClick={() => toggleDong(dong)}
                className="w-full px-4 sm:px-6 py-4 flex items-center gap-3 hover:bg-body transition-colors">
                {isExpanded ? <ChevronDown size={18} className="text-tertiary shrink-0"/> : <ChevronRight size={18} className="text-tertiary shrink-0"/>}
                <h3 className="text-[15px] font-extrabold text-primary">{dong}</h3>
                <span className="text-[11px] font-bold text-tertiary bg-body px-2 py-0.5 rounded-full">{apts.length}개</span>
                <span className={`text-[11px] font-bold px-2 py-0.5 rounded-full ${
                  dongMapped === apts.length ? 'bg-[#f0fdf4] text-toss-green' : dongMapped > 0 ? 'bg-[#fff4e6] text-[#ff8a3d]' : 'bg-body text-tertiary'
                }`}>TX {dongMapped}/{apts.length}</span>
                {dongAnalyzed > 0 && <span className="text-[11px] font-bold px-2 py-0.5 rounded-full bg-toss-blue-light text-[#1b64da]">📍 {dongAnalyzed}</span>}
                {dongVerified > 0 && <span className="text-[11px] font-bold px-2 py-0.5 rounded-full bg-[#fff4e6] text-[#ff8a3d]">📸 {dongVerified}</span>}
              </button>

              {isExpanded && (
                <div className="border-t border-border divide-y divide-[#f2f4f6]">
                  {apts.map(({ name, meta: m }) => {
                    const resolvedTxKey = m.txKey ? (findTxKey(m.txKey, TX_SUMMARY) || m.txKey) : null;
                    const hasValidTx = resolvedTxKey && TX_SUMMARY[resolvedTxKey as keyof typeof TX_SUMMARY];
                    const suggested = !m.txKey ? autoSuggest(name) : null;
                    const aptReports = reportsByApt[name] || [];
                    const verifiedReportsCount = aptReports.filter(r => r.images && r.images.length > 0).length;
                    const isAptExpanded = expandedApts.has(name);

                    return (
                      <div key={name} className={`${m.isPublicRental ? 'bg-body' : !hasValidTx ? 'bg-[#fffbf5]' : ''}`}>
                        {/* Apartment Unit Header */}
                        <Link href={`/admin/apartments/${encodeURIComponent(name)}`} className="block px-4 sm:px-6 py-4 hover:bg-[#f6f8fa] transition-colors border-b border-body last:border-0">
                          <div className="flex items-center gap-2 flex-wrap">
                            {hasValidTx ? <Check size={14} className="text-toss-green shrink-0"/> : <AlertTriangle size={14} className="text-toss-red shrink-0"/>}
                            
                            <span className="text-[13px] sm:text-[14px] font-bold text-primary">{name}</span>

                            {/* Report badge */}
                            {m.isPublicRental && (
                              <span className="text-[11px] font-bold bg-body text-secondary px-2 py-0.5 rounded-full mt-0.5 border border-border">공공임대</span>
                            )}
                            {verifiedReportsCount > 0 ? (
                              <span className="text-[11px] font-bold bg-[#fff4e6] text-[#ff8a3d] px-2 py-0.5 rounded-full mt-0.5">현장검증</span>
                            ) : analyzedApts.has(name) ? (
                              <span className="text-[11px] font-bold bg-toss-blue-light text-[#1b64da] px-2 py-0.5 rounded-full mt-0.5">가치평가</span>
                            ) : null}

                            <span className="ml-auto flex items-center gap-1.5 px-3 py-1.5 bg-surface border border-border rounded-lg text-[12px] font-bold text-secondary hover:bg-body hover:text-primary transition-colors shadow-sm">
                              상세보기
                              <ChevronRight size={14}/>
                            </span>
                          </div>
                        </Link>
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* Orphaned TX Keys */}
      <div className="mt-8 bg-surface rounded-2xl border border-border shadow-sm overflow-hidden">
        <div className="px-4 sm:px-6 py-4 bg-body border-b border-border">
          <h3 className="font-bold text-[14px] text-primary">매핑되지 않은 TX 키</h3>
          <p className="text-[11px] text-tertiary">실거래 데이터에 있지만 아파트 목록에 연결 안 된 키</p>
        </div>
        <div className="px-4 sm:px-6 py-4 flex flex-wrap gap-1.5 max-h-[200px] overflow-y-auto">
          {(() => {
            const used = new Set(Object.values(meta).map(m => m.txKey).filter(Boolean));
            return txKeys.filter(k => !used.has(k)).map(k => (
              <span key={k} className="bg-body text-secondary text-[11px] font-mono px-2.5 py-1 rounded-lg">{k}</span>
              ));
            })()}
        </div>
      </div>

      {/* Floating Save Bar */}
      {activeAdminTab === 'apartments' && (
        <div className="fixed bottom-0 left-0 md:left-[240px] right-0 z-40 bg-surface/90 backdrop-blur-lg border-t border-border px-4 sm:px-6 py-3 flex items-center justify-between shadow-[0_-4px_20px_rgba(0,0,0,0.08)]">
          <span className="text-[13px] text-tertiary font-medium">{stats.total}개 단지 · {stats.mapped} 매핑 · 📸 {stats.totalVerifiedReports} 현장검증</span>
          <button onClick={handleSave} disabled={saving}
            className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-bold transition-all text-[14px] ${
              saved ? 'bg-toss-green text-surface shadow-lg shadow-[#03c75a]/20' : 'bg-toss-blue hover:bg-[#2b72d6] text-surface shadow-lg shadow-[#3182f6]/20'
            } disabled:opacity-60`}>
            <Save size={16}/>
            {saving ? '저장 중...' : saved ? '저장 완료!' : '저장하기'}
          </button>
        </div>
      )}

      {/* Bottom padding for floating bar */}
      <div className="h-20" />
      </>
      ) : (
        <div className="bg-surface rounded-2xl border border-border shadow-sm overflow-hidden flex flex-col gap-0 divide-y divide-[#e5e8eb]">
          {inquiries.length === 0 ? (
            <div className="p-10 text-center text-tertiary text-[14px]">아직 접수된 광고/제휴 문의가 없습니다.</div>
          ) : (
            inquiries.map(inquiry => (
              <div key={inquiry.id} className={`p-5 sm:p-6 transition-colors ${inquiry.status === 'pending' ? 'bg-body' : 'bg-surface opacity-80'}`}>
                <div className="flex flex-col sm:flex-row sm:items-start justify-between gap-4 mb-4">
                  <div>
                    <div className="flex items-center gap-2 mb-1.5">
                      {inquiry.status === 'pending' ? (
                        <span className="px-2 py-0.5 rounded-md bg-[#ffe6e6] text-[#ff3b30] text-[11px] font-bold">확인 요망</span>
                      ) : (
                        <span className="px-2 py-0.5 rounded-md bg-[#e5e8eb] text-tertiary text-[11px] font-bold">확인 완료</span>
                      )}
                      <h3 className="text-[16px] font-extrabold text-primary">{inquiry.companyName}</h3>
                    </div>
                    <p className="text-[13px] text-secondary mb-1"><span className="font-bold text-tertiary mr-1">연락처/이메일:</span> {inquiry.contactInfo}</p>
                    <p className="text-[11px] text-tertiary">접수일: {inquiry.createdAt?.toDate ? inquiry.createdAt.toDate().toLocaleString('ko-KR') : '알 수 없음'}</p>
                  </div>
                  <div className="flex gap-2 shrink-0">
                    <button 
                      onClick={() => toggleInquiryStatus(inquiry.id, inquiry.status)}
                      className={`px-3 py-1.5 rounded-lg text-[12px] font-bold transition-colors ${inquiry.status === 'pending' ? 'bg-toss-blue text-surface' : 'bg-body text-secondary'}`}
                    >
                      {inquiry.status === 'pending' ? '읽음 처리' : '미확인으로 변경'}
                    </button>
                    <button 
                      onClick={() => deleteInquiry(inquiry.id)}
                      className="px-3 py-1.5 rounded-lg bg-[#fff0f1] text-toss-red text-[12px] font-bold hover:bg-[#ffe6e6] transition-colors flex items-center gap-1"
                    >
                      <Trash2 size={12} /> 삭제
                    </button>
                  </div>
                </div>
                <div className="bg-surface border border-border p-4 rounded-xl text-[14px] text-[#333d4b] whitespace-pre-wrap leading-relaxed">
                  {inquiry.message}
                </div>
              </div>
            ))
          )}
        </div>
      )}
      </div>
    </div>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { db, storage } from '@/lib/firebaseConfig';
import { collection, query, where, getDocs, doc, updateDoc, getDoc, orderBy } from 'firebase/firestore';
import { ref, deleteObject } from 'firebase/storage';
import { Camera, Check, X, Loader2, AlertCircle } from 'lucide-react';
import Image from 'next/image';

interface PendingPhoto {
  id: string;
  apartmentId: string;
  apartmentName: string;
  url: string;
  locationTag: string;
  locationTagId: string;
  caption: string;
  status: 'pending' | 'approved' | 'rejected';
  createdAt: any;
  uploaderName?: string;
}

export default function PendingPhotosPage() {
  const [photos, setPhotos] = useState<PendingPhoto[]>([]);
  const [loading, setLoading] = useState(true);
  const [processingId, setProcessingId] = useState<string | null>(null);

  const fetchPendingPhotos = async () => {
    setLoading(true);
    try {
      const q = query(
        collection(db, 'pending_photos'),
        where('status', '==', 'pending')
      );
      const snapshot = await getDocs(q);
      const fetched: PendingPhoto[] = [];
      snapshot.forEach(doc => {
        fetched.push({ id: doc.id, ...doc.data() } as PendingPhoto);
      });
      // Sort by createdAt descending (client-side to avoid composite index requirement for MVP)
      fetched.sort((a, b) => (b.createdAt?.toMillis?.() || 0) - (a.createdAt?.toMillis?.() || 0));
      setPhotos(fetched);
    } catch (error) {
      console.error("Error fetching pending photos:", error);
      alert('데이터를 불러오는데 실패했습니다.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchPendingPhotos();
  }, []);

  const handleApprove = async (photo: PendingPhoto) => {
    if (!window.confirm('이 사진을 승인하시겠습니까? (즉시 서비스에 노출됩니다)')) return;
    setProcessingId(photo.id);

    try {
      // 1. Get the target apartment report
      const reportRef = doc(db, 'scoutingReports', photo.apartmentId);
      const reportSnap = await getDoc(reportRef);
      
      if (!reportSnap.exists()) {
        alert('연결된 아파트 정보를 찾을 수 없습니다.');
        setProcessingId(null);
        return;
      }

      const reportData = reportSnap.data();
      const currentImages = reportData.images || [];

      // 2. Add new image
      const newImage = {
        url: photo.url,
        caption: photo.caption,
        locationTag: photo.locationTagId, // Need ID for mappings
        isPremium: false,
        uploaderName: photo.uploaderName || '익명'
      };

      await updateDoc(reportRef, {
        images: [...currentImages, newImage]
      });

      // 3. Update pending status
      await updateDoc(doc(db, 'pending_photos', photo.id), {
        status: 'approved',
        processedAt: new Date()
      });

      // 4. Remove from list
      setPhotos(prev => prev.filter(p => p.id !== photo.id));
      
    } catch (error) {
      console.error("Approval failed:", error);
      alert('승인 처리 중 오류가 발생했습니다.');
    } finally {
      setProcessingId(null);
    }
  };

  const handleReject = async (photo: PendingPhoto) => {
    if (!window.confirm('이 사진을 거절하시겠습니까? (영구 삭제됩니다)')) return;
    setProcessingId(photo.id);

    try {
      // 1. Update status
      await updateDoc(doc(db, 'pending_photos', photo.id), {
        status: 'rejected',
        processedAt: new Date()
      });

      // 2. Try to delete from storage to save space (optional, but good practice)
      try {
        const imageRef = ref(storage, photo.url);
        await deleteObject(imageRef);
      } catch (e) {
        console.warn('Could not delete image from storage:', e);
      }

      // 3. Remove from list
      setPhotos(prev => prev.filter(p => p.id !== photo.id));
    } catch (error) {
      console.error("Rejection failed:", error);
      alert('거절 처리 중 오류가 발생했습니다.');
    } finally {
      setProcessingId(null);
    }
  };

  return (
    <div className="max-w-6xl mx-auto p-6 md:p-8">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-[24px] font-bold text-primary flex items-center gap-2">
            <Camera className="text-toss-blue" /> 사진 등록 관리 (대기열)
          </h1>
          <p className="text-[15px] text-secondary mt-1">
            입주민이 등록한 단지 사진을 검토하고 승인/거절합니다.
          </p>
        </div>
        <div className="bg-body px-4 py-2 rounded-xl text-[14px] font-bold text-secondary">
          대기 중: <span className="text-toss-blue">{photos.length}</span>건
        </div>
      </div>

      {loading ? (
        <div className="flex flex-col items-center justify-center py-20 text-tertiary">
          <Loader2 size={32} className="animate-spin mb-4" />
          <p>업로드 내역을 불러오는 중...</p>
        </div>
      ) : photos.length === 0 ? (
        <div className="bg-surface border border-border rounded-2xl p-16 flex flex-col items-center justify-center text-center shadow-sm">
          <div className="w-16 h-16 bg-body rounded-full flex items-center justify-center mb-4">
            <Check size={32} className="text-tertiary" />
          </div>
          <h3 className="text-[18px] font-bold text-primary mb-1">대기 중인 사진이 없습니다</h3>
          <p className="text-[14px] text-tertiary">모든 등록 사진 처리가 완료되었습니다.</p>
        </div>
      ) : (
        <div className="flex flex-col gap-6">
          {photos.map(photo => (
            <div key={photo.id} className="bg-surface border border-border rounded-2xl overflow-hidden shadow-sm hover:shadow-md transition-shadow flex flex-col md:flex-row group">
              {/* Image Preview Area - Large Left Panel */}
              <div 
                className="relative w-full md:w-[400px] lg:w-[480px] shrink-0 bg-body cursor-pointer overflow-hidden aspect-[4/3] md:aspect-auto md:min-h-[320px]"
                onClick={() => window.open(photo.url, '_blank')}
                title="클릭하여 원본 보기"
              >
                <Image 
                  src={photo.url} 
                  alt="등록 사진" 
                  fill 
                  className="object-cover group-hover:scale-105 transition-transform duration-500 ease-out"
                  sizes="(max-width: 768px) 100vw, 480px"
                />
                <div className="absolute inset-0 bg-gradient-to-t from-black/70 via-transparent to-transparent opacity-90" />
                
                <div className="absolute top-4 right-4">
                  <span className="text-white/90 text-[12px] font-bold px-3 py-1.5 bg-black/40 backdrop-blur-md rounded-lg shadow-sm">
                    {photo.createdAt?.toDate ? new Date(photo.createdAt.toDate()).toLocaleDateString() : '최근 등록'}
                  </span>
                </div>

                <div className="absolute bottom-4 left-4 right-4 flex flex-col gap-1.5">
                  <span className="w-fit bg-toss-blue text-white text-[12px] font-extrabold px-2.5 py-1 rounded shadow-sm uppercase tracking-wide">
                    {photo.locationTag}
                  </span>
                  <h3 className="text-[20px] font-black text-white drop-shadow-md truncate">
                    {photo.apartmentName}
                  </h3>
                </div>
              </div>

              {/* Card Body - Right Panel */}
              <div className="p-6 md:p-8 flex-1 flex flex-col">
                <div className="flex items-center justify-between mb-4">
                  <h4 className="text-[16px] font-extrabold text-primary">사진 설명 및 업로더 정보</h4>
                  <div className="flex items-center gap-2 text-[13px] text-tertiary font-medium bg-body px-3 py-1.5 rounded-full">
                    <div className="w-6 h-6 rounded-full bg-toss-blue/10 flex items-center justify-center text-toss-blue font-extrabold text-[11px]">
                      {photo.uploaderName ? photo.uploaderName.charAt(0) : '익'}
                    </div>
                    {photo.uploaderName || '익명 사용자'}
                  </div>
                </div>

                {/* Caption / Description Box */}
                <div className="bg-body rounded-xl p-5 mb-6 flex-1 border border-border/50 shadow-inner">
                  <p className="text-[15px] text-secondary leading-relaxed whitespace-pre-wrap">
                    {photo.caption ? `"${photo.caption}"` : <span className="text-tertiary italic">작성된 설명이 없습니다.</span>}
                  </p>
                </div>
                
                {/* Action Buttons */}
                <div className="grid grid-cols-2 gap-4 mt-auto pt-4">
                  <button 
                    onClick={() => handleReject(photo)}
                    disabled={processingId === photo.id}
                    className="flex items-center justify-center gap-2 py-4 rounded-xl text-[15px] font-bold text-toss-red bg-toss-red/10 hover:bg-toss-red/20 transition-colors disabled:opacity-50"
                  >
                    {processingId === photo.id ? <Loader2 size={18} className="animate-spin" /> : <X size={18} strokeWidth={3} />}
                    거절 및 삭제
                  </button>
                  <button 
                    onClick={() => handleApprove(photo)}
                    disabled={processingId === photo.id}
                    className="flex items-center justify-center gap-2 py-4 rounded-xl text-[15px] font-bold text-white bg-toss-blue hover:opacity-90 shadow-sm hover:shadow transition-all disabled:opacity-50"
                  >
                    {processingId === photo.id ? <Loader2 size={18} className="animate-spin" /> : <Check size={18} strokeWidth={3} />}
                    승인 (즉시 노출)
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

'use client';

import { useState, useMemo, useTransition } from 'react';
import useSWR, { useSWRConfig } from 'swr';
import { Eye, Heart, BarChart2, ExternalLink, CreditCard, Activity, CalendarDays } from 'lucide-react';
import { collection, getDocs, writeBatch } from 'firebase/firestore';
import { db, auth } from '@/lib/firebaseConfig';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid } from 'recharts';
import { getDailyContentViews, ContentView } from '@/lib/repositories/traffic.repository';

interface TrafficRow {
  name: string;
  dong: string;
  viewCount: number;
  likes: number;
}

const fetchAnalyticsData = async () => {
  const idToken = await auth.currentUser?.getIdToken();
  const gaRes = await fetch('/api/admin/analytics', {
    headers: idToken ? { 'Authorization': `Bearer ${idToken}` } : {}
  });
  const gaJson = await gaRes.json();
  
  const metaRes = await fetch('/api/dashboard-init');
  const metaData = await metaRes.json();
  const aptMeta = metaData.apartmentMeta || {};

  const snap = await getDocs(collection(db, 'scoutingReports'));
  const viewMap: Record<string, number> = {};
  const likeMap: Record<string, number> = {};
  snap.docs.forEach(d => {
    const data = d.data();
    const apt = data.apartmentName as string;
    if (!apt) return;
    viewMap[apt] = (viewMap[apt] || 0) + (data.viewCount || 0);
    likeMap[apt] = (likeMap[apt] || 0) + (data.likes || 0);
  });

  const aptViewSnap = await getDocs(collection(db, 'apartmentViews')).catch(() => null);
  if (aptViewSnap) {
    aptViewSnap.docs.forEach(d => {
      viewMap[d.id] = (viewMap[d.id] || 0) + (d.data().count || 0);
    });
  }

  const rows = Object.keys(aptMeta).map(name => ({
    name,
    dong: (aptMeta[name] as Record<string, unknown>)?.dong || '',
    viewCount: viewMap[name] || 0,
    likes: likeMap[name] || 0,
  }));

  return {
    gaData: gaJson.data || [],
    trafficData: rows as TrafficRow[]
  };
};

export default function TrafficPage() {
  const { mutate } = useSWRConfig();
  const [isPending, startTransition] = useTransition();

  const [activeTab, setActiveTab] = useState<'daily' | 'cumulative'>('daily');
  const [selectedDate, setSelectedDate] = useState<string>('');
  
  const { data: analyticsData, isLoading: isAnalyticsLoading } = useSWR('analytics-data', fetchAnalyticsData, {
    revalidateOnFocus: false,
    onSuccess: (data) => {
      if (data.gaData && data.gaData.length > 0 && !selectedDate) {
        setSelectedDate(data.gaData[data.gaData.length - 1].date);
      }
    }
  });

  const gaData = analyticsData?.gaData || [];
  const trafficData = analyticsData?.trafficData || [];

  const { data: contentViews = [] } = useSWR(
    selectedDate ? ['content-views', selectedDate] : null, 
    ([_, date]) => getDailyContentViews(date as string),
    { revalidateOnFocus: false }
  );
  
  const [trafficSort, setTrafficSort] = useState<'viewCount' | 'likes'>('viewCount');
  const [selectedDong, setSelectedDong] = useState<string>('전체');
  
  const loading = isAnalyticsLoading && (!analyticsData); // Show loading only on initial fetch

  const handleReset = async () => {
    if (!confirm('경고: 정말 모든 단지의 누적 조회수와 관심 기록을 0으로 초기화하시겠습니까?\n(일자별 로그는 삭제되지 않습니다)')) return;
    
    const previousData = analyticsData;
    mutate('analytics-data', {
      ...analyticsData,
      trafficData: trafficData.map(r => ({ ...r, viewCount: 0, likes: 0 }))
    }, false);

    try {
      const batch = writeBatch(db);
      
      const snap = await getDocs(collection(db, 'scoutingReports'));
      snap.docs.forEach(d => {
        batch.update(d.ref, { viewCount: 0, likes: 0 });
      });

      const aptViewSnap = await getDocs(collection(db, 'apartmentViews')).catch(() => null);
      if (aptViewSnap) {
        aptViewSnap.docs.forEach(d => batch.delete(d.ref));
      }

      await batch.commit();
      alert('누적 트래픽 데이터가 초기화되었습니다.');
    } catch (e: unknown) {
      console.error(e);
      mutate('analytics-data', previousData, false);
      alert('초기화 중 오류 발생: ' + (e as Error).message);
    }
  };

  const handleTabChange = (tab: 'daily' | 'cumulative') => startTransition(() => setActiveTab(tab));
  const handleDateChange = (date: string) => startTransition(() => setSelectedDate(date));
  const handleDongChange = (dong: string) => startTransition(() => setSelectedDong(dong));
  const handleSortChange = (sort: 'viewCount' | 'likes') => startTransition(() => setTrafficSort(sort));

  const dongs = useMemo(() => Array.from(new Set(trafficData.map(r => r.dong))).filter(Boolean).sort(), [trafficData]);

  const sortedData = useMemo(() => {
    let base = trafficData;
    if (selectedDong !== '전체') {
      base = base.filter(r => r.dong === selectedDong);
    }
    return [...base].sort((a, b) => b[trafficSort] - a[trafficSort]);
  }, [trafficData, trafficSort, selectedDong]);

  const maxViews = Math.max(...sortedData.map(r => r.viewCount), 1);
  const maxLikes = Math.max(...sortedData.map(r => r.likes), 1);
  const totalViews = sortedData.reduce((s, r) => s + r.viewCount, 0);
  const totalLikes = sortedData.reduce((s, r) => s + r.likes, 0);

  return (
    <div className={`animate-in fade-in duration-300 pb-20 transition-opacity ${isPending ? 'opacity-50 pointer-events-none' : 'opacity-100'}`}>
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:justify-between sm:items-end gap-4 mb-8">
        <div>
          <h1 className="text-2xl md:text-3xl font-bold text-primary tracking-tight mb-2">트래픽 분석</h1>
          <p className="text-secondary text-[14px]">웹 사이트 및 임장 리포트 트래픽 지표</p>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex bg-body p-1 rounded-xl mb-8 w-fit">
        <button 
          onClick={() => handleTabChange('daily')}
          className={`flex items-center gap-2 px-5 py-2.5 rounded-lg text-[14px] font-bold transition-all ${activeTab === 'daily' ? 'bg-surface text-primary shadow-sm' : 'text-tertiary hover:text-secondary'}`}
        >
          <Activity size={16} /> 구글 애널리틱스 (GA4)
        </button>
        <button 
          onClick={() => handleTabChange('cumulative')}
          className={`flex items-center gap-2 px-5 py-2.5 rounded-lg text-[14px] font-bold transition-all ${activeTab === 'cumulative' ? 'bg-surface text-primary shadow-sm' : 'text-tertiary hover:text-secondary'}`}
        >
          <BarChart2 size={16} /> 누적 아파트 지표
        </button>
      </div>

      {loading && <div className="flex justify-center py-16"><div className="w-7 h-7 border-4 border-toss-blue border-t-transparent rounded-full animate-spin" /></div>}

      {/* ─── 일자별 트래픽 탭 (Daily Tab) ─── */}
      {!loading && activeTab === 'daily' && (
        <div className="space-y-6">
          {/* Chart Section */}
          <div className="bg-surface rounded-2xl border border-border shadow-sm p-6">
            <h2 className="text-[16px] font-bold text-primary mb-1 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Activity size={18} className="text-toss-blue" /> 구글 애널리틱스 트래픽 (순수 방문자)
              </div>
              <span className="text-[12px] font-medium text-tertiary bg-body px-2 py-1 rounded-md">
                과도한 봇(Bot) 및 내부 개발자 트래픽이 자동 필터링됩니다.
              </span>
            </h2>
            <div className="h-[280px] w-full mt-6">
              {gaData.length === 0 ? (
                <div className="h-full flex items-center justify-center text-tertiary">구글 애널리틱스 데이터를 불러오는 중이거나 아직 기록이 없습니다.</div>
              ) : (
                <ResponsiveContainer width="100%" height="100%" minWidth={1} minHeight={1}>
                  <BarChart data={gaData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e5e8eb" />
                    <XAxis 
                      dataKey="date" 
                      axisLine={false} 
                      tickLine={false} 
                      tick={{ fill: '#8b95a1', fontSize: 12 }} 
                      tickFormatter={(val) => val.slice(5)} 
                      dy={10}
                    />
                    <YAxis 
                      allowDecimals={false}
                      axisLine={false} 
                      tickLine={false} 
                      tick={{ fill: '#8b95a1', fontSize: 12 }} 
                    />
                    <Tooltip 
                      cursor={{ fill: '#f2f4f6' }}
                      contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1), 0 2px 4px -2px rgb(0 0 0 / 0.1)' }}
                      labelStyle={{ color: '#8b95a1', fontWeight: 'bold', marginBottom: '4px' }}
                    />
                    <Bar dataKey="activeUsers" name="순수 방문자 수" fill="#3182f6" radius={[4, 4, 0, 0]} maxBarSize={40} />
                    <Bar dataKey="pageViews" name="페이지 뷰" fill="#ff8a3d" radius={[4, 4, 0, 0]} maxBarSize={40} />
                  </BarChart>
                </ResponsiveContainer>
              )}
            </div>
          </div>

          {/* Daily Content Views Section */}
          <div className="bg-surface rounded-2xl border border-border shadow-sm p-6 overflow-hidden">
            <div className="flex flex-col sm:flex-row sm:items-center justify-between mb-6 gap-4">
              <h2 className="text-[16px] font-bold text-primary flex items-center gap-2">
                <CalendarDays size={18} className="text-[#ff8a3d]" /> 
                일자별 콘텐츠 콘텐츠 조회수
              </h2>
              <select 
                value={selectedDate}
                onChange={e => handleDateChange(e.target.value)}
                className="bg-body text-secondary font-bold text-[14px] px-4 py-2 rounded-xl outline-none"
              >
                {[...gaData].reverse().map(s => (
                  <option key={s.date} value={s.date}>{s.date}</option>
                ))}
              </select>
            </div>

            {contentViews.length === 0 ? (
              <div className="py-12 text-center text-tertiary">해당 일자에 조회된 콘텐츠가 없습니다.</div>
            ) : (
              <table className="w-full text-sm">
                <thead className="bg-body border-b border-border">
                  <tr className="text-tertiary text-xs font-bold">
                    <th className="py-3 pl-4 text-left w-8">#</th>
                    <th className="py-3 text-left w-16">구분</th>
                    <th className="py-3 text-left">콘텐츠 명</th>
                    <th className="py-3 pr-4 text-right text-toss-blue">조회수</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-[#f2f4f6]">
                  {contentViews.map((c, i) => (
                    <tr key={c.id} className="hover:bg-body transition-colors">
                      <td className="py-3 pl-4 text-center">
                        <span className={`text-xs font-extrabold ${i < 3 ? 'text-[#f59e0b]' : 'text-tertiary'}`}>{i + 1}</span>
                      </td>
                      <td className="py-3">
                        <span className={`text-[11px] font-bold px-2 py-0.5 rounded-md ${c.type === 'report' ? 'bg-[#ffebec] text-toss-red' : 'bg-toss-blue-light text-toss-blue'}`}>
                          {c.type === 'report' ? '리포트' : '라운지'}
                        </span>
                      </td>
                      <td className="py-3 font-bold text-primary text-[13px] line-clamp-1">{c.title}</td>
                      <td className="py-3 pr-4 text-right font-bold text-toss-blue">{c.views}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>
        </div>
      )}

      {/* ─── 누적 트래픽 탭 (Cumulative Tab) ─── */}
      {!loading && activeTab === 'cumulative' && (
        <div className="space-y-6">
          <div className="flex flex-col sm:flex-row sm:justify-between gap-4">
            {/* Dong Tabs */}
            <div className="flex flex-wrap gap-2">
              <button onClick={() => handleDongChange('전체')} 
                className={`px-4 py-2 rounded-xl text-[13px] font-bold transition-all ${selectedDong === '전체' ? 'bg-toss-blue text-surface shadow-sm' : 'bg-surface border border-border text-secondary hover:bg-body'}`}>
                전체
              </button>
              {dongs.map(dong => (
                <button key={dong} onClick={() => handleDongChange(dong)} 
                  className={`px-4 py-2 rounded-xl text-[13px] font-bold transition-all ${selectedDong === dong ? 'bg-toss-blue text-surface shadow-sm' : 'bg-surface border border-border text-secondary hover:bg-body'}`}>
                  {dong}
                </button>
              ))}
            </div>

            <div className="flex items-center gap-4">
              <button onClick={handleReset} className="px-3 py-2 text-[12px] font-bold text-toss-red bg-[#ffebec] hover:bg-toss-red hover:text-surface rounded-lg transition-colors shadow-sm whitespace-nowrap">
                데이터 전체 초기화
              </button>
              <div className="flex gap-1.5 border-l border-border pl-4">
                {(['viewCount', 'likes'] as const).map(k => (
                  <button key={k} onClick={() => handleSortChange(k)}
                    className={`flex items-center justify-center gap-1.5 px-3 sm:px-4 py-2.5 rounded-xl text-[12px] sm:text-[13px] font-bold transition-all ${
                      trafficSort === k ? 'bg-primary text-surface shadow-sm' : 'bg-surface border border-border text-secondary hover:bg-body'
                    }`}>
                    {k === 'viewCount' ? <><Eye size={14}/> 조회순</> : <><Heart size={14}/> 관심순</>}
                  </button>
                ))}
              </div>
            </div>
          </div>

          {/* Summary Cards */}
          <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
            <div className="bg-surface p-4 rounded-2xl border border-border shadow-sm">
              <div className="flex items-center gap-2 mb-2">
                <div className="p-1.5 rounded-lg bg-toss-blue-light text-toss-blue"><BarChart2 size={14}/></div>
                <span className="text-[11px] font-bold text-tertiary">선택 단지</span>
              </div>
              <div className="text-[26px] font-extrabold text-toss-blue">{sortedData.length}</div>
            </div>
            <div className="bg-surface p-4 rounded-2xl border border-border shadow-sm">
              <div className="flex items-center gap-2 mb-2">
                <div className="p-1.5 rounded-lg bg-toss-blue-light text-toss-blue"><Eye size={14}/></div>
                <span className="text-[11px] font-bold text-tertiary">총 조회수</span>
              </div>
              <div className="text-[26px] font-extrabold text-toss-blue">{totalViews.toLocaleString()}</div>
            </div>
            <div className="bg-surface p-4 rounded-2xl border border-border shadow-sm">
              <div className="flex items-center gap-2 mb-2">
                <div className="p-1.5 rounded-lg bg-[#ffebec] text-toss-red"><Heart size={14}/></div>
                <span className="text-[11px] font-bold text-tertiary">총 관심</span>
              </div>
              <div className="text-[26px] font-extrabold text-toss-red">{totalLikes.toLocaleString()}</div>
            </div>
            <div className="bg-surface p-4 rounded-2xl border border-border shadow-sm">
              <div className="flex items-center gap-2 mb-2">
                <div className="p-1.5 rounded-lg bg-[#fff4e6] text-[#ff8a3d]"><Eye size={14}/></div>
                <span className="text-[11px] font-bold text-tertiary">활성 단지</span>
              </div>
              <div className="text-[26px] font-extrabold text-[#ff8a3d]">{sortedData.filter(r => r.viewCount > 0 || r.likes > 0).length}</div>
            </div>
          </div>

          <div className="bg-surface rounded-2xl border border-border shadow-sm overflow-x-auto">
            <table className="w-full text-sm min-w-[500px]">
              <thead className="bg-body border-b border-border">
                <tr className="text-tertiary text-xs font-bold">
                  <th className="py-3 pl-4 text-left w-8">#</th>
                  <th className="py-3 text-left">아파트명</th>
                  <th className="py-3 text-left text-tertiary">동</th>
                  <th className="py-3 pr-4 text-right text-toss-blue">조회수</th>
                  <th className="py-3 pr-4 text-right text-toss-red">관심</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-[#f2f4f6]">
                {sortedData.map((row, i) => (
                  <tr key={row.name} className={`hover:bg-body transition-colors ${i < 3 ? 'bg-[#fffbf5]' : ''}`}>
                    <td className="py-3 pl-4 text-center">
                      <span className={`text-xs font-extrabold ${i === 0 ? 'text-[#f59e0b]' : i === 1 ? 'text-tertiary' : i === 2 ? 'text-[#cd7c2f]' : 'text-toss-gray'}`}>{i + 1}</span>
                    </td>
                    <td className="py-3 font-bold text-primary text-[13px]">{row.name}</td>
                    <td className="py-3 text-xs text-tertiary">{row.dong}</td>
                    <td className="py-3 pr-4">
                      <div className="flex items-center justify-end gap-2">
                        <div className="w-16 sm:w-20 h-1.5 bg-body rounded-full overflow-hidden">
                          <div className="h-full bg-toss-blue rounded-full" style={{ width: `${(row.viewCount / maxViews) * 100}%` }} />
                        </div>
                        <span className="text-xs font-bold text-toss-blue tabular-nums w-8 text-right">{row.viewCount}</span>
                      </div>
                    </td>
                    <td className="py-3 pr-4">
                      <div className="flex items-center justify-end gap-2">
                        <div className="w-16 sm:w-20 h-1.5 bg-body rounded-full overflow-hidden">
                          <div className="h-full bg-toss-red rounded-full" style={{ width: `${(row.likes / maxLikes) * 100}%` }} />
                        </div>
                        <span className="text-xs font-bold text-toss-red tabular-nums w-8 text-right">{row.likes}</span>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            {trafficData.every(r => r.viewCount === 0 && r.likes === 0) && (
              <div className="py-12 text-center text-tertiary text-sm">임장 리포트가 있는 단지에서만 조회수가 집계됩니다.</div>
            )}
          </div>
        </div>
      )}


    </div>
  );
}

import { Metadata } from 'next';
import { adminDb } from '@/lib/firebaseAdmin';
import DashboardClient from '@/components/DashboardClient';
import { SHEET_ID, SHEET_TABS, parseCsvLine } from '@/lib/constants';

// --- SEO: Dynamic Metadata Generator ---
// Await the params Promise for Next.js 15+
export async function generateMetadata(props: { params: Promise<{ aptName: string }> }): Promise<Metadata> {
  const params = await props.params;
  const decodedName = decodeURIComponent(params.aptName);
  const baseUrl = process.env.NEXT_PUBLIC_SITE_URL || 'https://dongtanview.com';
  
  let imageUrl = '';
  if (adminDb) {
    try {
      const snap = await adminDb.collection('scoutingReports').where('apartmentName', '==', decodedName).limit(1).get();
      if (!snap.empty) {
        const data = snap.docs[0].data();
        if (data.images && data.images.length > 0) {
          imageUrl = data.images[0].url;
        } else if (data.thumbnailUrl) {
          imageUrl = data.thumbnailUrl;
        }
      }
    } catch (e) {
      console.warn('[SEO] Failed to fetch report image for metadata:', e);
    }
  }
  
  // Dynamic OG Image URL
  const ogUrl = new URL(`${baseUrl}/api/og`);
  ogUrl.searchParams.set('title', decodedName);
  ogUrl.searchParams.set('subtitle', '동탄 실거래가 및 가치 분석');
  if (imageUrl) {
    ogUrl.searchParams.set('bgUrl', imageUrl);
  }
  
