export const revalidate = 300;

async function getInitialData() {
  const result: {
    favoriteCounts: Record<string, number>;
    typeMap: { aptName: string; area: string; typeM2: string; typePyeong: string }[];
    apartmentMeta: Record<string, { dong?: string; txKey?: string; isPublicRental?: boolean }>;
  } = {
    favoriteCounts: {},
    typeMap: [],
    apartmentMeta: {},
  };

  const withTimeout = <T,>(promise: Promise<T>, ms: number): Promise<T> =>
    Promise.race([
      promise,
      new Promise<T>((_, reject) => setTimeout(() => reject(new Error('Firebase timeout')), ms))
    ]);

  try {
    if (adminDb) {
      const snap = await withTimeout(adminDb.collection('favoriteCounts').get(), 3000);
      snap.docs.forEach((doc) => {
        const data = doc.data();
        if (data.count > 0) result.favoriteCounts[data.aptName || doc.id] = data.count;
      });
      const metaDoc = await withTimeout(adminDb.doc('settings/apartmentMeta').get(), 3000);
      if (metaDoc.exists) result.apartmentMeta = (metaDoc.data() || {}) as Record<string, { dong?: string; txKey?: string; isPublicRental?: boolean }>;
    }
  } catch (e) {
    console.warn('[Server] Firebase init error:', e);
  }

  try {
    const csvUrl = `https://docs.google.com/spreadsheets/d/${SHEET_ID}/gviz/tq?tqx=out:csv&sheet=${encodeURIComponent(SHEET_TABS.TYPE_MAP)}`;
    const res = await fetch(csvUrl, { next: { revalidate: 86400 } });
    if (res.ok) {
      const csvText = await res.text();
      const lines = csvText.split('\n').filter((l: string) => l.trim());
      for (let i = 1; i < lines.length; i++) {
        const cols = parseCsvLine(lines[i]);
        if (cols.length < 3) continue;
        const aptName = cols[1]?.trim();
        const area = cols[2]?.trim();
        const typeM2 = cols[3]?.trim() || '';
        const typePyeong = cols[5]?.trim() || '';
        if (aptName && area && (typeM2 || typePyeong)) {
          result.typeMap.push({ aptName, area, typeM2, typePyeong });
        }
      }
    }
  } catch (e) {}

  return result;
}

export default async function ApartmentPage(props: { params: Promise<{ aptName: string }> }) {
  const params = await props.params;
  const decodedName = decodeURIComponent(params.aptName);
  const initialData = await getInitialData();
  const baseUrl = process.env.NEXT_PUBLIC_SITE_URL || 'https://dongtanview.com';

  // Fetch report for structured data (JSON-LD)
  let structuredImages: string[] = [];
  if (adminDb) {
    try {
      const snap = await adminDb.collection('scoutingReports').where('apartmentName', '==', decodedName).limit(1).get();
      if (!snap.empty) {
        const data = snap.docs[0].data();
        if (data.images && Array.isArray(data.images)) {
          structuredImages = data.images.map((img: any) => img.url).filter(Boolean);
        }
      }
    } catch (e) {}
  }

  const jsonLd = {
    "@context": "https://schema.org",
    "@type": "ApartmentComplex",
    "name": `${decodedName}`,
    "description": `동탄 ${decodedName} 아파트 실거래가 및 임장 리포트`,
    "url": `${baseUrl}/apartment/${encodeURIComponent(decodedName)}`,
    ...(structuredImages.length > 0 ? { "image": structuredImages } : {})
  };

  return (
    <>
      <script
        type="application/ld+json"
        dangerouslySetInnerHTML={{ __html: JSON.stringify(jsonLd) }}
      />
      <DashboardClient initialDashboardData={initialData} preselectedAptName={decodedName} />
    </>
  );
}

/**
 * GET /api/cron/sync-transactions
 * 
 * 국토교통부 실거래가 API → Firestore 'transactions' 신규 거래 동기화
 * Vercel Cron에서 매일 1회 호출 (vercel.json에서 설정)
 * 수동 호출도 가능: fetch('/api/cron/sync-transactions')
 */
import { NextResponse } from 'next/server';
import { adminDb as db } from '@/lib/firebaseAdmin';

export const dynamic = 'force-dynamic';

const API_KEY = process.env.BUILDING_API_KEY || '';
const LAWD_CD = '41597'; // 동탄구
const API_BASE_TRADE = 'https://apis.data.go.kr/1613000/RTMSDataSvcAptTradeDev/getRTMSDataSvcAptTradeDev';
const API_BASE_RENT = 'https://apis.data.go.kr/1613000/RTMSDataSvcAptRent/getRTMSDataSvcAptRent';

interface GovApiItem {
  aptNm: string;
  dealAmount: string;
  dealDay: string;
  dealMonth: string;
  dealYear: string;
  excluUseAr: string;
  floor: string;
  buildYear: string;
  umdNm: string;
  roadNm: string;
  buyerGbn: string;
  slerGbn: string;
  cdealDay: string;
  cdealType: string;
  dealingGbn: string;
  estateAgentSggNm: string;
  rgstDate: string;
  sggCd: string;
}

function extractDong(umdNm: string): string {
  return umdNm || '';
}

export async function GET(request: Request) {
  try {
    const authHeader = request.headers.get('authorization');
    if (
      process.env.NODE_ENV !== 'development' &&
      authHeader !== `Bearer ${process.env.CRON_SECRET}`
    ) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    if (!API_KEY) {
      return NextResponse.json({ error: 'BUILDING_API_KEY not set' }, { status: 500 });
    }
    if (!db) {
      return NextResponse.json({ error: 'Firebase DB not initialized' }, { status: 500 });
    }

    // 1. Find the latest contractDate in Firestore to determine sync range
    const collRef = db.collection('transactions');
    const latestSnap = await collRef.orderBy('contractDate', 'desc').limit(1).get();
    
    let latestYm = '';
    if (!latestSnap.empty) {
      const latestDoc = latestSnap.docs[0].data();
      latestYm = latestDoc.contractYm || '';
    }

    // 2. Determine months to sync (latest month + current month)
    const now = new Date();
    const currentYm = `${now.getFullYear()}${String(now.getMonth() + 1).padStart(2, '0')}`;
    const monthsToSync = new Set<string>();
    
    if (latestYm) {
      monthsToSync.add(latestYm); // Re-sync latest month (may have new entries)
    }
    monthsToSync.add(currentYm); // Always sync current month
    
    // Also add previous month if we're early in the month (data delay)
    if (now.getDate() <= 15) {
      const prevDate = new Date(now.getFullYear(), now.getMonth() - 1, 1);
      monthsToSync.add(`${prevDate.getFullYear()}${String(prevDate.getMonth() + 1).padStart(2, '0')}`);
    }

    // 3. Fetch from 국토부 API for each month
    let totalNew = 0;
    const syncLog: string[] = [];

    for (const ym of Array.from(monthsToSync).sort()) {
      let page = 1;
      let totalCount = 0;
      const monthRecords: unknown[] = [];

      do {
        const url = `${API_BASE_TRADE}?serviceKey=${API_KEY}&LAWD_CD=${LAWD_CD}&DEAL_YMD=${ym}&pageNo=${page}&numOfRows=1000`;
        const res = await fetch(url);
        if (!res.ok) { syncLog.push(`${ym} page ${page}: HTTP ${res.status}`); break; }

        const text = await res.text();
        // Parse XML response
        const totalMatch = text.match(/<totalCount>(\d+)<\/totalCount>/);
        totalCount = totalMatch ? parseInt(totalMatch[1], 10) : 0;

        if (totalCount === 0) break;

        // Extract items using regex (simple XML parsing)
        const items = text.match(/<item>([\s\S]*?)<\/item>/g) || [];
        
        for (const itemXml of items) {
          // Single-pass: extract ALL tags into a Map (O(1) lookups)
          // Previously: 12x new RegExp() per item -> now 1x regex scan
          const tagMap = new Map<string, string>();
          const tagRegex = /<([^>]+)>([^<]*)<\/\1>/g;
          let tagMatch;
          while ((tagMatch = tagRegex.exec(itemXml)) !== null) {
            tagMap.set(tagMatch[1], tagMatch[2].trim());
          }
          const get = (tag: string) => tagMap.get(tag) || '';

          const aptName = get('aptNm');
          const priceStr = get('dealAmount').replace(/,/g, '').trim();
          const price = parseInt(priceStr, 10) || 0;
          const area = parseFloat(get('excluUseAr')) || 0;
          const contractDay = get('dealDay').padStart(2, '0');
          const floor = parseInt(get('floor'), 10) || 0;
          const dong = get('umdNm');

          const record = {
            sigungu: `경기도 화성시 동탄구 ${dong}`,
            dong,
            aptName,
            area,
            areaPyeong: Math.round(area / 3.3058 * 10) / 10,
            contractYm: ym,
            contractDay,
            contractDate: `${ym}${contractDay}`,
            price,
            deposit: 0,
            monthlyRent: 0,
            floor,
            buyer: get('buyerGbn'),
            seller: get('slerGbn'),
            buildYear: parseInt(get('buildYear'), 10) || 0,
            roadName: get('roadNm'),
            cancelDate: get('cdealDay') || '',
            dealType: get('cdealType') || get('dealingGbn') || '매매',
            agentLocation: get('estateAgentSggNm'),
            registrationDate: get('rgstDate'),
            housingType: '',
            source: 'govt_api',
            _key: `${aptName}_${ym}_${contractDay}_${area}_${price}_${floor}`,
          };

          monthRecords.push(record);
        }

        page++;
      } while (monthRecords.length < totalCount);

      // 3.1 Fetch Rent Data (전월세)
      let rentPage = 1;
      let rentTotalCount = 0;
      do {
        const url = `${API_BASE_RENT}?serviceKey=${API_KEY}&LAWD_CD=${LAWD_CD}&DEAL_YMD=${ym}&pageNo=${rentPage}&numOfRows=1000`;
        const res = await fetch(url);
        if (!res.ok) { syncLog.push(`${ym} rent page ${rentPage}: HTTP ${res.status}`); break; }

        const text = await res.text();
        const totalMatch = text.match(/<totalCount>(\d+)<\/totalCount>/);
        rentTotalCount = totalMatch ? parseInt(totalMatch[1], 10) : 0;
        if (rentTotalCount === 0) break;

        const items = text.match(/<item>([\s\S]*?)<\/item>/g) || [];
        for (const itemXml of items) {
          const tagMap = new Map<string, string>();
          const tagRegex = /<([^>]+)>([^<]*)<\/\1>/g;
          let tagMatch;
          while ((tagMatch = tagRegex.exec(itemXml)) !== null) {
            tagMap.set(tagMatch[1], tagMatch[2].trim());
          }
          const get = (tag: string) => tagMap.get(tag) || '';

          const aptName = get('aptNm');
          const depositStr = get('deposit').replace(/,/g, '').trim();
          const monthlyRentStr = get('monthlyRent') ? get('monthlyRent').replace(/,/g, '').trim() : '0';
          
          const deposit = parseInt(depositStr, 10) || 0;
          const monthlyRent = parseInt(monthlyRentStr, 10) || 0;
          const dealType = monthlyRent > 0 ? '월세' : '전세';

          const area = parseFloat(get('excluUseAr')) || 0;
          const contractDay = get('dealDay').padStart(2, '0');
          const floor = parseInt(get('floor'), 10) || 0;
          const dong = get('umdNm');

          const record = {
            sigungu: `경기도 화성시 동탄구 ${dong}`,
            dong,
            aptName,
            area,
            areaPyeong: Math.round(area / 3.3058 * 10) / 10,
            contractYm: ym,
            contractDay,
            contractDate: `${ym}${contractDay}`,
            price: deposit, // For UI compatibility, use deposit as price
            deposit,
            monthlyRent,
            floor,
            buyer: '',
            seller: '',
            buildYear: parseInt(get('buildYear'), 10) || 0,
            roadName: get('roadNm'),
            cancelDate: '',
            dealType,
            agentLocation: '',
            registrationDate: '',
            housingType: '',
            source: 'govt_api_rent',
            reqGb: get('contractType') || '',
            rnuYn: get('useRRRight') || '',
            _key: `RENT_${aptName}_${ym}_${contractDay}_${area}_${deposit}_${floor}`,
          };
          monthRecords.push(record);
        }
        rentPage++;
      } while (rentPage * 1000 < rentTotalCount);

      // 4. Batch write to Firestore
      if (monthRecords.length > 0) {
        const BATCH_SIZE = 500;
        let written = 0;
        for (let i = 0; i < monthRecords.length; i += BATCH_SIZE) {
          const batch = db.batch();
          const slice = monthRecords.slice(i, i + BATCH_SIZE);
          for (const r of (slice as Record<string, unknown>[])) {
            batch.set(collRef.doc(r._key as string), r, { merge: true });
          }
          await batch.commit();
          written += slice.length;
        }
        totalNew += written;
        syncLog.push(`${ym}: ${written}건 동기화 (매매+전월세)`);
      } else {
        syncLog.push(`${ym}: 0건`);
      }
    }

    // 5. Trigger Vercel Deploy Hook if there are new transactions
    if (totalNew > 0 && process.env.VERCEL_DEPLOY_HOOK_URL) {
      try {
        const deployRes = await fetch(process.env.VERCEL_DEPLOY_HOOK_URL, { method: 'POST' });
        if (deployRes.ok) {
          syncLog.push('Vercel Deploy Hook Triggered Successfully');
        } else {
          syncLog.push(`Vercel Deploy Hook Failed: HTTP ${deployRes.status}`);
        }
      } catch (err) {
        syncLog.push(`Vercel Deploy Hook Error: ${(err as Error).message}`);
      }
    }

    return NextResponse.json({
      success: true,
      synced: totalNew,
      months: Array.from(monthsToSync),
      log: syncLog,
    });
  } catch (error: unknown) {
    console.error('Sync error:', error);
    return NextResponse.json({ error: (error as Error).message }, { status: 500 });
  }
}

/**
 * POST /api/favorite
 * Body: { aptName: string, userId: string }
 * 
 * Toggle favorite status for an apartment.
 * Creates/deletes a favorites doc and increments/decrements favoriteCount on the apartment.
 */
import { NextRequest, NextResponse } from 'next/server';
import { adminDb } from '@/lib/firebaseAdmin';
import { FieldValue } from 'firebase-admin/firestore';
import { verifyAuthHeader } from '@/lib/authUtils';
import { redis } from '@/lib/redis';
import { z } from 'zod';

export const dynamic = 'force-dynamic';

// 보안: NoSQL Injection 및 오버플로우 공격 방어용 인바운드 스키마 검증
const favSchema = z.object({
  aptName: z.string().min(1).max(100).trim(), // 아파트 이름 길이 제한 및 스크러빙
});

export async function POST(request: NextRequest) {
  try {
    if (!adminDb) return NextResponse.json({ error: 'DB not initialized' }, { status: 500 });

    // Auth Validation
    let decodedToken;
    try {
      decodedToken = await verifyAuthHeader(request);
    } catch (authErr) {
      return NextResponse.json({ error: 'Unauthorized Request' }, { status: 401 });
    }
    const userId = decodedToken.uid;

    const rawBody = await request.json();
    const parsed = favSchema.safeParse(rawBody);
    if (!parsed.success) {
      return NextResponse.json({ error: 'Bad Request: Invalid Payload', details: parsed.error.issues }, { status: 400 });
    }
    const { aptName } = parsed.data;

    const docId = `${userId}_${aptName}`;
    const favRef = adminDb.collection('favorites').doc(docId);
    const favSnap = await favRef.get();

    if (favSnap.exists) {
      // Remove favorite
      await favRef.delete();
      // Decrement count
      const countRef = adminDb.collection('favoriteCounts').doc(aptName);
      await countRef.set({ count: FieldValue.increment(-1), aptName }, { merge: true });
      if (redis) {
        await redis.hincrby('DTDLS:cache:favoriteCounts', aptName, -1).catch(err => console.warn('Redis HINCRBY error:', err));
      }
      return NextResponse.json({ favorited: false });
    } else {
      // Add favorite
      await favRef.set({ userId, aptName, createdAt: FieldValue.serverTimestamp() });
      // Increment count
      const countRef = adminDb.collection('favoriteCounts').doc(aptName);
      await countRef.set({ count: FieldValue.increment(1), aptName }, { merge: true });
      if (redis) {
        await redis.hincrby('DTDLS:cache:favoriteCounts', aptName, 1).catch(err => console.warn('Redis HINCRBY error:', err));
      }
      return NextResponse.json({ favorited: true });
    }
  } catch (error: unknown) {
    console.error('[favorite] Error:', error);
    return NextResponse.json({ error: 'Internal server error', details: (error as Error)?.message || String(error) }, { status: 500 });
  }
}

/**
 * GET /api/favorite?userId=xxx
 * Returns all apartments the user has favorited.
 */
export async function GET(request: NextRequest) {
  try {
    if (!adminDb) return NextResponse.json({ favorites: [], warning: 'DB not initialized' }, { status: 200 });

    // Auth Validation
    let decodedToken;
    try {
      decodedToken = await verifyAuthHeader(request);
    } catch (authErr) {
      return NextResponse.json({ favorites: [], warning: 'Unauthorized' }, { status: 401 });
    }
    const userId = decodedToken.uid;

    const requestedUserId = request.nextUrl.searchParams.get('userId');
    if (requestedUserId && requestedUserId !== userId) {
      return NextResponse.json({ favorites: [], warning: 'Forbidden' }, { status: 403 });
    }

    const withTimeout = <T,>(promise: Promise<T>, ms: number): Promise<T> =>
      Promise.race([
        promise,
        new Promise<T>((_, reject) => setTimeout(() => reject(new Error('Firebase timeout')), ms))
      ]);

    const snap = await withTimeout(adminDb.collection('favorites').where('userId', '==', userId).get(), 5000);
    const favorites = snap.docs.map(d => d.data().aptName as string);
    return NextResponse.json({ favorites });
  } catch (error: unknown) {
    console.error('[favorite GET] Error:', error);
    // Return [] instead of 500 to prevent app crashes if Firebase hangs
    return NextResponse.json({ favorites: [], error: String(error) }, { status: 200 });
  }
}

import { NextRequest, NextResponse } from 'next/server';

export const runtime = 'edge';
import { SHEET_ID, SHEET_TABS, parseCsvLine } from '@/lib/constants';
import { Coord, haversineDistance, findNearest, countWithinRadius, parseCoordString } from '@/lib/utils/haversine';

export const revalidate = 86400; // ISR: 24 hours (coordinate data rarely changes)

import { loadAllCached, resolveApartment, filterByBBox, clearCache, StationPOI } from '@/lib/services/locationService';

// ── GET Handler ────────────────────────────────────

export async function GET(request: NextRequest) {
  const apartment = request.nextUrl.searchParams.get('apartment');
  const forceRefresh = request.nextUrl.searchParams.get('refresh') === '1';

  if (!apartment) {
    return NextResponse.json({ error: 'apartment parameter is required' }, { status: 400 });
  }

  try {
    // Force cache invalidation when admin requests fresh data
    if (forceRefresh) {
      clearCache();
    }

    // Load from cache (or fetch & cache if stale/empty)
    const { apartments, schools, stations, academies, restaurants, sboyds } = await loadAllCached(forceRefresh);

    const apt = resolveApartment(apartment, apartments);
    if (!apt) {
      return NextResponse.json(
        {
          error: `Unknown apartment: ${apartment}`,
          hint: `총 ${apartments.length}개 아파트 중 좌표가 있는 항목만 로드됩니다. Google Sheets '좌표' 컬럼을 확인하세요.`,
          availableApartments: apartments.map(a => a.name),
        },
        { status: 404 }
      );
    }

    const aptCoord: Coord = { lat: apt.lat, lng: apt.lng };

    // Calculate school distances
    const elementary = schools.filter(s => s.type.includes('초'));
    const middle = schools.filter(s => s.type.includes('중'));
    const high = schools.filter(s => s.type.includes('고'));

    const nearestElementary = findNearest(aptCoord, elementary);
    const nearestMiddle = findNearest(aptCoord, middle);
    const nearestHigh = findNearest(aptCoord, high);

    // Station distances by line type
    const gtxSrtLine = stations.filter(s => s.line.includes('GTX') || s.line.includes('SRT'));
    const indeokwonLine = stations.filter(s => s.line.includes('인덕원') || s.line.includes('동탄인덕원'));
    const tramLine = stations.filter(s => s.line.includes('트램') || s.line.includes('동탄트램') || s.line.includes('도시철도'));
    console.log('[DEBUG] tramLine =>', tramLine);
    const nearestStationBase = gtxSrtLine.length > 0 ? findNearest(aptCoord, gtxSrtLine) : findNearest(aptCoord, stations);
    const nearestIndeokwonBase = indeokwonLine.length > 0 ? findNearest(aptCoord, indeokwonLine) : null;
    const nearestTramBase = tramLine.length > 0 ? findNearest(aptCoord, tramLine) : null;
    console.log('[DEBUG] nearestTramBase =>', nearestTramBase);

    // Enrich with line name from sheet column C
    const findStationLine = (name: string | undefined, pool: StationPOI[]) => pool.find(s => s.name === name)?.line || null;
    const nearestStation = nearestStationBase ? { ...nearestStationBase, line: findStationLine(nearestStationBase.name, gtxSrtLine.length > 0 ? gtxSrtLine : stations) } : null;
    const nearestIndeokwon = nearestIndeokwonBase ? { ...nearestIndeokwonBase, line: findStationLine(nearestIndeokwonBase.name, indeokwonLine) } : null;
    const nearestTram = nearestTramBase ? { ...nearestTramBase, line: findStationLine(nearestTramBase.name, tramLine) } : null;

    // Academy density: bounding box pre-filter → haversine within 500m
    const candidateAcademies = filterByBBox(aptCoord, academies);
    const nearbyAcademies = candidateAcademies.filter(a => haversineDistance(aptCoord, a) <= 500);
    const academyDensity = nearbyAcademies.length;
    const academyCategories: Record<string, number> = {};
    for (const a of nearbyAcademies) {
      academyCategories[a.category] = (academyCategories[a.category] || 0) + 1;
    }

    // Restaurant/cafe density: bounding box pre-filter → haversine within 500m
    const candidateRestaurants = filterByBBox(aptCoord, restaurants);
    const nearbyRestaurants = candidateRestaurants.filter(r => haversineDistance(aptCoord, r) <= 500);
    const restaurantDensity = nearbyRestaurants.length;
    const restaurantCategories: Record<string, number> = {};
    for (const r of nearbyRestaurants) {
      restaurantCategories[r.category] = (restaurantCategories[r.category] || 0) + 1;
    }

    // Anchor Tenants Distance calculations (Search from ALL restaurants/academies, not just 500m)
    const findAnchor = (keywords: string[]) => {
      // SBOYDS(수기 데이터)와 기존 상권(restaurants) 데이터 모두 통합 검색
      const sboydsMatches = sboyds.filter(r => keywords.some(k => r.name.includes(k)));
      const restMatches = restaurants.filter(r => keywords.some(k => r.name.includes(k)));
      
      const combined = [...sboydsMatches, ...restMatches];
      return combined.length > 0 ? findNearest(aptCoord, combined) : null;
    };
    
    const nearestStarbucks = findAnchor(['스타벅스']);
    const nearestMcDonalds = findAnchor(['맥도날드']);
    const nearestOliveYoung = findAnchor(['올리브영']);
    const nearestDaiso = findAnchor(['다이소']);
    const nearestSupermarket = findAnchor(['이마트', '홈플러스', '롯데마트', '노브랜드']);

    // Parking per household
    const parkingPerHousehold = (apt.householdCount && apt.parkingCount)
      ? Math.round((apt.parkingCount / apt.householdCount) * 100) / 100
      : null;

    const result = {
      apartmentName: apartment,
      coordinates: aptCoord,
      distanceToElementary: nearestElementary?.distance ?? null,
      distanceToMiddle: nearestMiddle?.distance ?? null,
      distanceToHigh: nearestHigh?.distance ?? null,
      distanceToSubway: nearestStation?.distance ?? null,
      distanceToIndeokwon: nearestIndeokwon?.distance ?? null,
      distanceToTram: nearestTram?.distance ?? null,
      academyDensity,
      academyCategories,
      restaurantDensity,
      restaurantCategories,
      
      // Anchor Tenants Distances
      distanceToStarbucks: nearestStarbucks?.distance ?? null,
      distanceToMcDonalds: nearestMcDonalds?.distance ?? null,
      distanceToOliveYoung: nearestOliveYoung?.distance ?? null,
      distanceToDaiso: nearestDaiso?.distance ?? null,
      distanceToSupermarket: nearestSupermarket?.distance ?? null,

      // Building info from sheet
      buildingInfo: {
        householdCount: apt.householdCount ?? null,
        yearBuilt: apt.yearBuilt ?? null,
        far: apt.far ?? null,
        bcr: apt.bcr ?? null,
        parkingPerHousehold,
        brand: apt.brand ?? null,
      },
      nearestSchools: {
        elementary: nearestElementary,
        middle: nearestMiddle,
        high: nearestHigh,
      },
      nearestStation,
      nearestIndeokwon,
      nearestTram,
      meta: {
        totalSchools: schools.length,
        totalStations: stations.length,
        totalAcademies: academies.length,
        totalRestaurants: restaurants.length,
        totalApartments: apartments.length,
      },
    };

    return NextResponse.json(result, {
      headers: { 'Cache-Control': 'public, s-maxage=86400, stale-while-revalidate=172800' },
    });
  } catch (error: unknown) {
    const msg = error instanceof Error ? (error as Error).message : 'Unknown error';
    console.error('[LOCATION_SCORES] Error:', msg);
    return NextResponse.json(
      { error: 'Failed to calculate location scores', detail: msg },
      { status: 500 }
    );
  }
}

