                  (post?.category === '부동산 고민상담' || post?.category === '부동산 기초' || post?.category === '부동산') ? 'bg-[#ffe8e8] text-toss-red' :
                  (post?.category === '동탄 청약/대출' || post?.category === '정책자금 대출') ? 'bg-toss-blue-light text-toss-blue' :
