                            {/* eslint-disable-next-line @next/next/no-img-element */}
                            <img 
                              src={props.src} 
                              alt={props.alt || '첨부 이미지'} 
                              sizes="(max-width: 768px) 100vw, 800px"
                              decoding="async"
                              fetchPriority="high"
                              className="w-full h-auto object-contain max-h-[70vh]"
