  const [apiCategories, setApiCategories] = useState<ApiCategories>({});
  const router = useRouter();

  const [thumbnailFile, setThumbnailFile] = useState<File | null>(null);
  const [thumbnailPreview, setThumbnailPreview] = useState<string>(initialData?.thumbnailUrl || '');
  const [uploadProgress, setUploadProgress] = useState<{done: number, total: number} | null>(null);

  const methods = useForm<FormValues>({
    defaultValues: initialData || {
      dong: lockedMeta?.dong || '',
      apartmentName: lockedMeta?.apartmentName || '',
      scoutingDate: new Date().toLocaleDateString('en-CA'),
      metrics: {
        brand: '', householdCount: '', far: '', bcr: '', parkingPerHousehold: '', yearBuilt: '',
        distanceToElementary: '', distanceToMiddle: '', distanceToHigh: '', distanceToSubway: '', distanceToIndeokwon: '', distanceToTram: '', distanceToStarbucks: '', distanceToMcDonalds: '', distanceToOliveYoung: '', distanceToDaiso: '', distanceToSupermarket: '', starbucksName: '', starbucksAddress: '', starbucksCoordinates: '', mcdonaldsName: '', mcdonaldsAddress: '', mcdonaldsCoordinates: '', oliveYoungName: '', oliveYoungAddress: '', oliveYoungCoordinates: '', daisoName: '', daisoAddress: '', daisoCoordinates: '', supermarketName: '', supermarketAddress: '', supermarketCoordinates: '', academyDensity: '', restaurantDensity: ''
      },
      images: [],
      isPremium: true
    }
  });

  const { handleSubmit, reset, getValues, setValue } = methods;

  useEffect(() => {
    try {
      const key = `draft_report_${reportId || 'new'}`;
      const raw = localStorage.getItem(key);
      if (!raw) return;
      const draft = JSON.parse(raw);
      if (!draft._savedAt) return;
      const savedTime = new Date(draft._savedAt).toLocaleString('ko-KR');
      if (confirm(`💾 ${savedTime}에 임시 저장된 데이터가 있습니다.\n불러오시겠습니까?`)) {
        const { _savedAt, images, ...rest } = draft;
        reset({ ...rest, images: initialData?.images || [] });
      } else {
        localStorage.removeItem(key);
      }
    } catch { /* ignore */ }
  }, [reportId, initialData, reset]);

  useEffect(() => {
    if (initialData) {
      reset(initialData);
      const m = initialData.metrics as Record<string, unknown>;
      if (m) {
        setApiCategories(prev => ({
          ...prev,
          ...(m.academyCategories ? { academyCategories: m.academyCategories as Record<string, number> } : {}),
          ...(m.restaurantCategories ? { restaurantCategories: m.restaurantCategories as Record<string, number> } : {}),
          ...(m.restaurantDensity ? { restaurantDensity: m.restaurantDensity as number } : {}),
          ...(m.nearestSchoolNames ? { nearestSchoolNames: m.nearestSchoolNames as Record<string, string> } : {}),
          ...(m.nearestStationName ? { nearestStationName: m.nearestStationName as string } : {}),
          ...(m.nearestIndeokwonStationName ? { nearestIndeokwonStationName: m.nearestIndeokwonStationName as string } : {}),
          ...(m.nearestTramStationName ? { nearestTramStationName: m.nearestTramStationName as string } : {}),
        }));
      }

      const hasCategories = m?.academyCategories && Object.keys(m.academyCategories).length > 0;
      if (!hasCategories && initialData.apartmentName) {
        (async () => {
          try {
            const res = await fetch(`/api/location-scores?apartment=${encodeURIComponent(initialData.apartmentName)}`);
            if (!res.ok) return;
            const loc = await res.json();
            if (loc.distanceToElementary != null) setValue('metrics.distanceToElementary', String(loc.distanceToElementary));
            if (loc.distanceToMiddle != null) setValue('metrics.distanceToMiddle', String(loc.distanceToMiddle));
            if (loc.distanceToHigh != null) setValue('metrics.distanceToHigh', String(loc.distanceToHigh));
            if (loc.distanceToSubway != null) setValue('metrics.distanceToSubway', String(loc.distanceToSubway));
            if (loc.distanceToIndeokwon != null) setValue('metrics.distanceToIndeokwon', String(loc.distanceToIndeokwon));
            if (loc.distanceToTram != null) setValue('metrics.distanceToTram', String(loc.distanceToTram));
            if (loc.academyDensity != null) setValue('metrics.academyDensity', String(loc.academyDensity));
            if (loc.restaurantDensity != null) setValue('metrics.restaurantDensity', String(loc.restaurantDensity));
            const bld = loc.buildingInfo;
            if (bld) {
              if (bld.brand) setValue('metrics.brand', bld.brand);
              if (bld.householdCount) setValue('metrics.householdCount', String(bld.householdCount));
              if (bld.yearBuilt) setValue('metrics.yearBuilt', String(bld.yearBuilt));
              if (bld.far) setValue('metrics.far', String(bld.far));
              if (bld.bcr) setValue('metrics.bcr', String(bld.bcr));
              if (bld.parkingPerHousehold) setValue('metrics.parkingPerHousehold', String(bld.parkingPerHousehold));
            }
            setApiCategories({
              academyCategories: loc.academyCategories || {},
              restaurantDensity: loc.restaurantDensity,
              restaurantCategories: loc.restaurantCategories || {},
              nearestSchoolNames: {
                elementary: loc.nearestSchools?.elementary?.name,
                middle: loc.nearestSchools?.middle?.name,
                high: loc.nearestSchools?.high?.name,
              },
              nearestStationName: loc.nearestStation?.name,
              nearestIndeokwonStationName: loc.nearestIndeokwon?.name,
              nearestTramStationName: loc.nearestTram?.name,
            });
          } catch { /* silent fail */ }
        })();
      }
    }
  }, [initialData, reset, setValue]);

  const onSubmit = async (data: FormValues) => {
    setIsSubmitting(true);
    try {
      if (!auth.currentUser) throw new Error("로그인이 필요합니다.");

      const uploadedImages: { url: string; caption: string; locationTag: string; isPremium: boolean; capturedAt?: string }[] = [];
      const imagesToProcess = data.images.filter((img) => img.file || img.url);
      const totalImages = imagesToProcess.length;
      let uploadedCount = 0;
      setUploadProgress({ done: 0, total: totalImages });

      const BATCH_SIZE = 3;
      for (let i = 0; i < imagesToProcess.length; i += BATCH_SIZE) {
        const batch = imagesToProcess.slice(i, i + BATCH_SIZE);
        const results = await Promise.all(
          batch.map(async (img) => {
            let finalUrl = img.url;
            if (img.file) finalUrl = await uploadImage(img.file, 'report_images');
            return finalUrl ? { url: finalUrl, caption: img.caption || '', locationTag: img.locationTag || '', isPremium: img.isPremium, capturedAt: img.capturedAt } : null;
          })
        );
        results.forEach(r => { if (r) uploadedImages.push(r); });
        uploadedCount += batch.length;
        setUploadProgress({ done: uploadedCount, total: totalImages });
      }

      if (uploadedImages.length === 0) throw new Error("최소 1개 이상의 현장 사진을 업로드해주세요.");

      const metricsPayload = {
        brand: data.metrics.brand,
        householdCount: Number(data.metrics.householdCount),
        far: Number(data.metrics.far),
        bcr: Number(data.metrics.bcr),
        parkingPerHousehold: Number(data.metrics.parkingPerHousehold),
        yearBuilt: Number(data.metrics.yearBuilt),
        distanceToElementary: Number(data.metrics.distanceToElementary),
        distanceToMiddle: Number(data.metrics.distanceToMiddle),
        distanceToHigh: Number(data.metrics.distanceToHigh),
        distanceToSubway: Number(data.metrics.distanceToSubway),
        distanceToIndeokwon: Number(data.metrics.distanceToIndeokwon),
        distanceToTram: Number(data.metrics.distanceToTram),
        distanceToStarbucks: Number(data.metrics.distanceToStarbucks),
        distanceToMcDonalds: Number(data.metrics.distanceToMcDonalds),
        distanceToOliveYoung: Number(data.metrics.distanceToOliveYoung),
        distanceToDaiso: Number(data.metrics.distanceToDaiso),
        distanceToSupermarket: Number(data.metrics.distanceToSupermarket),
        starbucksName: data.metrics.starbucksName || undefined,
        starbucksAddress: data.metrics.starbucksAddress || undefined,
        starbucksCoordinates: data.metrics.starbucksCoordinates || undefined,
        academyDensity: Number(data.metrics.academyDensity),
        ...(apiCategories.academyCategories ? { academyCategories: apiCategories.academyCategories } : {}),
        ...(Number(data.metrics.restaurantDensity) || apiCategories.restaurantDensity ? { restaurantDensity: Number(data.metrics.restaurantDensity) || apiCategories.restaurantDensity } : {}),
        ...(apiCategories.restaurantCategories ? { restaurantCategories: apiCategories.restaurantCategories } : {}),
        ...(apiCategories.nearestSchoolNames ? { nearestSchoolNames: apiCategories.nearestSchoolNames } : {}),
        ...(apiCategories.nearestStationName ? { nearestStationName: apiCategories.nearestStationName } : {}),
        ...(apiCategories.nearestIndeokwonStationName ? { nearestIndeokwonStationName: apiCategories.nearestIndeokwonStationName } : {}),
        ...(apiCategories.nearestTramStationName ? { nearestTramStationName: apiCategories.nearestTramStationName } : {}),
      };

      const safeMetricsPayload = JSON.parse(JSON.stringify(metricsPayload));
      const premiumScores = await getPremiumScoresAction(safeMetricsPayload);

      let finalThumbnailUrl = thumbnailPreview || '';
      if (thumbnailFile) {
        finalThumbnailUrl = await uploadImage(thumbnailFile, 'thumbnails');
      }

      const reportData = {
        dong: data.dong,
        apartmentName: data.apartmentName,
        scoutingDate: data.scoutingDate,
        thumbnailUrl: finalThumbnailUrl || uploadedImages[0]?.url || '',
        images: uploadedImages,
        metrics: safeMetricsPayload,
        premiumScores,
        isPremium: data.isPremium,
        premiumContent: data.premiumContent || '',
        authorUid: auth.currentUser.uid
      };

      if (reportId) {
        await updateScoutingReport(reportId, reportData);
        alert("데이터가 성공적으로 수정되었습니다!");
      } else {
        await createScoutingReport(reportData);
        alert("데이터가 성공적으로 발행 및 저장되었습니다!");
      }
      
      if (onSuccess) {
        onSuccess();
      } else if (onCancel) {
        onCancel();
        window.location.reload(); 
      } else {
        router.push('/admin'); 
      }
    } catch (error: unknown) {
      console.error(error);
      alert(`오류가 발생했습니다: ${(error as Error).message}`);
    } finally {
      setIsSubmitting(false);
      setUploadProgress(null);
    }
  };

  return (
    <FormProvider {...methods}>
      <form onSubmit={handleSubmit(onSubmit)} className="p-6 md:p-8">
        
        <BasicInfoSection lockedMeta={lockedMeta} />
        
        <ThumbnailSection 
          thumbnailPreview={thumbnailPreview} 
          setThumbnailPreview={setThumbnailPreview} 
          setThumbnailFile={setThumbnailFile} 
        />
        
        <MetricsSection 
          isCalculating={isCalculating} 
          setIsCalculating={setIsCalculating} 
          apiCategories={apiCategories} 
          setApiCategories={setApiCategories} 
        />

        <ImageUploadSection />

        {/* 4. Publishing & Save */}
        <div className="fixed bottom-0 left-0 right-0 md:left-[240px] bg-surface/90 backdrop-blur-md p-4 border-t border-border shadow-[0_-10px_30px_rgba(0,0,0,0.05)] flex justify-end gap-3 z-50">
          {onCancel && (
            <button type="button" onClick={onCancel} className="px-6 py-3 font-bold text-tertiary bg-surface border border-border hover:bg-body rounded-xl transition-colors">
              취소
            </button>
          )}
          <button
            type="button"
            onClick={() => {
              try {
                const data = getValues();
                const safeData = {
                  ...data,
                  images: (data.images || []).map((img) => ({
                    url: img.url || '',
                    previewUrl: img.previewUrl || '',
                    caption: img.caption || '',
                    locationTag: img.locationTag || '',
                  })),
                  _savedAt: new Date().toISOString(),
                };
                localStorage.setItem(`draft_report_${reportId || 'new'}`, JSON.stringify(safeData));
                alert('✅ 임시 저장되었습니다!');
              } catch (err) {
                console.error('Draft save error:', err);
                alert('임시 저장에 실패했습니다.');
              }
            }}
            className="px-6 py-3 font-bold text-secondary bg-body hover:bg-[#e5e8eb] rounded-xl transition-colors"
          >
            임시 저장
          </button>
          <button 
            type="submit" 
            disabled={isSubmitting}
            className="px-8 py-3 font-bold text-surface bg-toss-blue hover:bg-[#2b72d6] active:bg-[#1b64da] rounded-xl transition-colors flex items-center gap-2 disabled:opacity-50 min-w-[180px] justify-center"
          >
            {isSubmitting ? (
              <>
                <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                {uploadProgress ? (
                  <span className="text-[13px]">{uploadProgress.done}/{uploadProgress.total}장 업로드 중...</span>
                ) : (
                  <span className="text-[13px]">저장 중...</span>
                )}
              </>
            ) : (
              <>
                <CheckCircle2 size={18} />
                {reportId ? '수정 완료하기' : '최종 발행하기'}
              </>
            )}
          </button>
        </div>

      </form>
    </FormProvider>
  );
}

import React from 'react';
import { ImagePlus, Trash2, ArrowUpDown } from 'lucide-react';
import { PhotoItem } from '@/lib/types/scoutingReport';

const IMAGE_CATEGORY_GROUPS: { group: string; items: string[] }[] = [
  { group: '🏢 단지 전경', items: ['단지 전경 (메인)', '단지 전경 (항공/드론)', '단지 조감도', '기타'] },
  { group: '🚪 문주·출입구', items: ['정문 (메인게이트)', '후문/측문', '차량 출입구', '보행자 출입구', '보안실', '기타'] },
  { group: '🌿 조경·외부', items: ['중앙 조경', '산책로/보행로', '수경시설 (분수/연못)', '놀이터', '운동기구/트랙', '정원/화단', '야외 카페', '경로당', '단지 내 어린이집', '분리수거장/쓰레기', '단지 내 상가', '기타'] },
  { group: '🅿 주차장', items: ['지하주차장 입구', '지하주차장 내부', '주차장 바닥/도색', '지상 주차', 'EV 충전기', '기타'] },
  { group: '🏋️ 커뮤니티', items: ['커뮤니티 외관/입구', '피트니스센터 (헬스장)', '골프연습장', '실내 수영장', '키즈카페/놀이방', '독서실/스터디룸', '사우나/찜질방', '기타 커뮤니티'] },
  { group: '🏠 동별·세대', items: ['동 외관', '엘리베이터/로비', '복도/계단', '택배함/무인택배', '기타'] },
  { group: '🪟 실내', items: ['거실/리빙', '주방', '욕실/화장실', '발코니/베란다', '현관', '조망/뷰 (창문)', '채광/향 (일조량)', '기타'] },
  { group: '🏙️ 주변 환경', items: ['역세권/교통 접근성', '통학로/학교', '주변 상권', '공원', '소음 환경 (도로)', '어린이집', '유치원', '기타'] },
];

interface ImageUploaderProps {
  photos: PhotoItem[];
  setPhotos: React.Dispatch<React.SetStateAction<PhotoItem[]>>;
  isDragging: boolean;
  setIsDragging: (val: boolean) => void;
  batchInputRef: React.RefObject<HTMLInputElement | null>;
  handleBatchFiles: (files: FileList | File[]) => void;
  sortByCategory: () => void;
  clearPhotos: () => void;
}

export function ImageUploader({
  photos,
  setPhotos,
  isDragging,
  setIsDragging,
  batchInputRef,
  handleBatchFiles,
  sortByCategory,
  clearPhotos,
}: ImageUploaderProps) {
  return (
    <div className="bg-surface rounded-2xl border border-border shadow-sm p-5 md:p-8">
      <h2 className="text-[16px] font-bold text-primary mb-5 border-b border-body pb-3 flex items-center gap-2">
        ③ 현장 사진
        <span className="text-[12px] font-medium text-tertiary ml-auto">{photos.length}장</span>
        {photos.length > 0 && (
          <button type="button" onClick={() => {
            if (confirm(`사진 ${photos.length}장을 전부 삭제합니다. 계속할까요?`)) {
              clearPhotos();
            }
          }} className="px-3 py-1.5 bg-[#ffebec] text-toss-red rounded-lg text-[11px] font-bold hover:bg-toss-red hover:text-surface transition-colors">
            전체 삭제
          </button>
        )}
      </h2>

      {/* Drop Zone */}
      <div
        className={`mb-6 border-2 border-dashed rounded-2xl p-8 text-center transition-all cursor-pointer ${
          isDragging ? 'border-toss-blue bg-toss-blue-light scale-[1.01]' : 'border-toss-gray bg-body hover:bg-body hover:border-toss-blue'
        }`}
        onDragOver={e => { e.preventDefault(); setIsDragging(true); }}
        onDragLeave={() => setIsDragging(false)}
        onDrop={e => { e.preventDefault(); setIsDragging(false); if (e.dataTransfer.files) handleBatchFiles(e.dataTransfer.files); }}
        onClick={() => batchInputRef.current?.click()}
      >
        <input ref={batchInputRef as any} type="file" accept="image/*" multiple className="hidden"
          onChange={e => { if (e.target.files) handleBatchFiles(e.target.files); e.target.value = ''; }} />
        <div className="w-12 h-12 bg-surface rounded-full shadow-sm flex items-center justify-center mx-auto mb-3">
          <ImagePlus size={22} className="text-toss-blue" />
        </div>
        <p className="text-[15px] font-bold text-primary mb-1">
          {isDragging ? '여기에 놓으세요!' : '사진을 한번에 여러 장 추가'}
        </p>
        <p className="text-[12px] text-tertiary">드래그하거나 클릭하여 사진 선택 · EXIF 촬영일 자동 감지</p>
      </div>

      {/* Sort Button */}
      {photos.length >= 2 && (
        <button type="button" onClick={sortByCategory}
          className="mb-4 flex items-center gap-2 px-4 py-2.5 bg-surface border border-border rounded-xl text-[13px] font-bold text-secondary hover:bg-body hover:border-toss-blue hover:text-toss-blue transition-all shadow-sm">
          <ArrowUpDown size={14} /> 카테고리별 자동 정렬 <span className="text-[11px] text-tertiary font-medium">({photos.length}장)</span>
        </button>
      )}

      {/* Photo Cards */}
      <div className="space-y-4">
        {photos.map((photo, index) => (
          <div key={index} className="flex flex-col md:flex-row gap-4 p-4 border border-border rounded-2xl bg-surface shadow-sm hover:border-toss-blue transition-colors group relative">
            {/* Preview */}
            <div className="w-full md:w-[150px] h-[100px] bg-body border-2 border-dashed border-toss-gray rounded-xl overflow-hidden relative shrink-0">
              {(photo.previewUrl || photo.url) ? (
                <>
                  <img src={photo.previewUrl || photo.url} alt="Preview" className="w-full h-full object-cover" />
                  {photo.capturedAt && (
                    <span className="absolute bottom-1 left-1 bg-black/60 text-surface text-[9px] font-bold px-1.5 py-0.5 rounded-md backdrop-blur-sm">
                      {photo.capturedAt}
                    </span>
                  )}
                </>
              ) : (
                <div className="w-full h-full flex items-center justify-center text-tertiary">
                  <ImagePlus size={24} />
                </div>
              )}
            </div>

            {/* Fields */}
            <div className="flex-1 space-y-3">
              <div className="flex gap-3">
                {/* Category Picker — 2-level popover */}
                {(() => {
                  const currentTag = photo.locationTag;
                  const currentGroup = IMAGE_CATEGORY_GROUPS.find(g => g.items.includes(currentTag));
                  return (
                    <div className="relative w-[220px]">
                      <button
                        type="button"
                        onClick={() => {
                          const el = document.getElementById(`cat-popover-${index}`);
                          if (el) el.classList.toggle('hidden');
                        }}
                        className="w-full px-3 py-2 bg-body border border-border rounded-lg text-[13px] font-bold text-left cursor-pointer hover:border-toss-blue focus:ring-2 focus:ring-toss-blue/30 focus:border-toss-blue outline-none transition-colors text-primary flex items-center justify-between"
                      >
                        <span className="truncate">{currentTag || '카테고리 선택'}</span>
                        <svg width="12" height="12" viewBox="0 0 12 12" className="shrink-0 ml-1 text-tertiary"><path d="M3 4.5L6 7.5L9 4.5" stroke="currentColor" strokeWidth="1.5" fill="none" strokeLinecap="round"/></svg>
                      </button>
                      <div
                        id={`cat-popover-${index}`}
                        className="hidden absolute top-full left-0 mt-1 z-50 bg-surface rounded-xl shadow-xl border border-border w-[380px] md:w-[560px] max-h-[280px] overflow-hidden"
                      >
                        {/* Group tabs */}
                        <div className="flex gap-1 p-2 overflow-x-auto border-b border-body bg-[#fafbfc]">
                          {IMAGE_CATEGORY_GROUPS.map((g, gIdx) => (
                            <button
                              key={g.group}
                              type="button"
                              onClick={() => {
                                const container = document.getElementById(`cat-popover-${index}`);
                                if (!container) return;
                                container.querySelectorAll('[data-cat-group]').forEach(el => el.classList.add('hidden'));
                                container.querySelector(`[data-cat-group="${gIdx}"]`)?.classList.remove('hidden');
                                container.querySelectorAll('[data-cat-tab]').forEach(el => {
                                  el.classList.remove('bg-primary', 'text-surface');
                                  el.classList.add('bg-body', 'text-secondary');
                                });
                                container.querySelector(`[data-cat-tab="${gIdx}"]`)?.classList.remove('bg-body', 'text-secondary');
                                container.querySelector(`[data-cat-tab="${gIdx}"]`)?.classList.add('bg-primary', 'text-surface');
                              }}
                              data-cat-tab={gIdx}
                              className={`shrink-0 px-2.5 py-1 rounded-lg text-[11px] font-bold transition-all ${
                                (currentGroup === g || (!currentGroup && gIdx === 0))
                                  ? 'bg-primary text-surface'
                                  : 'bg-body text-secondary hover:bg-[#e5e8eb]'
                              }`}
                            >
                              {g.group.replace(/[^\w가-힣·\s]/g, '').trim()}
                            </button>
                          ))}
                        </div>
                        {/* Items per group */}
                        <div className="p-2 flex flex-col gap-1 overflow-y-auto max-h-[160px]">
                        {IMAGE_CATEGORY_GROUPS.map((g, gIdx) => (
                          <div
                            key={g.group}
                            data-cat-group={gIdx}
                            className={`p-2 flex flex-wrap gap-1.5 max-h-[200px] overflow-y-auto ${
                              (currentGroup === g || (!currentGroup && gIdx === 0)) ? '' : 'hidden'
                            }`}
                          >
                            {g.items.map(item => (
                              <button
                                key={item}
                                type="button"
                                onClick={() => {
                                  const updated = [...photos];
                                  updated[index] = { ...updated[index], locationTag: item };
                                  setPhotos(updated);
                                  document.getElementById(`cat-popover-${index}`)?.classList.add('hidden');
                                }}
                                className={`px-3 py-1.5 rounded-lg text-[12px] font-medium border transition-all ${
                                  currentTag === item
                                    ? 'bg-toss-blue-light text-toss-blue border-toss-blue font-bold'
                                    : 'bg-surface text-secondary border-border hover:bg-body hover:border-toss-blue'
                                }`}
                              >
                                {item}
                              </button>
                            ))}
                          </div>
                        ))}
                        </div>
                      </div>
                    </div>
                  );
                })()}
                <input type="text" value={photo.caption}
                  onChange={e => {
                    const updated = [...photos];
                    updated[index] = { ...updated[index], caption: e.target.value };
                    setPhotos(updated);
                  }}
                  placeholder="캡션 입력 (선택)"
                  className="flex-1 px-3 py-2 bg-body border border-border rounded-lg text-[13px] outline-none focus:border-toss-blue transition-colors" />
              </div>
            </div>

            {/* Delete */}
            <button type="button" onClick={() => setPhotos(prev => prev.filter((_, i) => i !== index))}
              className="absolute top-3 right-3 w-7 h-7 rounded-lg bg-body text-tertiary hover:bg-toss-red hover:text-surface flex items-center justify-center transition-colors opacity-0 group-hover:opacity-100">
              <Trash2 size={13} />
            </button>
          </div>
        ))}
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useFormContext, useWatch, Path } from 'react-hook-form';
import { FormValues } from './types';
import { FALLBACK_DONG_DATA } from './constants';

interface BasicInfoSectionProps {
  lockedMeta?: { dong: string; apartmentName: string };
}

export function BasicInfoSection({ lockedMeta }: BasicInfoSectionProps) {
  const { register, control } = useFormContext<FormValues>();
  
  const [dongData, setDongData] = useState<Record<string, string[]>>(FALLBACK_DONG_DATA);
  const [isLoadingApts, setIsLoadingApts] = useState(false);

  useEffect(() => {
    const fetchApartments = async () => {
      setIsLoadingApts(true);
      try {
        const url = `/api/apartments-by-dong`; 
        const res = await fetch(url);
        if (res.ok) {
          const data = await res.json();
          if (data && Object.keys(data).length > 0) {
            setDongData({ ...FALLBACK_DONG_DATA, ...data });
          }
        }
      } catch (err) {
        console.warn('아파트 목록 API 호출 실패, 기본 데이터 사용:', err);
      } finally {
        setIsLoadingApts(false);
      }
    };
    fetchApartments();
  }, []);

  const selectedDong = useWatch({ control, name: 'dong' }) || Object.keys(dongData)[0];
  const availableApartments = dongData[selectedDong] || [];

  const SelectInput = ({ name, label, options }: { name: string, label: string, options: string[] }) => (
    <div className={label ? "mb-4" : ""}>
      {label && <label className="block text-[14px] font-bold text-secondary mb-2">{label}</label>}
      <select 
        {...register(name as Path<FormValues>, { required: true })}
        className="w-full px-4 py-3 bg-body border border-border rounded-xl text-[15px] focus:ring-2 focus:ring-toss-blue/30 focus:border-toss-blue outline-none transition-all appearance-none cursor-pointer"
      >
        <option value="" disabled>선택하세요</option>
        {options?.map(opt => <option key={opt} value={opt}>{opt}</option>)}
      </select>
    </div>
  );

  return (
    <section className="mb-12">
      <h3 className="text-[18px] font-bold text-primary mb-6 flex items-center gap-2">
        <span className="w-6 h-6 rounded-full bg-body text-secondary flex items-center justify-center text-[12px]">1</span>
        기본 정보
      </h3>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
        {lockedMeta ? (
          <div className="col-span-2 p-4 bg-body border border-border rounded-xl flex gap-3 items-center">
            <span className="text-[13px] font-bold text-tertiary bg-surface border border-border px-2 py-1 rounded shadow-sm">단지 고정됨</span>
            <span className="text-[14px] font-bold text-secondary">{lockedMeta.dong}</span>
            <span className="text-[14px] text-toss-gray">/</span>
            <span className="text-[15px] font-extrabold text-toss-blue">{lockedMeta.apartmentName}</span>
          </div>
        ) : (
          <>
            <div>
              <label className="block text-[14px] font-bold text-secondary mb-2">법정동 선택 <span className="text-toss-red">*</span></label>
              <SelectInput 
                name="dong" 
                label="" 
                options={isLoadingApts ? ['불러오는 중...'] : Object.keys(dongData)} 
              />
            </div>
            <div>
              <label className="block text-[14px] font-bold text-secondary mb-2">물건(아파트) 이름 <span className="text-toss-red">*</span></label>
              {selectedDong === '기타' ? (
                <input 
                  {...register('apartmentName', { required: true })}
                  className="w-full px-4 py-3 bg-body border border-border rounded-xl text-[15px] focus:ring-2 focus:ring-toss-blue/30 focus:border-toss-blue outline-none transition-all placeholder-[#b0b8c1]"
                  placeholder="직접 단지명을 입력하세요"
                />
              ) : (
                <SelectInput 
                  name="apartmentName" 
                  label="" 
                  options={availableApartments} 
                />
              )}
              <p className="text-[12px] text-tertiary font-medium mt-2">* 동을 먼저 선택하면 해당 지역의 주요 아파트 목록이 연동됩니다.</p>
            </div>
          </>
        )}
        <div className="md:col-span-2">
          <label className="block text-[14px] font-bold text-secondary mb-2">현장 방문(촬영) 일자 <span className="text-toss-red">*</span></label>
          <input 
            type="date"
            {...register('scoutingDate', { required: true })}
            className="w-full md:w-1/2 px-4 py-3 bg-body border border-border rounded-xl text-[15px] focus:ring-2 focus:ring-toss-blue/30 focus:border-toss-blue outline-none transition-all text-primary"
          />
          <p className="text-[12px] text-tertiary font-medium mt-2">* 현장 사진 갤러리에 '기준일자'로 자동 표시됩니다.</p>
        </div>
      </div>
    </section>
  );
}

import React, { useRef, useState, useEffect } from 'react';
import { useFormContext, useFieldArray } from 'react-hook-form';
import { ImagePlus, Trash2, ArrowUpDown } from 'lucide-react';
import { FormValues } from './types';
import { IMAGE_CATEGORY_GROUPS, CAPTION_TEMPLATES } from './constants';
import { extractCapturedDate } from '@/lib/utils/exif';

export function ImageUploadSection() {
  const { control, getValues, register } = useFormContext<FormValues>();

  const { fields: imageFields, append: appendImage, remove: removeImage, update: updateImage, replace: replaceImages } = useFieldArray({
    control,
    name: "images"
  });

  const fileInputRefs = useRef<(HTMLInputElement | null)[]>([]);
  const batchInputRef = useRef<HTMLInputElement>(null);
  const uploadedFileKeys = useRef<Set<string>>(new Set());
  const [isDragging, setIsDragging] = useState(false);

  // Auto-populate uploadedFileKeys based on existing images to track duplicates
  useEffect(() => {
    const images = getValues('images') || [];
    for (const img of images) {
      if (img.url) {
        try {
          const decoded = decodeURIComponent(img.url);
          const match = decoded.match(/\/([^/?]+)\?/);
          if (match) uploadedFileKeys.current.add(match[1]);
        } catch { /* ignore */ }
      }
      if (img.file) {
        uploadedFileKeys.current.add(img.file.name);
      }
    }
  }, [getValues, imageFields.length]); // Re-evaluate when field length changes (e.g., initialData load)

  const sortByCategory = () => {
    const currentImages = getValues('images');
    const categoryOrder = IMAGE_CATEGORY_GROUPS.flatMap(g => g.items);
    const sorted = [...currentImages].sort((a, b) => {
      const ai = categoryOrder.indexOf(a.locationTag);
      const bi = categoryOrder.indexOf(b.locationTag);
      return (ai === -1 ? 999 : ai) - (bi === -1 ? 999 : bi);
    });
    replaceImages(sorted);
  };

  const handleImageSelect = async (index: number, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (uploadedFileKeys.current.has(file.name)) {
        alert('이미 업로드된 사진입니다.');
        e.target.value = '';
        return;
      }
      uploadedFileKeys.current.add(file.name);
      const previewUrl = URL.createObjectURL(file);
      const capturedAt = await extractCapturedDate(file) || undefined;
      const currentVal = imageFields[index];
      updateImage(index, { ...currentVal, file, previewUrl, capturedAt });
    }
    e.target.value = '';
  };

  const handleBatchFiles = async (files: FileList | File[]) => {
    const fileArr = Array.from(files).filter(f => f.type.startsWith('image/'));
    if (fileArr.length === 0) return;

    const unique: File[] = [];
    let dupCount = 0;
    for (const f of fileArr) {
      if (uploadedFileKeys.current.has(f.name)) {
        dupCount++;
      } else {
        uploadedFileKeys.current.add(f.name);
        unique.push(f);
      }
    }
    if (dupCount > 0) alert(`중복 사진 ${dupCount}장이 제외되었습니다.`);
    if (unique.length === 0) return;

    const withDates = await Promise.all(
      unique.map(async (file) => {
        const previewUrl = URL.createObjectURL(file);
        const capturedAt = await extractCapturedDate(file) || undefined;
        return { file, previewUrl, url: '', caption: '', locationTag: '', isPremium: false, capturedAt };
      })
    );
    withDates.forEach(item => appendImage(item));
  };

  const handleDropZone = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (e.dataTransfer.files) handleBatchFiles(e.dataTransfer.files);
  };

  return (
    <section className="mb-12">
      <h3 className="text-[18px] font-bold text-primary mb-6 flex items-center gap-2">
        <span className="w-6 h-6 rounded-full bg-body text-secondary flex items-center justify-center text-[12px]">3</span>
        현장 사진 데이터베이스
        <span className="text-[12px] font-medium text-tertiary ml-auto">{imageFields.length}장</span>
        {imageFields.length > 0 && (
          <button
            type="button"
            onClick={() => {
              if (confirm(`사진 ${imageFields.length}장을 전부 삭제합니다. 계속할까요?`)) {
                replaceImages([]);
                uploadedFileKeys.current.clear();
              }
            }}
            className="px-3 py-1.5 bg-[#ffebec] text-toss-red rounded-lg text-[11px] font-bold hover:bg-toss-red hover:text-surface transition-colors"
          >
            전체 삭제
          </button>
        )}
      </h3>

      {/* Batch Drop Zone */}
      <div
        className={`mb-6 border-2 border-dashed rounded-2xl p-8 text-center transition-all cursor-pointer ${
          isDragging
            ? 'border-toss-blue bg-toss-blue-light scale-[1.01]'
            : 'border-toss-gray bg-body hover:bg-body hover:border-toss-blue'
        }`}
        onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
        onDragLeave={() => setIsDragging(false)}
        onDrop={handleDropZone}
        onClick={() => batchInputRef.current?.click()}
      >
        <input ref={batchInputRef} type="file" accept="image/*" multiple className="hidden" onChange={(e) => { if (e.target.files) handleBatchFiles(e.target.files); e.target.value = ''; }} />
        <div className="w-12 h-12 bg-surface rounded-full shadow-sm flex items-center justify-center mx-auto mb-3">
          <ImagePlus size={22} className="text-toss-blue" />
        </div>
        <p className="text-[15px] font-bold text-primary mb-1">
          {isDragging ? '여기에 놓으세요!' : '사진을 한번에 여러 장 추가'}
        </p>
        <p className="text-[12px] text-tertiary">드래그하거나 클릭하여 여러 사진을 선택한 후 카테고리를 직접 지정해주세요</p>
      </div>

      {/* Sort Button */}
      {imageFields.length >= 2 && (
        <button
          type="button"
          onClick={sortByCategory}
          className="mb-4 flex items-center gap-2 px-4 py-2.5 bg-surface border border-border rounded-xl text-[13px] font-bold text-secondary hover:bg-body hover:border-toss-blue hover:text-toss-blue transition-all shadow-sm"
        >
          <ArrowUpDown size={14} />
          카테고리별 자동 정렬
          <span className="text-[11px] text-tertiary font-medium">({imageFields.length}장)</span>
        </button>
      )}

      <div className="space-y-4 mb-6">
        {imageFields.map((field, index) => (
          <div key={field.id} className="flex flex-col md:flex-row gap-4 p-4 border border-border rounded-2xl bg-surface shadow-sm hover:border-toss-blue transition-colors group relative">

            <input 
              type="file" 
              accept="image/*"
              className="hidden"
              ref={(el) => {
                fileInputRefs.current[index] = el;
              }}
              onChange={(e) => handleImageSelect(index, e)}
            />

            <div 
              className="w-full md:w-[150px] h-[100px] bg-body border-2 border-dashed border-toss-gray rounded-xl flex flex-col items-center justify-center text-tertiary cursor-pointer hover:bg-body hover:text-toss-blue transition-colors overflow-hidden group/img relative"
              onClick={() => fileInputRefs.current[index]?.click()}
            >
              {(field.previewUrl || field.url) ? (
                <>
                  <img src={field.previewUrl || field.url} alt="Preview" className="w-full h-full object-cover" />
                  {field.capturedAt && (
                    <span className="absolute bottom-1 left-1 bg-black/60 text-surface text-[9px] font-bold px-1.5 py-0.5 rounded-md backdrop-blur-sm">
                      {field.capturedAt}
                    </span>
                  )}
                  <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover/img:opacity-100 transition-opacity">
                    <span className="text-surface text-[11px] font-bold">변경하기</span>
                  </div>
                </>
              ) : (
                <>
                  <ImagePlus size={24} className="mb-1" />
                  <span className="text-[11px] font-semibold">이미지 추가</span>
                </>
              )}
            </div>

            <div className="flex-1 space-y-3">
              <div className="flex gap-3">
                {/* Category Picker */}
                {(() => {
                  const currentTag = field.locationTag;
                  const currentGroup = IMAGE_CATEGORY_GROUPS.find(g => g.items.includes(currentTag));
                  return (
                    <div className="relative w-[220px]">
                      <button
                        type="button"
                        onClick={() => {
                          const el = document.getElementById(`cat-popover-${index}`);
                          if (el) el.classList.toggle('hidden');
                        }}
                        className="w-full px-3 py-2 bg-body border border-border rounded-lg text-[13px] font-bold text-left cursor-pointer hover:border-toss-blue focus:ring-2 focus:ring-toss-blue/30 focus:border-toss-blue outline-none transition-colors text-primary flex items-center justify-between"
                      >
                        <span className="truncate">{currentTag || '카테고리 선택'}</span>
                        <svg width="12" height="12" viewBox="0 0 12 12" className="shrink-0 ml-1 text-tertiary"><path d="M3 4.5L6 7.5L9 4.5" stroke="currentColor" strokeWidth="1.5" fill="none" strokeLinecap="round"/></svg>
                      </button>
                      <div
                        id={`cat-popover-${index}`}
                        className="hidden absolute top-full left-0 mt-1 z-50 bg-surface rounded-xl shadow-xl border border-border w-[380px] md:w-[560px] max-h-[280px] overflow-hidden"
                      >
                        {/* Group tabs */}
                        <div className="flex gap-1 p-2 overflow-x-auto border-b border-body bg-[#fafbfc]">
                          {IMAGE_CATEGORY_GROUPS.map((g, gIdx) => (
                            <button
                              key={g.group}
                              type="button"
                              onClick={() => {
                                const container = document.getElementById(`cat-popover-${index}`);
                                if (!container) return;
                                container.querySelectorAll('[data-cat-group]').forEach(el => el.classList.add('hidden'));
                                container.querySelector(`[data-cat-group="${gIdx}"]`)?.classList.remove('hidden');
                                container.querySelectorAll('[data-cat-tab]').forEach(el => {
                                  el.classList.remove('bg-primary', 'text-surface');
                                  el.classList.add('bg-body', 'text-secondary');
                                });
                                container.querySelector(`[data-cat-tab="${gIdx}"]`)?.classList.remove('bg-body', 'text-secondary');
                                container.querySelector(`[data-cat-tab="${gIdx}"]`)?.classList.add('bg-primary', 'text-surface');
                              }}
                              data-cat-tab={gIdx}
                              className={`shrink-0 px-2.5 py-1 rounded-lg text-[11px] font-bold transition-all ${
                                (currentGroup === g || (!currentGroup && gIdx === 0))
                                  ? 'bg-primary text-surface'
                                  : 'bg-body text-secondary hover:bg-[#e5e8eb]'
                              }`}
                            >
                              {g.group.replace(/[^\w가-힣·\s]/g, '').trim()}
                            </button>
                          ))}
                        </div>
                        {/* Items */}
                        {IMAGE_CATEGORY_GROUPS.map((g, gIdx) => (
                          <div
                            key={g.group}
                            data-cat-group={gIdx}
                            className={`p-2 flex flex-wrap gap-1.5 max-h-[200px] overflow-y-auto ${
                              (currentGroup === g || (!currentGroup && gIdx === 0)) ? '' : 'hidden'
                            }`}
                          >
                            {g.items.map(item => (
                              <button
                                key={item}
                                type="button"
                                onClick={() => {
                                  const currentVal = imageFields[index];
                                  updateImage(index, { ...currentVal, locationTag: item });
                                  document.getElementById(`cat-popover-${index}`)?.classList.add('hidden');
                                }}
                                className={`px-3 py-1.5 rounded-lg text-[12px] font-medium border transition-all ${
                                  currentTag === item
                                    ? 'bg-toss-blue-light text-toss-blue border-toss-blue font-bold'
                                    : 'bg-surface text-secondary border-border hover:bg-body hover:border-toss-blue'
                                }`}
                              >
                                {item}
                              </button>
                            ))}
                          </div>
                        ))}
                      </div>
                    </div>
                  );
                })()}
                <input
                  {...register(`images.${index}.caption` as const)}
                  className="flex-1 px-3 py-2 bg-body border border-border rounded-lg text-[13px] focus:ring-2 focus:ring-toss-blue/30 focus:border-toss-blue outline-none placeholder-[#b0b8c1]"
                  placeholder={CAPTION_TEMPLATES[field.locationTag]?.[0] || '사진 설명 캡션을 입력하세요'}
                />
              </div>
              {/* Caption Template Chips */}
              {CAPTION_TEMPLATES[field.locationTag] && (
                <div className="flex flex-wrap gap-1.5">
                  {CAPTION_TEMPLATES[field.locationTag].map((tmpl, tIdx) => (
                    <button
                      key={tIdx}
                      type="button"
                      onClick={() => {
                        const currentVal = imageFields[index];
                        updateImage(index, { ...currentVal, caption: tmpl });
                      }}
                      className="px-2.5 py-1 bg-body hover:bg-toss-blue-light hover:text-toss-blue border border-border hover:border-toss-blue rounded-lg text-[11px] text-secondary font-medium transition-all truncate max-w-[240px]"
                      title={tmpl}
                    >
                      📝 {tmpl}
                    </button>
                  ))}
                </div>
              )}
              <div className="flex items-center gap-3 w-full">
                <label className="flex items-center gap-2 cursor-pointer">
                  <input type="checkbox" {...register(`images.${index}.isPremium` as const)} className="w-4 h-4 rounded text-toss-blue focus:ring-toss-blue border-toss-gray" />
                  <span className="text-[13px] font-semibold text-secondary">유료(프리미엄) 멤버 전용 숨김 처리</span>
                </label>
                
                <button 
                  type="button" 
                  onClick={() => removeImage(index)}
                  className="ml-auto text-tertiary hover:text-toss-red p-2 rounded-lg transition-colors"
                >
                  <Trash2 size={16} />
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>

      <button 
        type="button" 
        onClick={() => appendImage({ url: '', caption: '', locationTag: '', isPremium: false })}
        className="w-full py-4 border-2 border-dashed border-toss-gray rounded-2xl text-secondary font-bold text-[14px] hover:bg-body hover:text-toss-blue hover:border-toss-blue transition-all flex items-center justify-center gap-2"
      >
        <ImagePlus size={18} /> 사진 블록(Block) 추가
      </button>
    </section>
  );
}

import React, { useRef } from 'react';
import { ImagePlus } from 'lucide-react';

interface ThumbnailSectionProps {
  thumbnailPreview: string;
  setThumbnailPreview: (url: string) => void;
  setThumbnailFile: (file: File | null) => void;
}

export function ThumbnailSection({
  thumbnailPreview,
  setThumbnailPreview,
  setThumbnailFile
}: ThumbnailSectionProps) {
  const thumbnailInputRef = useRef<HTMLInputElement>(null);

  return (
    <section className="mb-12">
      <h3 className="text-[18px] font-bold text-primary mb-4 flex items-center gap-2">
        <span className="w-6 h-6 rounded-full bg-body text-secondary flex items-center justify-center text-[12px]">📷</span>
        대표 썸네일
      </h3>
      <div className="flex items-start gap-5">
        <input
          ref={thumbnailInputRef}
          type="file"
          accept="image/*"
          className="hidden"
          onChange={(e) => {
            const file = e.target.files?.[0];
            if (file) {
              setThumbnailFile(file);
              setThumbnailPreview(URL.createObjectURL(file));
            }
            e.target.value = '';
          }}
        />
        <div
          onClick={() => thumbnailInputRef.current?.click()}
          className="w-[200px] h-[130px] bg-body border-2 border-dashed border-toss-gray rounded-2xl flex flex-col items-center justify-center text-tertiary cursor-pointer hover:bg-body hover:text-toss-blue transition-colors overflow-hidden group relative shrink-0"
        >
          {thumbnailPreview ? (
            <>
              <img src={thumbnailPreview} alt="Thumbnail" className="w-full h-full object-cover" />
              <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                <span className="text-surface text-[11px] font-bold">변경하기</span>
              </div>
            </>
          ) : (
            <>
              <ImagePlus size={28} className="mb-1" />
              <span className="text-[12px] font-semibold">썸네일 등록</span>
            </>
          )}
        </div>
        <div className="flex-1">
          <p className="text-[13px] text-secondary font-medium mb-2">
            메인 피드에 표시될 대표 이미지입니다.
          </p>
          <p className="text-[12px] text-tertiary">
            미등록 시 첫 번째 현장 사진이 자동 적용됩니다.
          </p>
          {thumbnailPreview && (
            <button
              type="button"
              onClick={() => { setThumbnailFile(null); setThumbnailPreview(''); }}
              className="mt-3 text-[12px] text-toss-red font-bold hover:underline"
            >
              썸네일 삭제
            </button>
          )}
        </div>
      </div>
    </section>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { X, Upload, Image as ImageIcon, Camera, Loader2, CheckCircle2 } from 'lucide-react';
import { db } from '@/lib/firebaseConfig';
import { collection, addDoc, serverTimestamp } from 'firebase/firestore';
import { uploadImage } from '@/lib/services/reportService';
import Image from 'next/image';
import type { User } from 'firebase/auth';
import { auth, googleProvider } from '@/lib/firebaseConfig';
import { signInWithPopup } from 'firebase/auth';

interface PhotoUploadModalProps {
  isOpen: boolean;
  onClose: () => void;
  apartmentId: string;
  apartmentName: string;
  user: User | null;
}

const CATEGORIES = [
  { id: 'gateImg', label: '정문' },
  { id: 'landscapeImg', label: '조경' },
  { id: 'parkingImg', label: '주차장' },
  { id: 'maintenanceImg', label: '공용부' },
  { id: 'communityImg', label: '커뮤니티' },
  { id: 'schoolImg', label: '통학로' },
  { id: 'commerceImg', label: '상권' },
  { id: '기타', label: '기타' },
];

export function PhotoUploadModal({ isOpen, onClose, apartmentId, apartmentName, user }: PhotoUploadModalProps) {
  const [file, setFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [category, setCategory] = useState<string>('gateImg');
  const [caption, setCaption] = useState('');
  const [isUploading, setIsUploading] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [mounted, setMounted] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    setMounted(true);
  }, []);

  if (!isOpen || !mounted) return null;

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selected = e.target.files?.[0];
    if (selected && selected.type.startsWith('image/')) {
      if (selected.size > 10 * 1024 * 1024) {
        alert('이미지 크기는 10MB 이하여야 합니다.');
        return;
      }
      setFile(selected);
      const url = URL.createObjectURL(selected);
      setPreviewUrl(url);
    }
  };

  const handleSubmit = async () => {
    if (!file) return;
    setIsUploading(true);
    
    try {
      // 1. Upload to Storage
      const downloadUrl = await uploadImage(file, 'user_pending_photos');
      
      // 2. Save to Firestore pending queue
      const uploaderName = user?.displayName || user?.email?.split('@')[0] || '익명';
      await addDoc(collection(db, 'pending_photos'), {
        apartmentId,
        apartmentName,
        url: downloadUrl,
        locationTag: CATEGORIES.find(c => c.id === category)?.label || category,
        locationTagId: category,
        caption: caption.trim(),
        status: 'pending',
        createdAt: serverTimestamp(),
        uploaderUid: user?.uid || 'anonymous',
        uploaderEmail: user?.email || 'anonymous',
        uploaderName,
      });
      
      setIsSuccess(true);
      setTimeout(() => {
        onClose();
        setIsSuccess(false);
        setFile(null);
        setPreviewUrl(null);
        setCaption('');
      }, 2000);
      
    } catch (error) {
      console.error('Upload failed:', error);
      alert('업로드 중 오류가 발생했습니다. 다시 시도해 주세요.');
    } finally {
      setIsUploading(false);
    }
  };

  return createPortal(
    <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
      <div 
        className="bg-surface rounded-3xl w-full max-w-md overflow-hidden shadow-2xl flex flex-col max-h-[90vh] animate-in zoom-in-95 duration-200"
        onClick={(e) => e.stopPropagation()}
      >
        {/* Header */}
        <div className="flex items-center justify-between p-5 border-b border-border">
          <h2 className="text-[18px] font-bold text-primary flex items-center gap-2">
            <Camera className="text-toss-blue" size={20} />
            우리 단지 사진 올리기
          </h2>
          <button 
            onClick={onClose}
            className="p-2 -mr-2 text-tertiary hover:bg-body rounded-full transition-colors"
            disabled={isUploading}
          >
            <X size={20} />
          </button>
        </div>

        {/* Content */}
        <div className="p-6 overflow-y-auto custom-scrollbar flex flex-col gap-6">
          {isSuccess ? (
            <div className="flex flex-col items-center justify-center py-10 text-center">
              <div className="w-16 h-16 bg-toss-blue-light text-toss-blue rounded-full flex items-center justify-center mb-4">
                <CheckCircle2 size={32} />
              </div>
              <h3 className="text-[20px] font-bold text-primary mb-2">등록이 완료되었습니다!</h3>
              <p className="text-[15px] text-secondary">관리자 검토 후 단지 갤러리에 반영됩니다.<br/>참여해 주셔서 감사합니다.</p>
            </div>
          ) : !user ? (
            <div className="flex flex-col items-center justify-center py-12 text-center">
              <div className="w-16 h-16 bg-body rounded-full flex items-center justify-center mb-5">
                <Camera size={32} className="text-tertiary" />
              </div>
              <h3 className="text-[18px] font-bold text-primary mb-2">로그인이 필요합니다</h3>
              <p className="text-[14px] text-secondary mb-6">
                단지 사진을 등록하려면<br />구글 로그인을 먼저 진행해 주세요.
              </p>
              <button
                onClick={() => signInWithPopup(auth, googleProvider)}
                className="flex items-center gap-2 bg-surface border border-border shadow-sm text-primary font-bold px-6 py-3 rounded-xl hover:bg-body transition-colors"
              >
                <img src="https://www.gstatic.com/firebasejs/ui/2.0.0/images/auth/google.svg" alt="Google" className="w-5 h-5" />
                구글로 계속하기
              </button>
            </div>
          ) : (
            <>
              {/* Image Upload Area */}
              <div className="flex flex-col gap-2">
                <label className="text-[14px] font-bold text-secondary">사진 등록 (필수)</label>
                <div 
                  className={`w-full aspect-video rounded-2xl border-2 border-dashed flex flex-col items-center justify-center cursor-pointer transition-colors relative overflow-hidden
                    ${previewUrl ? 'border-transparent bg-black' : 'border-border bg-body hover:bg-surface'}`}
                  onClick={() => fileInputRef.current?.click()}
                >
                  {previewUrl ? (
                    <>
                      <Image src={previewUrl} alt="Preview" fill className="object-contain" />
                      <div className="absolute inset-0 bg-black/40 opacity-0 hover:opacity-100 transition-opacity flex items-center justify-center">
                        <span className="text-white font-bold flex items-center gap-2 bg-black/50 px-4 py-2 rounded-full">
                          <Upload size={16} /> 변경하기
                        </span>
                      </div>
                    </>
                  ) : (
                    <div className="flex flex-col items-center gap-3 text-tertiary p-6 text-center">
                      <div className="w-12 h-12 bg-surface rounded-full shadow-sm flex items-center justify-center">
                        <ImageIcon size={24} className="text-toss-blue" />
                      </div>
                      <p className="text-[14px] font-medium">여기를 눌러 사진을 선택하세요<br/><span className="text-[12px] text-tertiary">(최대 10MB)</span></p>
                    </div>
                  )}
                  <input 
                    type="file" 
                    accept="image/*" 
                    className="hidden" 
                    ref={fileInputRef}
                    onChange={handleFileChange}
                  />
                </div>
              </div>

              {/* Category */}
              <div className="flex flex-col gap-2">
                <label className="text-[14px] font-bold text-secondary">카테고리 (필수)</label>
                <div className="grid grid-cols-4 gap-2">
                  {CATEGORIES.map(cat => (
                    <button
                      key={cat.id}
                      onClick={() => setCategory(cat.id)}
                      className={`py-2 px-1 text-[13px] font-bold rounded-xl transition-colors
                        ${category === cat.id 
                          ? 'bg-toss-blue-light text-toss-blue border border-toss-blue/20' 
                          : 'bg-body text-secondary border border-transparent hover:bg-surface'}`}
                    >
                      {cat.label}
                    </button>
                  ))}
                </div>
              </div>

              {/* Caption */}
              <div className="flex flex-col gap-2">
                <label className="text-[14px] font-bold text-secondary">간단한 설명 (선택)</label>
                <textarea
                  placeholder="예: 단지 내 메인 산책로 야경입니다."
                  value={caption}
                  onChange={(e) => setCaption(e.target.value)}
                  className="w-full bg-body border-none rounded-xl p-4 text-[15px] text-primary placeholder:text-tertiary focus:ring-2 focus:ring-toss-blue/30 focus:bg-surface transition-all resize-none h-24"
                  maxLength={100}
                />
                <div className="text-right text-[12px] text-tertiary font-medium">
                  {caption.length}/100
                </div>
              </div>
            </>
          )}
        </div>

        {/* Footer */}
        {(!isSuccess && user) && (
          <div className="p-5 border-t border-border bg-surface">
            <button
              onClick={handleSubmit}
              disabled={!file || isUploading}
              className={`w-full py-4 rounded-xl text-[16px] font-bold flex items-center justify-center gap-2 transition-all
                ${(!file || isUploading) ? 'bg-body text-tertiary cursor-not-allowed' : 'bg-toss-blue text-white hover:opacity-90 shadow-[0_4px_12px_rgba(49,130,246,0.2)]'}`}
            >
              {isUploading ? (
                <>
                  <Loader2 size={20} className="animate-spin" />
                  업로드 중...
                </>
              ) : (
                '사진 등록하기'
              )}
            </button>
          </div>
        )}
      </div>
    </div>,
    document.getElementById('modal-root') || document.body
  );
}

import React, { useState } from 'react';
import { MapPin, TrendingUp } from 'lucide-react';
import {
  ResponsiveContainer,
  ComposedChart,
  CartesianGrid,
  XAxis,
  YAxis,
  Tooltip as RechartsTooltip,
  Bar,
  Line,
  Customized
} from 'recharts';
import { TransactionRecord } from './TransactionTable';

interface TransactionChartSectionProps {
  transactions: TransactionRecord[];
  chartType: 'sale' | 'jeonse';
  setChartType: (type: 'sale' | 'jeonse') => void;
  displayAptName: string;
  dong: string;
  typeMap: Record<string, Record<string, { typeM2: string; typePyeong: string }>>;
  areaUnit: 'm2' | 'pyeong';
  normalizeAptName: (name: string) => string;
  txSummary?: any;
}

export function TransactionChartSection({
  transactions,
  chartType,
  setChartType,
  displayAptName,
  dong,
  typeMap,
  areaUnit,
  normalizeAptName,
  txSummary
}: TransactionChartSectionProps) {
  type ScatterData = {
    ts: number; yearMonth: number; contractDay: number; price: number; area: number;
    rawArea: number; floor: number; priceEok: string; dealType: string; fullDate: string; isOutlier: boolean;
  };

  const [chartTimeframe, setChartTimeframe] = useState<'6M' | '1Y' | '3Y' | 'ALL'>('ALL');
  const [hoveredDot, setHoveredDot] = useState<{ x: number; y: number; data: ScatterData } | null>(null);

  const relevantTxs = transactions.filter(tx => 
    chartType === 'sale' 
      ? (tx.dealType !== '전세' && tx.dealType !== '월세') 
      : (tx.dealType === '전세' || tx.dealType === '월세')
  );

  if (relevantTxs.length === 0) {
    return (
      <div className="w-full md:w-[60%] flex flex-col order-1 md:order-2">
        <div className="flex items-center justify-between mb-3 w-full">
          <div className="flex items-center gap-2">
            <span className="bg-body text-secondary text-sm font-bold px-3 py-1 rounded-full">{dong || '동탄'}</span>
          </div>
          <div className="bg-body p-0.5 rounded-xl flex items-center shadow-inner">
            <button onClick={() => setChartType('sale')} className={`px-4 py-1 rounded-lg text-[13px] font-bold transition-all ${chartType === 'sale' ? 'bg-surface text-primary shadow-[0_1px_3px_rgba(0,0,0,0.1)]' : 'text-tertiary hover:text-secondary'}`}>매매</button>
            <button onClick={() => setChartType('jeonse')} className={`px-4 py-1 rounded-lg text-[13px] font-bold transition-all ${chartType === 'jeonse' ? 'bg-surface text-primary shadow-[0_1px_3px_rgba(0,0,0,0.1)]' : 'text-tertiary hover:text-secondary'}`}>전월세</button>
          </div>
        </div>
        <h1 className="text-2xl sm:text-3xl md:text-4xl font-extrabold leading-tight tracking-tight mb-2 text-primary flex items-center gap-2 w-full min-w-0">
          <span className="truncate">{displayAptName}</span>
        </h1>
        <div className="bg-body rounded-2xl p-8 flex flex-col items-center justify-center ring-1 ring-black/5 mt-4 min-h-[300px]">
          <span className="text-[40px] mb-2">🤫</span>
          <span className="text-tertiary text-[15px] font-extrabold tracking-tight">현재 숨고르기 중인 단지입니다</span>
          <span className="text-tertiary text-[12px] font-medium mt-1">해당 기간 내 실거래 기록이 없습니다</span>
        </div>
      </div>
    );
  }

  const rawData = relevantTxs.map((tx) => {
    let rawPrice = tx.price;
    if (chartType === 'jeonse') {
      rawPrice = (tx.deposit || 0) + Math.round((tx.monthlyRent || 0) * 12 / 0.055);
    }

    let priceEokNum = rawPrice / 10000;
    if (priceEokNum > 100) priceEokNum = rawPrice / 100000000;
    const ym = tx.contractYm;
    const year = parseInt(ym.slice(0, 4));
    const month = parseInt(ym.slice(4));
    const day = parseInt(tx.contractDay) || 15;
    return {
      ts: new Date(year, month - 1, day).getTime(),
      yearMonth: parseInt(ym), contractDay: day,
      price: Math.round(priceEokNum * 1000) / 1000,
      area: tx.areaPyeong, rawArea: tx.area,
      floor: tx.floor, priceEok: tx.priceEok || `${priceEokNum >= 1 ? Math.floor(priceEokNum)+'억' : ''}${Math.round((priceEokNum%1)*10000)||''}`,
      dealType: tx.dealType,
      fullDate: `${year}.${String(month).padStart(2,'0')}.${String(day).padStart(2,'0')}`,
    };
  });

  const now = new Date();
  const cutoffMap: Record<string, number> = { '6M': 6, '1Y': 12, '3Y': 36, 'ALL': 9999 };
  const monthsCut = cutoffMap[chartTimeframe];
  const cutoffDate = new Date(now.getFullYear(), now.getMonth() - monthsCut, 1);
  const cutoffYm = cutoffDate.getFullYear() * 100 + (cutoffDate.getMonth() + 1);
  const timeFiltered = rawData.filter(d => d.yearMonth >= cutoffYm);

  const sortedPrices = [...timeFiltered].sort((a, b) => a.price - b.price);
  const q1 = sortedPrices[Math.floor(sortedPrices.length * 0.05)]?.price || 0;
  const q3 = sortedPrices[Math.floor(sortedPrices.length * 0.95)]?.price || 10;
  const iqr = q3 - q1;
  const bandLow = q1;
  const bandHigh = q3;
  const scatterData = timeFiltered.map(d => ({
    ...d,
    isOutlier: d.price < q1 - iqr * 2 || d.price > q3 + iqr * 2,
  })).filter(d => d.price >= q1 - iqr * 3 && d.price <= q3 + iqr * 3);
  
  const getFloorColor = (floor: number) => '#3182f6';

  const byMonthTier = new Map<number, { all: number[] }>();
  scatterData.forEach(d => {
    if (!byMonthTier.has(d.yearMonth)) byMonthTier.set(d.yearMonth, { all: [] });
    const bucket = byMonthTier.get(d.yearMonth)!;
    bucket.all.push(d.price);
  });
  const avg = (arr: number[]) => arr.length > 0 ? Math.round((arr.reduce((a, b) => a + b, 0) / arr.length) * 1000) / 1000 : undefined;
  const monthlyData = Array.from(byMonthTier.entries())
    .map(([ym, buckets]) => ({
      ts: new Date(Math.floor(ym / 100), (ym % 100) - 1, 15).getTime(),
      monthAvg: avg(buckets.all)!,
      volume: buckets.all.length, ym,
      bandHigh, bandLow,
    }))
    .sort((a, b) => a.ts - b.ts);

  const prices = scatterData.map(d => d.price);
  let minP = Infinity, maxP = -Infinity;
  for (const p of prices) { if (p < minP) minP = p; if (p > maxP) maxP = p; }
  const domainMin = Math.floor(minP * 10) / 10 - 0.3;
  const domainMax = Math.ceil(maxP * 10) / 10 + 0.5;
  const maxVol = Math.max(...monthlyData.map(d => d.volume), 1);

  const getRecentAvgByMonths = (months: number) => {
    const cutoffDate = new Date(now.getFullYear(), now.getMonth() - months, now.getDate());
    const filtered = rawData.filter(d => {
      const y = Math.floor(d.yearMonth / 100);
      const m = d.yearMonth % 100;
      const day = d.contractDay || 1;
      return new Date(y, m - 1, day) >= cutoffDate;
    });
    if (filtered.length === 0) return 0;
    return filtered.reduce((acc, d) => acc + d.price, 0) / filtered.length;
  };

  const momentum = {
    m1: getRecentAvgByMonths(1),
    m3: getRecentAvgByMonths(3),
    m6: getRecentAvgByMonths(6),
    y1: getRecentAvgByMonths(12),
    y3: getRecentAvgByMonths(36)
  };

  const formatAvgPriceEok = (avgPrice: number) => {
    if (!avgPrice) return '-';
    const roundedAvg = Math.round(avgPrice * 100) / 100;
    const eok = Math.floor(roundedAvg);
    const rem = Math.round((roundedAvg % 1) * 10000);
    return `${eok >= 1 ? `${eok}억` : ''}${rem > 0 ? rem.toLocaleString() : (eok > 0 ? '' : '0')}`;
  };

  return (
    <div className="w-full md:w-[60%] flex flex-col order-1 md:order-2">
      <div className="flex items-center justify-between mb-3 w-full">
        <div className="flex items-center gap-2">
          <span className="bg-body text-secondary text-sm font-bold px-3 py-1 rounded-full">{dong || '동탄'}</span>
        </div>
        <div className="bg-body p-0.5 rounded-xl flex items-center shadow-inner">
          <button onClick={() => setChartType('sale')} className={`px-4 py-1 rounded-lg text-[13px] font-bold transition-all ${chartType === 'sale' ? 'bg-surface text-primary shadow-[0_1px_3px_rgba(0,0,0,0.1)]' : 'text-tertiary hover:text-secondary'}`}>매매</button>
          <button onClick={() => setChartType('jeonse')} className={`px-4 py-1 rounded-lg text-[13px] font-bold transition-all ${chartType === 'jeonse' ? 'bg-surface text-primary shadow-[0_1px_3px_rgba(0,0,0,0.1)]' : 'text-tertiary hover:text-secondary'}`}>전월세</button>
        </div>
      </div>
      <h1 className="text-2xl sm:text-3xl md:text-4xl font-extrabold leading-tight tracking-tight mb-2 text-primary flex items-center gap-2 w-full min-w-0">
        <span className="truncate">{displayAptName}</span>
        <a 
          href={`https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(displayAptName + (displayAptName.includes('아파트') ? '' : ' 아파트'))}`}
          target="_blank" rel="noopener noreferrer"
          className="text-toss-blue hover:bg-toss-blue-light p-1.5 md:p-2 rounded-full transition-colors group flex shrink-0 items-center justify-center -ml-1 md:ml-0"
          title="구글 지도에서 아파트 위치 보기"
        >
          <MapPin className="w-6 h-6 md:w-8 md:h-8 group-hover:scale-110 transition-transform" />
        </a>
      </h1>

      <div className="mt-4 bg-surface rounded-2xl p-5 ring-1 ring-black/5 flex-1">
        <div className="flex flex-col md:flex-row md:items-center justify-between mb-3 w-full gap-3">
          <div className="flex flex-col gap-2 w-full md:w-1/2">
            <h4 className="text-[14px] font-extrabold text-primary flex items-center gap-1.5 shrink-0">
              <TrendingUp size={15} className="text-toss-blue" /> {chartType === 'sale' ? '매매가 추이' : '전월세 추이'}
            </h4>
            
            {/* 최고 평균가 대비 현재 평균가 게이지 바 */}
            {(() => {
              if (prices.length > 0) {
                const maxPrice = monthlyData.length > 0 ? Math.max(...monthlyData.map(d => d.monthAvg).filter(Boolean)) : Math.max(...prices);
                const currentPrice = momentum.m1 || prices[0];
                if (maxPrice > 0 && currentPrice > 0) {
                  const dropRatio = ((maxPrice - currentPrice) / maxPrice) * 100;
                  const ratio = Math.max(0, Math.min(100, (currentPrice / maxPrice) * 100));
                  return (
                    <div className="flex flex-col gap-1 mt-1">
                      <div className="flex justify-between text-[11px] font-bold">
                        <span className="text-tertiary">최고 평균가 {formatAvgPriceEok(maxPrice)}</span>
                        <span className="text-toss-blue">현재 {formatAvgPriceEok(currentPrice)} ({dropRatio > 0 ? `-${dropRatio.toFixed(1)}%` : `+${Math.abs(dropRatio).toFixed(1)}%`})</span>
                      </div>
                      <div className="w-full h-1.5 bg-body rounded-full overflow-hidden">
                        <div 
                          className="h-full bg-gradient-to-r from-[#3182f6] to-[#1b64da] rounded-full transition-all duration-1000" 
                          style={{ width: `${ratio}%` }} 
                        />
                      </div>
                    </div>
                  );
                }
              }
              return null;
            })()}
          </div>
          
          <div className="flex items-center gap-3 md:ml-auto">
            <div className="flex items-center gap-0.5 bg-body p-0.5 rounded-lg shadow-inner">
              {(['6M','1Y','3Y','ALL'] as const).map(tf => (
                <button key={tf} onClick={() => setChartTimeframe(tf)}
                  className={`px-2 py-1 rounded-md text-[11px] font-bold transition-all ${
                    chartTimeframe === tf ? 'bg-surface text-primary shadow-sm' : 'text-tertiary hover:bg-[#e5e8eb]'
                  }`}>{tf}</button>
              ))}
            </div>
          </div>
        </div>
        
        <div className="flex w-full divide-x divide-[#e5e8eb] mb-5 bg-body py-3 rounded-xl border border-border overflow-x-auto scrollbar-hide [-ms-overflow-style:none] [scrollbar-width:none] [&::-webkit-scrollbar]:hidden snap-x">
          {[{label: '1개월 평균', val: momentum.m1}, {label: '3개월 평균', val: momentum.m3}, {label: '6개월 평균', val: momentum.m6}, {label: '1년 평균', val: momentum.y1}, {label: '3년 평균', val: momentum.y3}].map((item, idx) => (
            <div key={item.label} className={`flex flex-col items-center px-3 sm:px-5 shrink-0 min-w-[76px] sm:min-w-[85px] flex-1 snap-center ${idx === 4 ? 'border-r-0' : ''}`}>
              <span className="text-[10px] sm:text-[11px] font-bold text-tertiary mb-0.5 whitespace-nowrap">{item.label}</span>
              <span className={`text-[13px] sm:text-[16px] font-bold sm:font-extrabold ${idx < 2 ? 'text-primary' : 'text-secondary'} whitespace-nowrap`}>{formatAvgPriceEok(item.val)}</span>
            </div>
          ))}
        </div>
        
        <div className="h-[300px] relative">
          <ResponsiveContainer width="100%" height="100%" minWidth={1} minHeight={1}>
            <ComposedChart data={monthlyData} margin={{ top: 10, right: 10, left: 0, bottom: 5 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="#f2f4f6" vertical={false} />
              <XAxis dataKey="ts" type="number" scale="time" domain={['dataMin', 'dataMax']}
                tick={{ fill: '#8b95a1', fontSize: 10, fontWeight: 600 }} axisLine={{ stroke: '#e5e8eb' }}
                tickLine={false} tickMargin={6}
                tickFormatter={(ts: number) => { const d = new Date(ts); return `${String(d.getFullYear()).slice(2)}.${String(d.getMonth()+1).padStart(2,'0')}`; }}
              />
              <YAxis yAxisId="price" orientation="left" domain={[Math.max(0, domainMin), domainMax]}
                tick={{ fill: '#8b95a1', fontSize: 10, fontWeight: 600 }} axisLine={false} tickLine={false}
                width={48} dx={-3}
                tickFormatter={(v: number) => v >= 1 ? `${v.toFixed(1)}억` : `${Math.round(v * 10000)}만`}
              />
              <YAxis yAxisId="volume" orientation="right" domain={[0, maxVol * 4]}
                tick={false} axisLine={false} tickLine={false} width={0}
              />
              <RechartsTooltip
                content={({ active, payload }) => {
                  if (!active || !payload?.length) return null;
                  const item = payload[0]?.payload;
                  const vol = item?.volume;
                  return (
                    <div style={{ background: '#ffffff', borderRadius: 10, padding: '8px 12px', boxShadow: '0 8px 24px rgba(0,0,0,0.12)', border: '1px solid #f2f4f6' }}>
                      <div style={{ color: '#8b95a1', fontSize: 11, marginBottom: 4 }}>
                        {new Date(item?.ts).getFullYear()}.{String(new Date(item?.ts).getMonth()+1).padStart(2,'0')}월
                      </div>
                      {item?.monthAvg && <div style={{ color: '#191f28', fontSize: 12, fontWeight: 700 }}>평균 {item.monthAvg.toFixed(2)}억</div>}
                      {vol != null && <div style={{ color: '#8b95a1', fontSize: 11, marginTop: 2 }}>거래 {vol}건</div>}
                    </div>
                  );
                }}
                cursor={{ stroke: '#d1d6db', strokeWidth: 1, strokeDasharray: '3 3' }}
              />
              <Bar dataKey="volume" yAxisId="volume" fill="#e5e8eb" radius={[2, 2, 0, 0]} maxBarSize={12} opacity={0.6} isAnimationActive={false} />
              <Line type="monotone" dataKey="monthAvg" yAxisId="price" stroke="#3182f6" strokeWidth={2} dot={false} activeDot={false} connectNulls isAnimationActive={false} />
              <Customized
                component={(rechartProps: Record<string, unknown>) => {
                  const { xAxisMap, yAxisMap } = rechartProps as { xAxisMap?: Record<string, { scale?: (val: number) => number }>; yAxisMap?: Record<string, { scale?: (val: number) => number }> };
                  if (!xAxisMap || !yAxisMap) return null;
                  const xAx = Object.values(xAxisMap)[0];
                  const yAx = Object.values(yAxisMap)[0];
                  if (!xAx?.scale || !yAx?.scale) return null;
                  return (
                    <g>
                      {scatterData.map((d, i) => {
                        const cx = xAx.scale ? xAx.scale(d.ts) : 0;
                        const cy = yAx.scale ? yAx.scale(d.price) : 0;
                        if (!Number.isFinite(cx) || !Number.isFinite(cy)) return null;
                        const isHov = hoveredDot?.data === d;
                        const floorColor = getFloorColor(d.floor);
                        return (
                          <circle key={i} cx={cx} cy={cy}
                            r={isHov ? 5 : 3} fill={floorColor}
                            opacity={d.isOutlier ? 0.1 : (isHov ? 1 : 0.35)}
                            stroke={isHov ? '#fbbf24' : 'none'}
                            strokeWidth={isHov ? 2 : 0}
                            style={{ cursor: 'pointer', transition: 'r 0.15s, opacity 0.15s' }}
                            onMouseEnter={() => setHoveredDot({ x: cx, y: cy, data: { ...d, dealType: d.dealType || '' } })}
                            onMouseLeave={() => setHoveredDot(null)}
                          />
                        );
                      })}
                    </g>
                  );
                }}
              />
            </ComposedChart>
          </ResponsiveContainer>
          {hoveredDot && (() => {
            const d = hoveredDot.data;
            const aptKey = normalizeAptName(displayAptName);
            const typeData = typeMap[aptKey]?.[String(d.rawArea)];
            const typeName = typeData ? (areaUnit === 'm2' ? typeData.typeM2 : (typeData.typePyeong || typeData.typeM2)) : undefined;
            return (
              <div style={{
                position: 'absolute', left: hoveredDot.x + 48, top: hoveredDot.y + 10,
                transform: 'translate(-50%, -100%) translateY(-12px)',
                background: '#ffffff', borderRadius: 10, padding: '10px 14px', border: '1px solid #f2f4f6',
                boxShadow: '0 8px 24px rgba(0,0,0,0.12)',
                pointerEvents: 'none', zIndex: 10, whiteSpace: 'nowrap',
              }}>
                <div style={{ color: '#8b95a1', fontSize: 11, marginBottom: 4 }}>{d.fullDate}</div>
                <div style={{ color: '#191f28', fontSize: 16, fontWeight: 800, marginBottom: 3 }}>
                  {d.priceEok || `${d.price.toFixed(2)}억`}
                </div>
                <div style={{ color: '#8b95a1', fontSize: 11, display: 'flex', gap: 6, alignItems: 'center' }}>
                  {typeName ? <span style={{ color: '#3182f6', fontWeight: 600 }}>{typeName}</span> : <span>{areaUnit === 'm2' ? `${d.rawArea}m²` : `${d.area}평`}</span>}
                  <span>·</span><span style={{ color: getFloorColor(d.floor) }}>{d.floor}층</span>
                  {d.dealType && <><span>·</span><span>{d.dealType}</span></>}
                </div>
              </div>
            );
          })()}
        </div>
        <div className="flex flex-wrap items-center justify-end gap-x-4 gap-y-2 mt-2 px-1 text-[12px] sm:text-[13px] font-bold text-tertiary">
          <span className="flex items-center gap-1.5 whitespace-nowrap"><span className="w-5 sm:w-6 h-[1.5px] bg-toss-blue rounded"/>평균가</span>
          <span className="flex items-center gap-1.5 whitespace-nowrap"><span className="w-3.5 h-3.5 bg-[#e5e8eb] rounded-sm"/>거래량</span>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useMemo } from 'react';
import { normalizeAptName } from '@/lib/utils/apartmentMapping';

interface TransactionRecord {
  dong: string;
  aptName: string;
  area: number;
  areaPyeong: number;
  contractYm: string;
  contractDay: string;
  price: number;
  priceEok: string;
  deposit?: number;
  monthlyRent?: number;
  floor: number;
  buildYear: number;
  dealType: string;
  reqGb?: string;
  rnuYn?: string;
}

interface TransactionSummaryMetricsProps {
  transactions: TransactionRecord[];
  apartmentName: string;
  typeMap: Record<string, Record<string, { typeM2: string; typePyeong: string }>>;
  areaUnit: 'm2' | 'pyeong';
}

export function TransactionSummaryMetrics({ transactions, apartmentName, typeMap, areaUnit }: TransactionSummaryMetricsProps) {
  const [priceTypeFilter, setPriceTypeFilter] = useState<string>('ALL');
  const [showPriceHelp, setShowPriceHelp] = useState(false);
  const [periodDealType, setPeriodDealType] = useState<'sale' | 'jeonse'>('sale');

  const { typeFilters, periodData } = useMemo(() => {
    const now = new Date();
    
    // 1) 타입 필터 칩 목록 구성
    const byArea = new Map<string, { label: string; area: number }>();
    transactions.forEach(tx => {
      const key = String(tx.area);
      if (!byArea.has(key)) {
        const txAptNorm = normalizeAptName(tx.aptName);
        const typeData = typeMap[txAptNorm]?.[key];
        const typeName = typeData ? (areaUnit === 'm2' ? typeData.typeM2 : (typeData.typePyeong || typeData.typeM2)) : undefined;
        const label = typeName || (areaUnit === 'm2' ? `${tx.area}m²` : `${tx.areaPyeong}평`);
        byArea.set(key, { label, area: tx.area });
      }
    });

    const typeFilters = [
      { key: 'ALL', label: '단지 전체', area: 0 },
      ...Array.from(byArea.values())
        .sort((a, b) => {
          const numA = parseInt(a.label.match(/\d+/)?.[0] || '0');
          const numB = parseInt(b.label.match(/\d+/)?.[0] || '0');
          if (numA !== numB) return numA - numB;
          return a.label.localeCompare(b.label);
        })
        .map(c => ({ key: String(c.area), label: c.label, area: c.area }))
    ];

    // 2) 기간별 평균 산출
    const periods = [
      { key: '1M', label: '1개월', months: 1 },
      { key: '3M', label: '3개월', months: 3 },
      { key: '6M', label: '6개월', months: 6 },
      { key: '1Y', label: '1년', months: 12 },
      { key: '3Y', label: '3년', months: 36 },
      { key: '5Y', label: '5년', months: 60 },
      { key: '10Y', label: '10년', months: 120 },
      { key: 'ALL', label: '전체', months: 9999 },
    ];

    const getTxDate = (tx: TransactionRecord) => {
      const y = parseInt(tx.contractYm.slice(0, 4));
      const m = parseInt(tx.contractYm.slice(4, 6));
      const d = parseInt(tx.contractDay) || 1;
      return new Date(y, m - 1, d);
    };

    const periodTransactions = transactions.filter(tx => {
      if (periodDealType === 'sale' && (tx.dealType === '전세' || tx.dealType === '월세')) return false;
      if (periodDealType === 'jeonse' && tx.dealType !== '전세' && tx.dealType !== '월세') return false;
      return true;
    });

    const baseTx = priceTypeFilter === 'ALL'
      ? periodTransactions
      : periodTransactions.filter(tx => String(tx.area) === priceTypeFilter);

    const getTxSupplyPyeong = (tx: TransactionRecord) => {
      const key = String(tx.area);
      const txAptNorm = normalizeAptName(tx.aptName);
      const typeData = typeMap[txAptNorm]?.[key];
      if (typeData?.typeM2) {
        const supplyM2Match = typeData.typeM2.match(/\d+(\.\d+)?/);
        if (supplyM2Match) return parseFloat(supplyM2Match[0]) * 0.3025;
      }
      return tx.area * 0.3025 * 1.33; 
    };

    const formatEok = (priceMan: number) => {
      if (priceMan >= 10000) {
        const eok = Math.floor(priceMan / 10000);
        const rem = Math.round(priceMan % 10000);
        return `${eok}억${rem > 0 ? rem.toLocaleString() : ''}`;
      }
      return `${Math.round(priceMan).toLocaleString()}만`;
    };

    const overallAvgPrice = baseTx.length > 0 ? baseTx.reduce((s, t) => s + t.price, 0) / baseTx.length : 0;
    const sortedBaseTx = [...baseTx].sort((a, b) => getTxDate(b).getTime() - getTxDate(a).getTime());
    const fallbackTx = sortedBaseTx.length > 0 ? sortedBaseTx[0] : null;

    const periodData = periods.map(p => {
      const cutoffDate = new Date(now.getFullYear(), now.getMonth() - p.months, now.getDate());
      const filtered = baseTx.filter(tx => p.months >= 9999 || getTxDate(tx) >= cutoffDate);
      
      let rawAvgPrice = 0;
      let perPyeong = 0;
      let count = filtered.length;

      if (filtered.length > 0) {
        rawAvgPrice = filtered.reduce((s, t) => s + t.price, 0) / filtered.length;
        perPyeong = Math.round(filtered.reduce((s, tx) => s + (tx.price / getTxSupplyPyeong(tx)), 0) / filtered.length);
      } else if (fallbackTx) {
        rawAvgPrice = fallbackTx.price;
        perPyeong = Math.round(fallbackTx.price / getTxSupplyPyeong(fallbackTx));
        count = 0;
      }

      const avgPrice = Math.round(rawAvgPrice / 100) * 100;
      const trendPct = overallAvgPrice > 0 && p.months < 9999 
        ? ((avgPrice - overallAvgPrice) / overallAvgPrice * 100) 
        : null;

      return {
        ...p,
        count,
        avgPrice,
        avgPriceEok: formatEok(avgPrice),
        perPyeong,
        perPyeongEok: formatEok(perPyeong),
        trendPct,
      };
    }).filter(p => p.count > 0 || p.avgPrice > 0);

    return { typeFilters, periodData };
  }, [transactions, apartmentName, typeMap, areaUnit, priceTypeFilter, periodDealType]);

  if (transactions.length === 0 || periodData.length === 0) return null;

  return (
    <div className="bg-surface w-full px-4 md:px-10 pb-6 border-b border-border">
      <div className="pt-4">
        <div className="flex items-center justify-between gap-2 mb-3 flex-wrap w-full">
          <div className="flex items-center gap-2 justify-between w-full sm:w-auto sm:justify-start">
            <h5 className="text-[15px] font-bold text-secondary flex items-center gap-1.5">기간별 평균가격
              <button
                onClick={(e) => { e.stopPropagation(); setShowPriceHelp((prev) => !prev); }}
                className="w-4 h-4 rounded-full bg-toss-gray hover:bg-[#8b95a1] text-[10px] font-extrabold text-surface inline-flex items-center justify-center transition-colors leading-none flex-shrink-0"
                aria-label="기준 설명"
              >?</button>
            </h5>
            <div className="bg-body p-1 rounded-lg flex items-center shadow-inner ml-2">
              <button onClick={() => setPeriodDealType('sale')} className={`px-3 py-1 rounded-md text-[13px] font-bold transition-all ${periodDealType === 'sale' ? 'bg-surface text-primary shadow-[0_1px_3px_rgba(0,0,0,0.1)]' : 'text-tertiary hover:text-secondary'}`}>매매</button>
              <button onClick={() => setPeriodDealType('jeonse')} className={`px-3 py-1 rounded-md text-[13px] font-bold transition-all ${periodDealType === 'jeonse' ? 'bg-surface text-primary shadow-[0_1px_3px_rgba(0,0,0,0.1)]' : 'text-tertiary hover:text-secondary'}`}>전월세</button>
            </div>
          </div>
          {showPriceHelp && (
            <>
              <div className="fixed inset-0 z-[9998]" onClick={() => setShowPriceHelp(false)} />
              <div className="absolute left-4 top-12 z-[9999] w-[260px] bg-[#1e293b] text-surface text-[11px] leading-relaxed rounded-xl px-4 py-3 shadow-2xl">
                <div className="font-bold mb-1.5">📊 기간별 평균가격이란?</div>
                <p className="text-surface/80">각 기간 내 실거래된 모든 자료의 <span className="text-surface font-bold">산술 평균</span>입니다.</p>
                <p className="text-surface/80 mt-1">100만 원 단위로 반올림하여 표시합니다.</p>
                <p className="text-surface/50 mt-1.5 text-[10px]">예: "1개월" = 최근 1개월간 거래된 가격의 평균</p>
              </div>
            </>
          )}
        </div>
        <div className="flex flex-nowrap gap-1.5 overflow-x-auto custom-scrollbar pb-3 -mx-1 px-1">
          {typeFilters.map(f => {
            const isActive = priceTypeFilter === f.key;
            return (
              <button key={f.key} onClick={() => setPriceTypeFilter(f.key)}
                className={`shrink-0 px-3 py-1.5 rounded-lg text-[11px] font-bold transition-all ${
                  isActive
                    ? 'bg-primary text-surface shadow-sm'
                    : 'bg-body text-tertiary hover:bg-[#e5e8eb]'
                }`}
              >{f.label}</button>
            );
          })}
        </div>
        <div className="overflow-x-auto custom-scrollbar -mx-4 md:-mx-10 px-4 md:px-10 mt-1">
          <table className="w-full text-sm min-w-[600px] border-t border-body">
            <thead>
              <tr className="border-b border-border text-tertiary text-[12px] font-bold bg-body">
                <th className="py-2.5 px-2 text-center w-[52px] min-w-[52px] shrink-0">구분</th>
                {periodData.map(p => (
                  <th key={`th-${p.key}`} className="py-2.5 px-3 text-center whitespace-nowrap">{p.label}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              <tr className="border-b border-body hover:bg-[#f8faff] transition-colors">
                <td className="py-3 px-2 text-[12px] md:text-[13px] font-bold text-secondary bg-body/50 align-middle">
                  <div className="flex flex-col items-center justify-center leading-tight">
                    <span>평균</span>
                    <span>가격</span>
                  </div>
                </td>
                {periodData.map(p => (
                  <td key={`price-${p.key}`} className="py-3 px-3 text-center whitespace-nowrap">
                    <span className="text-[13px] md:text-[14px] font-bold md:font-extrabold text-primary">{p.avgPriceEok}</span>
                  </td>
                ))}
              </tr>
              <tr className="border-b border-body hover:bg-[#f8faff] transition-colors">
                <td className="py-3 px-2 text-[12px] md:text-[13px] font-bold text-secondary bg-body/50 align-middle">
                  <div className="flex flex-col items-center justify-center leading-tight">
                    <span>평당</span>
                    <span>가격</span>
                  </div>
                </td>
                {periodData.map(p => (
                  <td key={`perpyeong-${p.key}`} className="py-3 px-3 text-center">
                    <div className="flex items-center justify-center gap-0.5 whitespace-nowrap">
                      <span className="text-[12px] md:text-[13px] font-bold text-secondary">{p.perPyeongEok}</span>
                      <span className="text-[10px] md:text-[11px] text-tertiary font-medium tracking-tight">/평</span>
                    </div>
                  </td>
                ))}
              </tr>
              <tr className="border-b border-body hover:bg-[#f8faff] transition-colors">
                <td className="py-3 px-2 text-[12px] md:text-[13px] font-bold text-secondary bg-body/50 align-middle">
                  <div className="flex flex-col items-center justify-center leading-tight">
                    <span>거래</span>
                    <span>건수</span>
                  </div>
                </td>
                {periodData.map(p => (
                  <td key={`count-${p.key}`} className="py-3 px-3 text-center whitespace-nowrap">
                    <span className="text-[12px] md:text-[13px] font-medium text-tertiary">{p.count}건</span>
                  </td>
                ))}
              </tr>
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

import React, { useMemo, useState, useEffect, useRef } from 'react';
import { ChevronDown, AlertTriangle, AlertCircle } from 'lucide-react';

export interface TransactionRecord {
  dong?: string;
  aptName: string;
  area: number;
  areaPyeong: number;
  contractYm: string;
  contractDay: string;
  price: number;
  priceEok: string;
  deposit?: number;
  monthlyRent?: number;
  floor: number;
  buildYear: number;
  dealType?: string;
  reqGb?: string;
  rnuYn?: string;
  cancelDate?: string;
  isOutlier?: boolean;
}

interface TransactionTableProps {
  transactions: TransactionRecord[];
  typeMap: Record<string, Record<string, { typeM2: string; typePyeong: string }>>;
  areaUnit: 'm2' | 'pyeong';
  chartType: 'sale' | 'jeonse';
  normalizeAptName: (name: string) => string;
}

export function TransactionTable({
  transactions,
  typeMap,
  areaUnit,
  chartType,
  normalizeAptName
}: TransactionTableProps) {
  const [txSort, setTxSort] = useState<'date_desc' | 'date_asc' | 'price_desc' | 'price_asc'>('date_desc');
  const [txFilterArea, setTxFilterArea] = useState<string>('ALL');
  const [txFilterDealType, setTxFilterDealType] = useState<string>('ALL');
  const [activeDropdown, setActiveDropdown] = useState<'sort' | 'area' | 'dealType' | null>(null);
  
  const INITIAL_DISPLAY_COUNT = 10;
  const [displayedCount, setDisplayedCount] = useState(INITIAL_DISPLAY_COUNT);

  // Reset displayed count when filters change
  useEffect(() => {
    setDisplayedCount(INITIAL_DISPLAY_COUNT);
  }, [txSort, txFilterArea, txFilterDealType, chartType]);

  // Close dropdown on outside click
  useEffect(() => {
    if (!activeDropdown) return;
    const handleClickOutside = (e: MouseEvent) => {
      setActiveDropdown(null);
    };
    document.addEventListener('click', handleClickOutside);
    return () => document.removeEventListener('click', handleClickOutside);
  }, [activeDropdown]);

  // Derived filter options
  const { areaTypes, dealTypes } = useMemo(() => {
    const areas = new Set<number>();
    const deals = new Set<string>();
    transactions.forEach(t => {
      areas.add(t.area);
      if (t.dealType) deals.add(t.dealType);
    });
    return {
      areaTypes: Array.from(areas).sort((a, b) => a - b),
      dealTypes: Array.from(deals)
    };
  }, [transactions]);

  const filteredTransactions = useMemo(() => {
    return transactions.filter(tx => {
      // 연동 차트에 따라 매매/전월세 기본 분류 필터링
      if (chartType === 'sale' && (tx.dealType === '전세' || tx.dealType === '월세')) return false;
      if (chartType === 'jeonse' && tx.dealType !== '전세' && tx.dealType !== '월세') return false;

      // 추가 필터링
      if (txFilterArea !== 'ALL' && tx.area !== Number(txFilterArea)) return false;
      if (txFilterDealType !== 'ALL' && tx.dealType !== txFilterDealType) return false;
      return true;
    });
  }, [transactions, chartType, txFilterArea, txFilterDealType]);

  const sortedFilteredTransactions = useMemo(() => {
    return [...filteredTransactions].sort((a, b) => {
      const getP = (t: TransactionRecord) => (t.dealType === '전세' || t.dealType === '월세') ? (t.deposit || 0) : t.price;
      if (txSort === 'date_desc') {
        const da = a.contractYm + a.contractDay.padStart(2, '0');
        const db = b.contractYm + b.contractDay.padStart(2, '0');
        if (da !== db) return parseInt(db) - parseInt(da);
        return getP(b) - getP(a);
      }
      if (txSort === 'date_asc') {
        const da = a.contractYm + a.contractDay.padStart(2, '0');
        const db = b.contractYm + b.contractDay.padStart(2, '0');
        return parseInt(da) - parseInt(db);
      }
      if (txSort === 'price_desc') return getP(b) - getP(a);
      if (txSort === 'price_asc') return getP(a) - getP(b);
      return 0;
    });
  }, [filteredTransactions, txSort]);

  // '중개거래', '직거래' 등은 거래 방식이지 유형이 아님 — 사실상 매매
  const isSaleDealType = (dealType: string | undefined) =>
    !dealType || (dealType !== '전세' && dealType !== '월세');

