                    onClick={(e) => { e.stopPropagation(); setTxFilterDealType(opt.value); setActiveDropdown(null); }}>
                    {opt.label}
                  </button>
                ))}
              </div>
            )}
          </div>
          {/* 정렬 필터 */}
          <div className="relative" onClick={(e) => { e.stopPropagation(); setActiveDropdown(activeDropdown === 'sort' ? null : 'sort'); }}>
