                <th className="py-2 text-left font-extrabold">영역</th>
                <th className="py-2 text-right font-extrabold">원 점수</th>
                <th className="py-2 text-right font-extrabold">가중치</th>
                <th className="py-2 text-right font-extrabold">기여분</th>
