'use client';

import React, { createContext, useContext, useEffect, useState, ReactNode } from 'react';

// BeforeInstallPromptEvent type declaration
export interface BeforeInstallPromptEvent extends Event {
  readonly platforms: string[];
  readonly userChoice: Promise<{
    outcome: 'accepted' | 'dismissed';
    platform: string;
  }>;
  prompt(): Promise<void>;
}

interface PWAContextType {
  isInstallable: boolean;
  deferredPrompt: BeforeInstallPromptEvent | null;
  triggerA2HSPrompt: () => Promise<boolean>;
  showCustomA2HSModal: boolean;
  setShowCustomA2HSModal: (show: boolean) => void;
  triggerCustomA2HSModal: () => void;
  // Web Push Notifications
  isPushSupported: boolean;
  pushSubscription: PushSubscription | null;
  subscribeToPush: () => Promise<boolean>;
}

const PWAContext = createContext<PWAContextType>({
  isInstallable: false,
  deferredPrompt: null,
  triggerA2HSPrompt: async () => false,
  showCustomA2HSModal: false,
  setShowCustomA2HSModal: () => {},
  triggerCustomA2HSModal: () => {},
  isPushSupported: false,
  pushSubscription: null,
  subscribeToPush: async () => false,
});

export const usePWA = () => useContext(PWAContext);

function urlBase64ToUint8Array(base64String: string) {
  const padding = '='.repeat((4 - base64String.length % 4) % 4);
  const base64 = (base64String + padding)
    .replace(/\-/g, '+')
    .replace(/_/g, '/');

  const rawData = window.atob(base64);
  const outputArray = new Uint8Array(rawData.length);

  for (let i = 0; i < rawData.length; ++i) {
    outputArray[i] = rawData.charCodeAt(i);
  }
  return outputArray;
}

export function PWAProvider({ children }: { children: ReactNode }) {
  const [deferredPrompt, setDeferredPrompt] = useState<BeforeInstallPromptEvent | null>(null);
  const [isInstallable, setIsInstallable] = useState(false);
  const [showCustomA2HSModal, setShowCustomA2HSModal] = useState(false);
  
  // Push Notification state
  const [isPushSupported, setIsPushSupported] = useState(false);
  const [pushSubscription, setPushSubscription] = useState<PushSubscription | null>(null);

  useEffect(() => {
    // 1. A2HS Logic
    const handleBeforeInstallPrompt = (e: Event) => {
      e.preventDefault();
      setDeferredPrompt(e as BeforeInstallPromptEvent);
      setIsInstallable(true);
    };

    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    window.addEventListener('appinstalled', () => {
      setDeferredPrompt(null);
      setIsInstallable(false);
      setShowCustomA2HSModal(false);
    });

    // 2. Web Push Support Check
    if (typeof window !== 'undefined' && 'serviceWorker' in navigator && 'PushManager' in window) {
      setIsPushSupported(true);
      // Check existing subscription
      navigator.serviceWorker.ready.then((reg) => {
        reg.pushManager.getSubscription().then((sub) => {
          if (sub) setPushSubscription(sub);
        });
      });
    }

    return () => {
      window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    };
  }, []);

  const triggerA2HSPrompt = async () => {
    if (!deferredPrompt) return false;
    
    await deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    
    if (outcome === 'accepted') {
      setDeferredPrompt(null);
      setIsInstallable(false);
      return true;
    }
    return false;
  };

  const triggerCustomA2HSModal = () => {
    if (isInstallable && deferredPrompt) {
      setShowCustomA2HSModal(true);
    }
  };

  const subscribeToPush = async () => {
    if (!isPushSupported) {
      alert('이 브라우저는 푸시 알림을 지원하지 않습니다.');
      return false;
    }
    try {
      const permission = await Notification.requestPermission();
      if (permission !== 'granted') {
        alert('푸시 알림 권한이 거부되었습니다.');
        return false;
      }
      
      const reg = await navigator.serviceWorker.ready;
      
      // Replace with your VAPID public key
      const vapidPublicKey = process.env.NEXT_PUBLIC_VAPID_PUBLIC_KEY || 'BEl62iUYgUivxIkv69yViEuiBIa-Ib9-SkvMeAtA3LFgDzkrxZJjSgSnfckjBJuBkr3qBUYIHBQFLXYp5Nksh8U';
      const convertedVapidKey = urlBase64ToUint8Array(vapidPublicKey);
      
      const sub = await reg.pushManager.subscribe({
        userVisibleOnly: true,
        applicationServerKey: convertedVapidKey
      });
      
      setPushSubscription(sub);
      
      // TODO: Here you would typically send the subscription to your backend server
      // e.g. await fetch('/api/push/subscribe', { method: 'POST', body: JSON.stringify(sub) });
      
      console.log('Push Subscribed:', JSON.stringify(sub));
      return true;
    } catch (error) {
      console.error('Error subscribing to push', error);
      return false;
    }
  };

  return (
    <PWAContext.Provider
      value={{
        isInstallable,
        deferredPrompt,
        triggerA2HSPrompt,
        showCustomA2HSModal,
        setShowCustomA2HSModal,
        triggerCustomA2HSModal,
        isPushSupported,
        pushSubscription,
        subscribeToPush,
      }}
    >
      {children}
    </PWAContext.Provider>
  );
}

'use client';

import React, { useState, useEffect, useRef } from 'react';
import { useRouter } from 'next/navigation';
import { RefreshCw } from 'lucide-react';

interface PullToRefreshProps {
  children: React.ReactNode;
  onRefresh?: () => Promise<void>;
  pullThreshold?: number;
  scrollContainerId?: string;
}

export default function PullToRefresh({ 
  children, 
  onRefresh,
  pullThreshold = 80,
  scrollContainerId
}: PullToRefreshProps) {
  const router = useRouter();
  const [isPulling, setIsPulling] = useState(false);
  const [pullProgress, setPullProgress] = useState(0);
  const [isRefreshing, setIsRefreshing] = useState(false);
  
  const startY = useRef<number | null>(null);
  const contentRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const getScrollTop = () => {
      if (scrollContainerId) {
        const el = document.getElementById(scrollContainerId);
        return el ? el.scrollTop : 0;
      }
      return window.scrollY;
    };

    const handleTouchStart = (e: TouchEvent) => {
      // Only allow pull-to-refresh if we are at the very top of the scroll container
      if (getScrollTop() > 0) return;
      startY.current = e.touches[0].clientY;
    };

    const handleTouchMove = (e: TouchEvent) => {
      if (startY.current === null || isRefreshing) return;
      
      const y = e.touches[0].clientY;
      const deltaY = y - startY.current;

      if (deltaY > 0 && getScrollTop() === 0) {
        // We are pulling down
        setIsPulling(true);
        // Add some resistance
        const progress = Math.min((deltaY / pullThreshold) * 100, 150);
        setPullProgress(progress);
        
        // Prevent default browser scroll/refresh behavior
        if (e.cancelable) e.preventDefault();
      }
    };

    const handleTouchEnd = async () => {
      if (startY.current === null) return;
      
      if (pullProgress >= 100 && !isRefreshing) {
        setIsRefreshing(true);
        setPullProgress(100); // Lock it at 100% while refreshing
        
        try {
          if (onRefresh) {
            await onRefresh();
          } else {
            // Fallback to Next.js router refresh
            router.refresh();
            // Artificial delay for better UX
            await new Promise(resolve => setTimeout(resolve, 800));
          }
        } catch (error) {
          console.error("Refresh failed:", error);
        } finally {
          setIsRefreshing(false);
          setIsPulling(false);
          setPullProgress(0);
          startY.current = null;
        }
      } else {
        setIsPulling(false);
        setPullProgress(0);
        startY.current = null;
      }
    };

    const handleTouchCancel = () => {
      if (isRefreshing) return;
      setIsPulling(false);
      setPullProgress(0);
      startY.current = null;
    };

    const element = contentRef.current;
    if (element) {
      element.addEventListener('touchstart', handleTouchStart, { passive: true });
      element.addEventListener('touchmove', handleTouchMove, { passive: false });
      element.addEventListener('touchend', handleTouchEnd);
      element.addEventListener('touchcancel', handleTouchCancel);
    }

    return () => {
      if (element) {
        element.removeEventListener('touchstart', handleTouchStart);
        element.removeEventListener('touchmove', handleTouchMove);
        element.removeEventListener('touchend', handleTouchEnd);
        element.removeEventListener('touchcancel', handleTouchCancel);
      }
    };
  }, [pullProgress, isRefreshing, pullThreshold, onRefresh, router]);

  return (
    <div ref={contentRef} className="min-h-screen">
      {/* PTR Indicator */}
      <div 
        className="fixed top-0 left-0 right-0 flex justify-center z-50 pointer-events-none transition-transform duration-200 ease-out"
        style={{
          transform: `translateY(${Math.min(pullProgress * 0.6 - 40, 20)}px)`,
          opacity: Math.min(pullProgress / 100, 1),
        }}
      >
        <div className="bg-surface rounded-full p-2.5 shadow-md flex items-center justify-center">
          <RefreshCw 
            size={20} 
            className={`text-blue-500 transition-transform ${isRefreshing ? 'animate-spin' : ''}`}
            style={{
              transform: isRefreshing ? 'none' : `rotate(${pullProgress * 3.6}deg)`
            }}
          />
        </div>
      </div>
      
      {/* Content wrapper. Moves down slightly when pulled */}
      <div 
        className="transition-transform duration-200 ease-out"
        style={{
          transform: isPulling || isRefreshing ? `translateY(${Math.min(pullProgress * 0.4, 40)}px)` : 'none',
        }}
      >
        {children}
      </div>
    </div>
  );
}

