'use client';

import { useState, useEffect, useSyncExternalStore } from 'react';

function subscribe(callback: () => void) {
  window.addEventListener('online', callback);
  window.addEventListener('offline', callback);
  return () => {
    window.removeEventListener('online', callback);
    window.removeEventListener('offline', callback);
  };
}

function getSnapshot() {
  return navigator.onLine;
}

function getServerSnapshot() {
  return true; // SSR always assumes online
}

/**
 * Hook that tracks the user's network connectivity status.
 * Returns `true` when online, `false` when offline.
 */
export function useNetworkStatus() {
  return useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot);
}

/**
 * @module post.repository
 * @description Data Access Layer for 'posts' Firestore collection.
 * Architecture Layer: Repository (CRUD only, no business logic)
 * 
 * Rationale: Isolates Firestore-specific operations so the Service layer
 * remains database-agnostic. Enables future migration to another DB.
 */
import { db } from '@/lib/firebaseConfig';
import { collection, onSnapshot, query, orderBy, limit, addDoc, doc, updateDoc, increment, deleteDoc, serverTimestamp } from 'firebase/firestore';
import { logger } from '@/lib/services/logger';
import type { NewsItemData } from '@/lib/types/dashboard.types';
import { Train, Building, BookOpen, Calendar, MessageSquare } from 'lucide-react';

/**
 * Listens to the 'posts' collection in real-time.
 * @param callback - Invoked with the latest posts array on each change
 * @returns Unsubscribe function
 */
export function listenToPosts(callback: (posts: NewsItemData[]) => void): () => void {
  const q = query(collection(db, 'posts'), orderBy('createdAt', 'desc'), limit(30));

  return onSnapshot(q, (snapshot) => {
    const posts: NewsItemData[] = [];

    snapshot.forEach((docSnap) => {
      const data = docSnap.data();

      let icon = MessageSquare;
      let tagClass = 'tag-culture';

      if (data.category === '교통') { icon = Train; tagClass = 'tag-traffic'; }
      else if (data.category === '부동산') { icon = Building; tagClass = 'tag-realestate'; }
      else if (data.category === '교육') { icon = BookOpen; tagClass = 'tag-edu'; }

      const dateStr = data.createdAt ? new Date(data.createdAt.toDate()).toLocaleDateString('ko-KR') : '방금 전';

      posts.push({
        id: docSnap.id,
        title: data.title,
        meta: `${dateStr} · ${data.category}`,
        content: data.content || undefined,
        author: data.authorName || '익명',
        imageUrl: data.imageUrl,
        tagClass,
        icon,
        likes: data.likes || 0,
        views: data.views || 0,
        authorUid: data.authorUid || undefined,
        verifiedApartment: data.verifiedApartment || undefined,
        verificationLevel: data.verificationLevel || undefined,
      });
    });

    callback(posts);
  });
}

/**
 * Creates a new post document in Firestore.
 * @param data - Post data to persist
 * @returns The new document ID
 * @throws FirestoreError if write fails
 */
export async function createPost(data: {
  title: string;
  category: string;
  content?: string;
  authorName: string;
  authorUid: string;
  imageUrl: string | null;
  verifiedApartment?: string;
  verificationLevel?: string;
}): Promise<string> {
  const docRef = await addDoc(collection(db, 'posts'), {
    ...data,
    likes: 0,
    views: 0,
    createdAt: serverTimestamp(),
  });
  logger.info('PostRepository.createPost', 'Post created', { id: docRef.id });
  return docRef.id;
}

/**
 * Increments the like counter on a post.
 * @param postId - The Firestore document ID
 * @throws FirestoreError if update fails
 */
export async function incrementPostLike(postId: string): Promise<void> {
  const postRef = doc(db, 'posts', postId);
  await updateDoc(postRef, { likes: increment(1) });
}

import * as TrafficRepo from '@/lib/repositories/traffic.repository';

/**
 * Increments the view counter on a post.
 * @param postId - The Firestore document ID
 * @param title - The post title for daily stats
 * @throws FirestoreError if update fails
 */
export async function incrementPostView(postId: string, title: string = '알 수 없는 글'): Promise<void> {
  const postRef = doc(db, 'posts', postId);
  await updateDoc(postRef, { views: increment(1) });
  await TrafficRepo.incrementContentView(postId, title, 'lounge');
}

/**
 * Deletes a post document from Firestore.
 * @param postId - The Firestore document ID
 * @throws FirestoreError if delete fails
 */
export async function deletePost(postId: string): Promise<void> {
  const postRef = doc(db, 'posts', postId);
  await deleteDoc(postRef);
  logger.info('PostRepository.deletePost', 'Post deleted', { postId });
}

/**
 * @module purchase.repository
 * @description Data Access Layer for purchase records in Firestore.
 * Architecture Layer: Repository (CRUD only)
 */
import { db } from '@/lib/firebaseConfig';
import {
  collection, query, where, getDocs, addDoc,
  serverTimestamp, doc, getDoc
} from 'firebase/firestore';
import { logger } from '@/lib/services/logger';
import type { Purchase } from '@/lib/types/purchase.types';
import { z } from 'zod';

const PurchaseDataSchema = z.object({
  reportId: z.string()
});

const COLLECTION = 'purchases';

/**
 * Checks if a user has already purchased a specific report.
 * @returns true if purchased (status = 'DONE')
 */
export async function hasPurchased(userId: string, reportId: string): Promise<boolean> {
  try {
    const q = query(
      collection(db, COLLECTION),
      where('userId', '==', userId),
      where('reportId', '==', reportId),
      where('status', '==', 'DONE')
    );
    const snap = await getDocs(q);
    return !snap.empty;
  } catch (e) {
    logger.error('PurchaseRepo.hasPurchased', 'Query failed', { userId, reportId }, e);
    return false;
  }
}

/**
 * Creates a purchase record after successful payment confirmation.
 */
export async function createPurchase(purchase: Omit<Purchase, 'id' | 'purchasedAt'>): Promise<string> {
  const docRef = await addDoc(collection(db, COLLECTION), {
    ...purchase,
    purchasedAt: serverTimestamp(),
  });
  logger.info('PurchaseRepo.createPurchase', 'Purchase created', {
    userId: purchase.userId,
    reportId: purchase.reportId,
    orderId: purchase.orderId,
  });
  return docRef.id;
}

/**
 * Gets all purchases for a user (to pre-load unlocked report list).
 * @returns Array of reportIds that this user has purchased
 */
export async function getUserPurchasedReportIds(userId: string): Promise<string[]> {
  try {
    const q = query(
      collection(db, COLLECTION),
      where('userId', '==', userId),
      where('status', '==', 'DONE')
    );
    const snap = await getDocs(q);
    return snap.docs
      .map(d => PurchaseDataSchema.safeParse(d.data()))
      .filter(result => result.success)
      .map(result => result.data.reportId);
  } catch (e) {
    logger.error('PurchaseRepo.getUserPurchasedReportIds', 'Query failed', { userId }, e);
    return [];
  }
}

/**
 * @module report.repository
 * @description Data Access Layer for 'scoutingReports' Firestore collection.
 * Architecture Layer: Repository (CRUD only, no business logic)
 */
import { db } from '@/lib/firebaseConfig';
import { collection, onSnapshot, query, orderBy, limit, doc, updateDoc, increment, getDoc, getDocs, where, QuerySnapshot, DocumentData, QueryDocumentSnapshot } from 'firebase/firestore';
import type { FieldReportData } from '@/lib/types/report.types';

/**
 * Listens to the 'scoutingReports' collection in real-time.
 * Maps only lightweight fields needed for list cards.
 * Heavy fields (sections, images) are loaded on-demand via getFullReport().
 * @param callback - Invoked with the latest reports array on each change
 * @returns Unsubscribe function
 */
export function listenToReports(callback: (reports: FieldReportData[]) => void): () => void {
  const q = query(collection(db, 'scoutingReports'), limit(30));

  const mapSnapshot = (snapshot: QuerySnapshot<DocumentData>): FieldReportData[] => {
    const reports: FieldReportData[] = [];
    snapshot.forEach((docSnap: QueryDocumentSnapshot<DocumentData>) => {
      const data = docSnap.data();
      reports.push({
        id: docSnap.id,
        dong: data.dong || '오산동 (동탄역)',
        apartmentName: data.apartmentName,
        premiumScores: data.premiumScores,
        premiumContent: data.premiumContent,
        pros: data.premiumContent || '포장 싹 뺀 진짜 동네 아파트 리뷰',
        cons: '',
        rating: 5,
        author: '데이터 랩스',
        likes: data.likes || 0,
        viewCount: data.viewCount || 0,
        commentCount: data.commentCount || 0,
        imageUrl: data.thumbnailUrl || data.imageUrl,
        images: data.images || [],
        metrics: data.metrics,
        scoutingDate: data.scoutingDate || '',
        createdAt: data.createdAt?.toDate ? data.createdAt.toDate().toLocaleDateString('ko-KR') : '방금 전',
        // keep raw timestamp for sorting
        _rawTimestamp: data.createdAt?.toDate ? data.createdAt.toDate().getTime() : 0, 
      } as FieldReportData & { _rawTimestamp: number });
    });
    return reports.sort((a, b) => (b as FieldReportData & { _rawTimestamp: number })._rawTimestamp - (a as FieldReportData & { _rawTimestamp: number })._rawTimestamp);
  };

  return onSnapshot(q, (snapshot) => {
    const mapped = mapSnapshot(snapshot);
    console.trace('[ReportRepo] Invoking callback with mapped.length:', mapped.length);
    callback(mapped);
  }, (error) => {
    console.error('[ReportRepo] onSnapshot error, falling back to unordered query:', error.message);
    // Fallback: query without orderBy (no index needed)
    const fallbackQ = query(collection(db, 'scoutingReports'), limit(30));
    onSnapshot(fallbackQ, (fallbackSnapshot) => {
      const fallbackMapped = mapSnapshot(fallbackSnapshot);
      console.trace('[ReportRepo] Invoking callback from fallback with length:', fallbackMapped.length);
      callback(fallbackMapped);
    }, (fallbackError) => {
      console.error('[ReportRepo] Fallback also failed:', fallbackError.message);
      console.trace('[ReportRepo] Invoking callback from fallback error with length: 0');
      callback([]);
    });
  });
}

/**
 * Fetches a single report's full data (including sections & images) on demand.
 * Used when opening the detail modal — avoids loading heavy data for all 30 reports upfront.
 * @param reportId - The Firestore document ID
 * @returns Full report data, or null if not found
 */
export async function getFullReport(reportId: string): Promise<FieldReportData | null> {
  const docRef = doc(db, 'scoutingReports', reportId);
  const docSnap = await getDoc(docRef);
  if (!docSnap.exists()) return null;

  const data = docSnap.data();
  return {
    id: docSnap.id,
    dong: data.dong || '오산동 (동탄역)',
    apartmentName: data.apartmentName,
    sections: data.sections || undefined,
    premiumScores: data.premiumScores,
    premiumContent: data.premiumContent,
    pros: data.premiumContent || '포장 싹 뺀 진짜 동네 아파트 리뷰',
    cons: '',
    rating: 5,
    author: '데이터 랩스',
    likes: data.likes || 0,
    viewCount: data.viewCount || 0,
    commentCount: data.commentCount || 0,
    imageUrl: data.thumbnailUrl || data.imageUrl,
    images: data.images || [],
    metrics: data.metrics,
    scoutingDate: data.scoutingDate || '',
    createdAt: data.createdAt?.toDate ? data.createdAt.toDate().toLocaleDateString('ko-KR') : '방금 전',
  };
}

