import { TX_SUMMARY } from '@/lib/transaction-summary';
import { findTxKey, normalizeAptName } from './apartmentMapping';

const LOCATION_PREFIXES = [
  '숲속마을동탄','푸른마을동탄','나루마을동탄',
  '동탄역시범','동탄시범다은마을','동탄시범한빛마을','동탄시범나루마을',
  '시범다은마을','시범한빛마을','시범나루마을','시범',
  '반탄솔빛마을','솔빛마을','예당마을','새강마을',
  '동탄2신도시','동탄신도시','동탄숲속마을','동탄푸른마을','동탄나루마을',
  '동탄호수공원역','동탄호수공원','동탄호수','동탄역',
  '화성동탄2','능동역','호수공원역','동탄2','동탄',
];
const NAME_SUFFIXES = ['역', '2단지', '1단지', '3단지', '4단지', '5단지', '단지'];

export function stripPrefix(n: string) {
  for (const p of LOCATION_PREFIXES) if (n.startsWith(p) && n.length > p.length) return n.slice(p.length);
  return n;
}

export function stripSuffix(n: string) {
  for (const s of NAME_SUFFIXES) if (n.endsWith(s) && n.length > s.length) return n.slice(0, -s.length);
  return n;
}

export function editDistance(a: string, b: string): number {
  const m = a.length, n = b.length;
  if (m === 0) return n;
  if (n === 0) return m;
  const dp: number[][] = Array.from({ length: m + 1 }, () => Array(n + 1).fill(0));
  for (let i = 0; i <= m; i++) dp[i][0] = i;
  for (let j = 0; j <= n; j++) dp[0][j] = j;
  for (let i = 1; i <= m; i++)
    for (let j = 1; j <= n; j++)
      dp[i][j] = Math.min(dp[i-1][j]+1, dp[i][j-1]+1, dp[i-1][j-1]+(a[i-1]===b[j-1]?0:1));
  return dp[m][n];
}

export function autoSuggest(aptName: string): string | null {
  const exactOrHardcoded = findTxKey(aptName, TX_SUMMARY as Record<string, any>);
  if (exactOrHardcoded) return exactOrHardcoded;

  const norm = normalizeAptName(aptName);
  const keys = Object.keys(TX_SUMMARY);
  if (!norm || norm.length < 2) return null;
  if (keys.includes(norm)) return norm;
  const stripped = stripPrefix(norm);
  if (stripped !== norm && keys.includes(stripped)) return stripped;
  for (const k of keys) if (stripPrefix(k) === stripped) return k;
  const suffixStripped = stripSuffix(norm);
  if (suffixStripped !== norm && keys.includes(suffixStripped)) return suffixStripped;
  for (const k of keys) if (stripSuffix(k) === suffixStripped) return k;
  const bothStripped = stripSuffix(stripped);
  if (bothStripped !== stripped) {
    for (const k of keys) if (stripSuffix(stripPrefix(k)) === bothStripped) return k;
  }
  const containMatches = keys.filter(k => norm.includes(k) || k.includes(norm));
  if (containMatches.length === 1) return containMatches[0];
  if (containMatches.length > 1) {
    containMatches.sort((a, b) => Math.abs(a.length - norm.length) - Math.abs(b.length - norm.length));
    return containMatches[0];
  }
  const threshold = Math.max(2, Math.floor(norm.length * 0.25));
  let bestKey: string | null = null;
  let bestDist = Infinity;
  for (const k of keys) {
    const dist = editDistance(norm, k);
    if (dist < bestDist && dist <= threshold) { bestDist = dist; bestKey = k; }
  }
  return bestKey;
}

// src/lib/utils/idb.ts

const DB_NAME = 'dview-offline-db';
const DB_VERSION = 1;
const STORE_NAME = 'sync-queue';

export interface OfflineMutation {
  id: string; // Unique ID (e.g., timestamp + random)
  type: 'ADD_COMMENT' | 'TOGGLE_FAVORITE';
  payload: any;
  timestamp: number;
}

function openDB(): Promise<IDBDatabase> {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);

    request.onupgradeneeded = (event: IDBVersionChangeEvent) => {
      const db = (event.target as IDBOpenDBRequest).result;
      if (!db.objectStoreNames.contains(STORE_NAME)) {
        db.createObjectStore(STORE_NAME, { keyPath: 'id' });
      }
    };

    request.onsuccess = (event: Event) => {
      resolve((event.target as IDBOpenDBRequest).result);
    };

    request.onerror = (event: Event) => {
      reject((event.target as IDBOpenDBRequest).error);
    };
  });
}

export async function saveOfflineMutation(mutation: Omit<OfflineMutation, 'id' | 'timestamp'>): Promise<void> {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction(STORE_NAME, 'readwrite');
    const store = transaction.objectStore(STORE_NAME);

    const fullMutation: OfflineMutation = {
      ...mutation,
      id: `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
      timestamp: Date.now(),
    };

    const request = store.add(fullMutation);

    request.onsuccess = () => resolve();
    request.onerror = () => reject(request.error);
  });
}

export async function getOfflineMutations(): Promise<OfflineMutation[]> {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction(STORE_NAME, 'readonly');
    const store = transaction.objectStore(STORE_NAME);
    const request = store.getAll();

    request.onsuccess = () => {
      // Sort by timestamp
      const mutations = (request.result as OfflineMutation[]).sort((a, b) => a.timestamp - b.timestamp);
      resolve(mutations);
    };
    request.onerror = () => reject(request.error);
  });
}

export async function deleteOfflineMutation(id: string): Promise<void> {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction(STORE_NAME, 'readwrite');
    const store = transaction.objectStore(STORE_NAME);
    const request = store.delete(id);

    request.onsuccess = () => resolve();
    request.onerror = () => reject(request.error);
  });
}

export async function clearOfflineMutations(): Promise<void> {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction(STORE_NAME, 'readwrite');
    const store = transaction.objectStore(STORE_NAME);
    const request = store.clear();

    request.onsuccess = () => resolve();
    request.onerror = () => reject(request.error);
  });
}

import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';
import { Ratelimit } from "@upstash/ratelimit";
import { redis } from "@/lib/redis";

// Upstash 글로벌 Rate Limiter (Edge 호환)
const RATE_LIMIT_POINTS = 60; // 분당 60회 허용

let ratelimit: Ratelimit | null = null;

try {
  // 환경변수가 없어도 빌트 및 구동 단계에서 앱이 멈추지 않도록 안전하게 예외처리
  if (redis) {
    ratelimit = new Ratelimit({
      redis: redis,
      limiter: Ratelimit.slidingWindow(RATE_LIMIT_POINTS, "1 m"),
      analytics: false,
      prefix: "DTDLS:ratelimit", // 멀티 프로젝트 Isolation을 위한 Prefix
    });
  }
} catch (error) {
  console.warn("Failed to initialize Upstash Ratelimit:", error);
}

export async function middleware(request: NextRequest) {
  // 클라이언트 IP 추출 (Vercel 환경 지원 시 x-real-ip 최우선)
  const ip = request.headers.get('x-real-ip') || request.headers.get('x-forwarded-for') || '127.0.0.1';
  
  // 1. Rate Limiting (API 라우트에 국한)
  if (request.nextUrl.pathname.startsWith('/api/')) {
    if (ratelimit) {
      try {
        const { success, limit, reset, remaining } = await ratelimit.limit(ip);
        if (!success) {
          return new NextResponse(
            JSON.stringify({ 
              error: 'Too Many Requests', 
              message: '비정상적인 트래픽이 감지되어 요청이 차단되었습니다. 잠시 후 다시 시도해주십시오.' 
            }),
            { 
              status: 429, 
              headers: { 
                'Content-Type': 'application/json',
                'X-RateLimit-Limit': limit.toString(),
                'X-RateLimit-Remaining': remaining.toString(),
                'X-RateLimit-Reset': reset.toString(),
                'Retry-After': Math.ceil((reset - Date.now()) / 1000).toString(),
              } 
            }
          );
        }
      } catch (err) {
        // Redis 연결 에러 시 요청을 차단하지 않고 Bypass (Fail-Open 방식)
        console.warn("Upstash RateLimiter Error, bypassing:", err);
      }
    }
  }

  // 2. HTTP Security 헤더 주입 파이프라인
  const isDev = process.env.NODE_ENV === 'development';

  // CSP: ISR/Static Generation 과의 충돌(nonce 불일치)을 방지하기 위해 strict-dynamic 및 nonce를 제거.
  // 대신 엄격한 Host 기반 Allowlist 유지.
  const cspHeader = `
    default-src 'self';
    script-src 'self' 'unsafe-eval' 'unsafe-inline' https://www.google.com https://www.gstatic.com https://www.googletagmanager.com https://apis.google.com https://www.recaptcha.net https://cdn.jsdelivr.net;
    worker-src 'self' blob:;
    style-src 'self' 'unsafe-inline' https://fonts.googleapis.com https://cdn.jsdelivr.net;
    img-src 'self' blob: data: https://firebasestorage.googleapis.com https://lh3.googleusercontent.com https://maps.gstatic.com https://maps.googleapis.com https://www.googletagmanager.com https://www.google-analytics.com;
    font-src 'self' data: https://fonts.gstatic.com https://cdn.jsdelivr.net;
    connect-src 'self' https://securetoken.googleapis.com https://identitytoolkit.googleapis.com https://firestore.googleapis.com https://firebasestorage.googleapis.com https://maps.googleapis.com https://vitals.vercel-insights.com https://cdn.jsdelivr.net https://www.google.com https://content-firebaseappcheck.googleapis.com https://apis.google.com https://www.recaptcha.net https://lh3.googleusercontent.com https://www.googletagmanager.com https://www.google-analytics.com;
    frame-src 'self' https://www.google.com https://www.youtube.com https://portfolio-dtdls.firebaseapp.com https://apis.google.com https://www.recaptcha.net;
    object-src 'none';
    base-uri 'self';
    form-action 'self';
    frame-ancestors 'none';
    upgrade-insecure-requests;
  `.replace(/\s{2,}/g, ' ').trim();

  const requestHeaders = new Headers(request.headers);
  requestHeaders.set('Content-Security-Policy', cspHeader);

  const response = NextResponse.next({
    request: {
      headers: requestHeaders,
    },
  });

  // 공통 보안 헤더 (A 레벨)
  response.headers.set('Content-Security-Policy', cspHeader);
  response.headers.set('X-Frame-Options', 'DENY'); // Clickjacking 원천 차단
  response.headers.set('X-Content-Type-Options', 'nosniff'); // MIME 타입 변조 방지 
  response.headers.set('Referrer-Policy', 'strict-origin-when-cross-origin'); // 리퍼러 보호
  response.headers.set('Permissions-Policy', 'camera=(), microphone=(), geolocation=(self)'); // 하드웨어 권한 탈취 방지

  // A+ 등급 승급용 심화 보안 헤더
  response.headers.set('Strict-Transport-Security', 'max-age=31536000; includeSubDomains; preload'); // 전 구간 강제 HTTPS화
  response.headers.set('Cross-Origin-Opener-Policy', 'same-origin-allow-popups'); // Spectre 공격 방어 (Firebase OAuth 팝업을 위해 allow-popups 필수)
  response.headers.set('Cross-Origin-Resource-Policy', 'same-origin'); // 타 도메인의 브라우저 메모리 로딩 차단

  return response;
}

// 미들웨어 구동 범위 (정적 에셋 등 불필요한 연산 방지)
export const config = {
  matcher: [
    '/((?!_next/static|_next/image|favicon.ico|_vercel|assets|css|js|images).*)',
  ],
};
